        }
    } catch (error) {
        console.error("Error in scheduled expiration check:", error);
    }
    return null;
});

/**
 * Push Notification Module
 * 푸시 알림 관련 Cloud Functions
 * 
 * @module modules/push
 * [Refactor] Extracted from index.js
 */

const { onDocumentCreated } = require("firebase-functions/v2/firestore");
const { onSchedule } = require("firebase-functions/v2/scheduler");
const { admin, getAI, logAIError, getAllFCMTokens, getStudioName } = require("../helpers/common");

/**
 * 개인 메시지 푸시 알림
 */
exports.sendPushOnMessageV2 = onDocumentCreated({
    document: "messages/{messageId}",
    region: "asia-northeast3"
}, async (event) => {
    console.log(`[Push] Triggered for message ${event.params.messageId}`);
    const messageData = event.data.data();
    const memberId = messageData.memberId;
    const content = messageData.content;

    if (!memberId || !content) return;
    
    // [GUARD] Skip scheduled messages (handled by scheduler)
    if (messageData.status === 'scheduled') {
        console.log(`[Push] Skipping scheduled message ${event.params.messageId}`);
        return;
    }

    try {
        const db = admin.firestore();
        // [FIX] 인라인 3중 컬렉션 순회 → getAllFCMTokens 헬퍼로 통합
        const { tokens, tokenSources } = await getAllFCMTokens(db, { memberId });

        if (tokens.length === 0) {
            await event.data.ref.update({
                pushStatus: {
                    sent: false,
                    error: "No registered device found.",
                    sentAt: admin.firestore.FieldValue.serverTimestamp()
                }
            });
            return;
        }

        const studioName = await getStudioName();
        const payload = {
            notification: { title: `${studioName} 메시지`, body: content },
            data: { url: "https://boksaem-yoga.web.app/member?tab=messages" }
        };

        const response = await admin.messaging().sendEachForMulticast({
            tokens,
            notification: payload.notification,
            data: payload.data,
            webpush: {
                notification: { icon: "https://boksaem-yoga.web.app/logo_circle.png" },
                fcm_options: { link: "https://boksaem-yoga.web.app/member?tab=messages" }
            },
            android: {
                notification: { color: "#D4AF37", icon: "stock_ticker_update" }
            }
        });

        // Clean stale tokens
        const tokensToDelete = [];
        response.responses.forEach((res, idx) => {
            if (!res.success && 
                (res.error?.code === 'messaging/invalid-registration-token' ||
                 res.error?.code === 'messaging/registration-token-not-registered')) {
                tokensToDelete.push({ token: tokens[idx], col: tokenSources[tokens[idx]] });
            }
        });

        if (tokensToDelete.length > 0) {
            const batch = admin.firestore().batch();
            tokensToDelete.forEach(item => {
                batch.delete(admin.firestore().collection(item.col).doc(item.token));
            });
            await batch.commit();
        }

        // Write to push_history
        if (response.successCount > 0) {
            const memberDoc = await db.collection('members').doc(memberId).get();
            const memberName = memberDoc.exists ? memberDoc.data().name : 'Unknown';
            
            await admin.firestore().collection('push_history').add({
                type: 'individual',
                title: payload.notification.title,
                body: payload.notification.body,
                status: 'sent',
                successCount: response.successCount,
