/**
 * 예약 메시지 발송 (매 10분마다 실행)
 */
exports.sendScheduledMessages = onSchedule({
    schedule: "*/10 * * * *",
    timeZone: "Asia/Seoul",
    region: "asia-northeast3"
}, async (event) => {
    const db = admin.firestore();
    const now = new Date();
    
    console.log(`[Scheduled] Checking for messages to send at ${now.toISOString()}`);

    try {
        // Query for messages that are 'scheduled' and due
        const snapshot = await db.collection('messages')
            .where('status', '==', 'scheduled')
            .where('scheduledAt', '<=', now.toISOString())
            .get();

        if (snapshot.empty) {
            console.log('[Scheduled] No messages due.');
            return;
        }

        console.log(`[Scheduled] Found ${snapshot.size} messages to send.`);
        const solapiModule = require('./solapi'); // Lazy load if needed, or re-implement logic
        // Since we cannot easily invoke other cloud functions directly from here without HTTP,
        // and logic is relatively simple, we will duplicate the core sending logic or trigger updates.
        
        // BETTER APPROACH: 
        // We will update the status to 'pending' (or a new trigger state 'sending_scheduled')
        // But our existing triggers ignore 'scheduled', so changing to 'pending' MIGHT trigger them?
        // No, onDocumentCreated only triggers on creation. onDocumentUpdated is NOT set up for messages.
        
        // So we must Implement Sending Logic Here.
        
        const messageService = solapiModule.messageService; // Access exported service if available? 
        // Actually solapi.js exports 'sendSolapiOnMessageV2', not the service instance usually.
        // We'll initialize Solapi Service here locally or import a helper if we had one.
        // To be safe and quick, let's re-implement the core sending steps for these docs.

        // Initialize Solapi ONLY if needed
        const { SolapiMessageService } = require("solapi");
        let myMessageService = null;
        if (process.env.SOLAPI_API_KEY && process.env.SOLAPI_API_SECRET) {
            myMessageService = new SolapiMessageService(
                process.env.SOLAPI_API_KEY, 
                process.env.SOLAPI_API_SECRET
            );
        }

        const docsToProcess = snapshot.docs;
        const results = [];

        for (const doc of docsToProcess) {
            const msg = doc.data();
            const memberId = msg.memberId;
            const content = msg.content;
            
            // 1. Send Push
            let pushSuccess = false;
            try {
                // Get Tokens
                const tokensSnap = await db.collection("fcm_tokens").where("memberId", "==", memberId).get();
                const tokens = tokensSnap.docs.map(t => t.id);
                
                if (tokens.length > 0) {
                    const payload = {
                        notification: { title: "내요가 예약 알림", body: content },
                        data: { url: "https://boksaem-yoga.web.app/member?tab=messages" }
                    };
                    const response = await admin.messaging().sendEachForMulticast({
                        tokens,
                        notification: payload.notification,
                        data: payload.data,
                        android: { notification: { color: "#D4AF37", icon: "stock_ticker_update" } }
                    });
                    pushSuccess = response.successCount > 0;
                }
            } catch (e) {
                console.error(`[Scheduled] Push failed for ${doc.id}:`, e);
            }

            // 2. Send Solapi (SMS/AlimTalk)
            let solapiResult = null;
            if (myMessageService && !msg.skipSolapi) {
                try {
                    const memberDoc = await db.collection('members').doc(memberId).get();
                    if (memberDoc.exists) {
                        const phone = memberDoc.data().phone?.replace(/-/g, '');
                        if (phone) {
                             const solapiPayload = {
                                to: phone,
                                from: process.env.SOLAPI_SENDER_NUMBER || "01022232789",
                                text: content,
                                subject: "복샘요가 알림"
                            };
                            // Simple LMS/SMS for now
                            solapiResult = await myMessageService.sendOne(solapiPayload);
                        }
                    }
                } catch (e) {
                    console.error(`[Scheduled] Solapi failed for ${doc.id}:`, e);
                }
            }

            // Prepare updates instead of batching immediately
            results.push({
                ref: doc.ref,
                updateData: {
                    status: 'sent',
                    sentAt: new Date().toISOString(),
                    pushStatus: { sent: pushSuccess, note: 'Scheduled Send' },
                    solapiStatus: solapiResult ? { sent: true, result: solapiResult } : { sent: false }
                },
                historyData: (pushSuccess || solapiResult) ? {
                    type: 'individual_scheduled',
                    title: "예약 알림",
                    body: content,
                    status: 'sent',
                    targetMemberId: memberId,
                    createdAt: new Date()
                } : null
            });
        }

        // Chunking the execution to handle > 500 documents
        // Each result produces 1 to 2 operations (update message, set history)
        // A batch can hold 500 operations. To be perfectly safe, chunk by 200 items (max 400 ops)
        const CHUNK_SIZE = 200;
        const chunks = chunk(results, CHUNK_SIZE);

        for (const batchChunk of chunks) {
            const batch = db.batch();
            for (const item of batchChunk) {
                 batch.update(item.ref, item.updateData);
                 if (item.historyData) {
                     const historyRef = db.collection('push_history').doc();
                     batch.set(historyRef, item.historyData);
                 }
            }
            await batch.commit();
        }

        console.log(`[Scheduled] Successfully processed ${results.length} messages.`);

    } catch (error) {
        console.error("Scheduled message processing failed:", error);
    }
});

/**
 * Solapi Message Module
 * 솔라피(SOLAPI) 알림톡 및 문자 발송 관련 Cloud Functions
 * 
 * @module modules/solapi
 */

const { onDocumentCreated, onDocumentUpdated } = require("firebase-functions/v2/firestore");
const { admin, logAIError, getStudioName } = require("../helpers/common");
const { SolapiMessageService } = require("solapi");

// Initialize Solapi Service
let messageService;
try {
    const apiKey = process.env.SOLAPI_API_KEY;
    const apiSecret = process.env.SOLAPI_API_SECRET;
    if (apiKey && apiSecret) {
        messageService = new SolapiMessageService(apiKey, apiSecret);
    } else {
        console.warn("[Solapi] API Key or Secret is missing in environment variables.");
    }
} catch (e) {
    console.error("[Solapi] Failed to initialize service:", e);
}

/**
 * 메시지 승인 시 발송 트리거
 * message_approvals 컬렉션의 문서가 'approved' 상태로 변경되면 발송
 */
exports.sendMessageOnApproval = onDocumentUpdated({
    document: "message_approvals/{approvalId}",
    region: "asia-northeast3",
    timeoutSeconds: 300, // [PERF FIX] V2 타임아웃 5분으로 연장하여 타임아웃으로 인한 중도 끊김 방지
    memory: "512MiB"
}, async (event) => {
    const newData = event.data.after.data();
    const oldData = event.data.before.data();
    const approvalId = event.params.approvalId;

    // Only process if status changed to 'approved'
    if (newData.status !== 'approved' || oldData.status === 'approved') return;

    // Prevent double sending
    if (newData.solapiStatus?.sent) {
        console.log(`[Solapi] Message ${approvalId} already sent.`);
        return;
    }

    console.log(`[Solapi] Processing approved message: ${approvalId}`);
    const db = admin.firestore();

    try {
        if (!messageService) {
            throw new Error("Solapi service is not initialized.");
        }

        const targetMemberIds = newData.targetMemberIds || [];
        const content = newData.body || "";
        const studioName = await getStudioName();
        const title = newData.title || `${studioName} 알림`;
        const senderNumber = process.env.SOLAPI_SENDER_NUMBER || "01022232789";

        if (!content) {
            throw new Error("Message content is empty.");
        }

        // 1. Get Target Phone Numbers
        const phoneNumbers = [];
        const memberChunks = [];
        const chunkSize = 10; // Firestore limit for 'in' query

        for (let i = 0; i < targetMemberIds.length; i += chunkSize) {
            memberChunks.push(targetMemberIds.slice(i, i + chunkSize));
        }

        for (const chunk of memberChunks) {
            const snap = await db.collection('members').where(admin.firestore.FieldPath.documentId(), 'in', chunk).get();
            snap.docs.forEach(doc => {
                const data = doc.data();
                if (data.phone) {
                    // Normalize phone number (remove dashes)
                    const cleanPhone = data.phone.replace(/-/g, '');
                    if (cleanPhone.length >= 10) { // Simple validation
                        phoneNumbers.push({ to: cleanPhone, name: data.name });
                    }
                }
            });
        }

        if (phoneNumbers.length === 0) {
            throw new Error("No valid phone numbers found for targets.");
        }

        // 2. Prepare Messages (LMS/SMS)
        // Note: 알림톡(Kakao AlimTalk) requires templateId. 
        // Failing back to LMS (Long Message Service) for general purpose content like "Holiday Notice".
        const messages = phoneNumbers.map(p => ({
            to: p.to,
            from: senderNumber,
            text: content,
            subject: title, // Used for LMS subject
            kakaoOptions: {
                pfId: process.env.KAKAO_PFID, // Optional: needed for AlimTalk
                templateId: newData.templateId // Optional: needed for AlimTalk
            }
            // If templateId is provided, Solapi tries AlimTalk first, fallbacks to SMS/LMS if failed.
            // If no templateId, it sends SMS/LMS directly.
        }));

        // 3. Send Bulk Messages (limit 1000 per request, handling batching if needed)
        // Solapi SDK handles some batching, but let's be safe with smaller chunks if massive.
        // For typical usage (< 100), SDK's sendMany or sendOne is fine.
        // Solapi sendMany accepts array of messages.
        
        // Split into chunks of 100 for safety
        const sendChunks = [];
        for (let i = 0; i < messages.length; i += 100) {
             sendChunks.push(messages.slice(i, i + 100));
        }

        let successCount = 0;
        let failureCount = 0;
        const groupIds = [];

        for (const chunk of sendChunks) {
            const result = await messageService.send(chunk);
            // Result format depends on SDK version, usually contains groupInfo
            console.log(`[Solapi] Sent chunk result:`, JSON.stringify(result));
            
            // Count approximate success (Solapi async result usually returns Group ID)
            // For precise tracking, we'd need to query status, but for now assume acceptance = success
            successCount += Object.keys(result).length; // Solapi returns map of messageId -> message object usually
            
            // If result has groupId, store it
             const firstKey = Object.keys(result)[0];
             if (result[firstKey]?.groupId) {
                 if (!groupIds.includes(result[firstKey].groupId)) {
                     groupIds.push(result[firstKey].groupId);
                 }
             }
        }

        // 4. Update Approval Doc
        await event.data.after.ref.update({
            solapiStatus: {
                sent: true,
                sentAt: new Date().toISOString(),
                method: newData.templateId ? 'ALIMTALK' : 'LMS',
