      const memberMap = {};
      membersSnapshot.forEach(doc => { memberMap[doc.id] = doc.data(); });

      const todayStr = new Date().toLocaleDateString('sv-SE', { timeZone: 'Asia/Seoul' });
      const startOfDay = new Date(`${todayStr}T00:00:00+09:00`);
