import { useState, useMemo, useEffect } from 'react';
import { User, Phone, CalendarBlank, MapPin, Trash, CheckCircle, Warning, ClockCounterClockwise, Plus, X } from '@phosphor-icons/react';
import { useStudioConfig } from '../../../contexts/StudioContext';
import { storageService } from '../../../services/storage';
import CustomDatePicker from '../../common/CustomDatePicker';
import AttendanceHistory from '../../profile/AttendanceHistory';
import { translations } from '../../../utils/translations';

const AttendanceTab = ({ logs, member, aiAnalysis, onAdd, onDelete, isSubmitting, logLimit, setLogLimit }) => {
    const { config } = useStudioConfig();
    const branches = config.BRANCHES || [];

    const getSafeToday = () => {
        const d = new Date();
        const year = d.getFullYear();
        const month = String(d.getMonth() + 1).padStart(2, '0');
        const day = String(d.getDate()).padStart(2, '0');
        return `${year}-${month}-${day}`;
    };

    const [manualDate, setManualDate] = useState(getSafeToday());
    const [manualClassName, setManualClassName] = useState('자율수련');
    const [manualBranch, setManualBranch] = useState(member.homeBranch || (branches.length > 0 ? branches[0].id : ''));
    const [dailyClasses, setDailyClasses] = useState([]);

    // 선택된 날짜와 지점에 해당하는 수업 목록 가져오기
    useEffect(() => {
        const fetchClasses = async () => {
            if (!manualBranch || !manualDate) return;
            try {
                const classes = await storageService.getDailyClasses(manualBranch, null, manualDate);
                setDailyClasses(classes || []);
            } catch (err) {
                console.warn('[AttendanceTab] Failed to fetch daily classes:', err);
                setDailyClasses([]);
            }
        };
        fetchClasses();
    }, [manualBranch, manualDate]);

    // 수업 목록: 선택 지점의 해당 날짜 수업 + 자율수련(시간만)
    const classOptions = useMemo(() => {
        // 자율수련 포함 - 선택된 지점의 이름 찾기
        const selectedBranchName = branches.find(b => b.id === manualBranch)?.name || '';
        const options = [{ value: '자율수련', label: '자율수련' }];

        if (dailyClasses.length > 0) {
            dailyClasses.forEach(cls => {
                const time = cls.time || '';
                const title = cls.title || cls.className || '';
                const instructor = cls.instructor || '';
                const parts = [time, title, instructor].filter(Boolean);
                const label = parts.join(' ');
                options.push({ value: title, label, time, instructor });
            });
        }
        return options;
    }, [dailyClasses, manualBranch, branches]);

    // 지점이나 날짜 변경 시 수업 선택 초기화
    useEffect(() => {
        setManualClassName('자율수련');
    }, [manualBranch, manualDate]);

    return (
        <div>
            <h3 style={{ color: 'var(--primary-gold)', marginBottom: '15px', fontSize: '1rem' }}>수동 출석 처리</h3>
            <div style={{
                background: 'rgba(255,255,255,0.05)', padding: '15px', borderRadius: '10px', marginBottom: '20px',
                display: 'flex', alignItems: 'center', gap: '8px', flexWrap: 'wrap'
            }}>
                <select
                    value={manualBranch}
                    onChange={(e) => setManualBranch(e.target.value)}
                    disabled={isSubmitting}
                    className="form-select"
                    style={{
                        flex: 1, minWidth: '100px',
                        opacity: isSubmitting ? 0.5 : 1
                    }}
                >
                    {branches.map(b => (
                        <option key={b.id} value={b.id}>{b.name}</option>
                    ))}
                </select>
                <div style={{ flex: 1.5, minWidth: '130px', opacity: isSubmitting ? 0.5 : 1 }}>
                    <CustomDatePicker value={manualDate} onChange={setManualDate} />
                </div>
                <select
                    value={manualClassName}
                    onChange={(e) => setManualClassName(e.target.value)}
                    disabled={isSubmitting}
                    className="form-select"
                    style={{
                        flex: 1.2, minWidth: '120px',
                        opacity: isSubmitting ? 0.5 : 1
                    }}
                >
                    {classOptions.map(opt => (
                        <option key={opt.label} value={opt.value}>{opt.label}</option>
                    ))}
                </select>
                <button
                    onClick={() => onAdd(manualDate, '10:00', manualBranch, manualClassName)}
                    disabled={isSubmitting}
                    style={{
                        background: isSubmitting ? 'rgba(212,175,55,0.3)' : 'var(--primary-gold)',
                        color: 'black', fontWeight: 'bold', border: 'none',
                        padding: '10px 15px', borderRadius: '8px', whiteSpace: 'nowrap', flex: '0 0 auto',
                        cursor: isSubmitting ? 'not-allowed' : 'pointer',
                        opacity: isSubmitting ? 0.6 : 1
                    }}
                >
                    {isSubmitting ? '처리 중...' : '출석'}
                </button>
            </div>

            <AttendanceHistory
                logs={logs}
                member={member}
                aiAnalysis={aiAnalysis}
                language="ko"
                t={(k) => translations.ko[k] || k}
                onDelete={onDelete}
                isSubmitting={isSubmitting}
                logLimit={logLimit}
                setLogLimit={setLogLimit}
            />
        </div>
    );
};

export default AttendanceTab;

import { useState, useEffect, useRef } from 'react';

import { storageService } from '../../../services/storage';
import { onSnapshot, collection, query, where, orderBy, limit as firestoreLimit, getDocs } from 'firebase/firestore';
import { db } from '../../../firebase';
import { useStudioConfig } from '../../../contexts/StudioContext';
import { Info, Copy } from '@phosphor-icons/react';

const MessagesTab = ({ memberId }) => {
    const { config } = useStudioConfig();
    const [message, setMessage] = useState('');
    const [sending, setSending] = useState(false);
    const [history, setHistory] = useState([]);
    const [msgLimit, setMsgLimit] = useState(10);
    const [notices, setNotices] = useState([]);
    
    // [NEW] Scheduled Sending State
    const [isScheduled, setIsScheduled] = useState(false);
    const [scheduledTime, setScheduledTime] = useState('');
    const [selectedTemplateId, setSelectedTemplateId] = useState('');
    const scheduleInputRef = useRef(null);

    // [Solapi] AlimTalk Templates
    const alimTalkTemplates = config.ALIMTALK_TEMPLATES || [];
    const selectedTemplate = alimTalkTemplates.find(t => t.id === selectedTemplateId);

    // [UX] Auto-open picker when scheduled is checked
    const handleScheduleToggle = (e) => {
        const checked = e.target.checked;
        setIsScheduled(checked);
        if (checked) {
            setTimeout(() => {
                try {
                    if (scheduleInputRef.current) scheduleInputRef.current.showPicker();
                } catch (e) {
                    // ignore
                }
            }, 100);
        }
    };

    const handleTemplateSelect = (e) => {
        const id = e.target.value;
        setSelectedTemplateId(id);
        
        // [UX] Auto-fill message content when template is selected
        const template = alimTalkTemplates.find(t => t.id === id);
        if (template && template.content) {
            setMessage(template.content);
        } else if (!id) {
            setMessage('');
        }
    };

    const handleCopyTemplate = () => {
        if (selectedTemplate && selectedTemplate.content) {
            setMessage(selectedTemplate.content);
        }
    };

    // [REAL-TIME] Individual Message History Listener
    useEffect(() => {
        if (!memberId) return;

        console.log(`[MessagesTab] Subscribing to messages for member: ${memberId}`);
        const q = query(
            collection(db, 'messages'),
            where("memberId", "==", memberId),
            orderBy("timestamp", "desc"),
            firestoreLimit(msgLimit)
        );

        const unsub = onSnapshot(q, (snap) => {
            const logs = snap.docs.map(doc => ({ id: doc.id, ...doc.data(), type: 'individual' }));
            // [FIX] Sort client-side
            logs.sort((a, b) => new Date(b.timestamp) - new Date(a.timestamp));
            setHistory(logs);
        }, (err) => {
            console.error("[MessagesTab] History listener error:", err);
        });

        return () => unsub();
    }, [memberId, msgLimit]);

    // [NEW] Load Notice/Campaign Push History
    useEffect(() => {
        const loadNotices = async () => {
            try {
                const q = query(
                    collection(db, 'push_history'),
                    where('type', 'in', ['campaign', 'notice']),
                    orderBy('createdAt', 'desc'),
                    firestoreLimit(20)
                );
                const snapshot = await getDocs(q);
                const noticeList = snapshot.docs.map(doc => ({
                    id: doc.id,
                    ...doc.data(),
                    type: 'notice',
                    timestamp: doc.data().createdAt?.toDate()?.toISOString() || new Date().toISOString()
                }));
                setNotices(noticeList);
            } catch (err) {
                console.error('[MessagesTab] Failed to load notices:', err);
            }
        };
        loadNotices();
    }, []);

    const handleSend = async () => {
        if (!message.trim() || !memberId) return;
        
        let method = selectedTemplateId ? '알림톡' : '문자(LMS)';
        let confirmMsg = `메시지를 실제 전송하시겠습니까? 회원의 스마트폰으로 ${method}가 발송됩니다.`;
        if (isScheduled) {
            if (!scheduledTime) {
                alert('예약 시간을 설정해주세요.');
                return;
            }
            const scheduledDate = new Date(scheduledTime);
            if (scheduledDate <= new Date()) {
                alert('예약 시간은 현재 시간 이후여야 합니다.');
                return;
            }
            confirmMsg = `메시지를 예약하시겠습니까?\n발송 예정: ${scheduledDate.toLocaleString()}`;
        }

        if (!confirm(confirmMsg)) return;

        setSending(true);
        try {
            await storageService.addMessage(
                memberId, 
                message, 
                isScheduled ? new Date(scheduledTime).toISOString() : null,
                selectedTemplateId
            );
            setMessage('');
            setIsScheduled(false);
            setScheduledTime('');
            setSelectedTemplateId('');
            if (isScheduled) alert('메시지가 예약되었습니다.');
        } catch (error) {
            console.error("Message send failed:", error);
            alert('발송에 실패했습니다. 네트워크 상태를 확인해주세요.');
        } finally {
            setSending(false);
        }
    };

    const templates = [
        "회원님, 재등록 기간입니다. 확인 부탁드려요! 🧘‍♀️",
        "안녕하세요! 이번 주 휴강 안내드립니다.",
        "오랜만이네요! 수련하러 오세요 ✨",
        "수강권이 7일 남았습니다."
    ];

    return (
        <div className="fade-in" style={{ display: 'flex', flexDirection: 'column', height: '100%' }}>
            {/* Input Area */}
            <div style={{ background: 'rgba(255,255,255,0.05)', padding: '15px', borderRadius: '12px', marginBottom: '20px' }}>
                
                {/* [Solapi] Template Selection */}
                <div style={{ marginBottom: '12px' }}>
                    <label style={{ display: 'block', marginBottom: '6px', fontSize: '0.8rem', color: '#a1a1aa' }}>발송 유형 (알림톡/문자)</label>
                    <select
                        value={selectedTemplateId}
                        onChange={handleTemplateSelect}
                        style={{
                            width: '100%', padding: '8px', borderRadius: '8px',
                            background: 'rgba(255,255,255,0.08)', border: '1px solid rgba(255,255,255,0.1)',
                            color: 'white', outline: 'none', cursor: 'pointer', fontSize: '0.9rem'
                        }}
                    >
                        {alimTalkTemplates.map(t => (
                            <option key={t.id} value={t.id} style={{ background: '#1d1d2b' }}>
                                {t.name}
                            </option>
                        ))}
                    </select>

                    {/* [NEW] AlimTalk Template Preview */}
                    {selectedTemplateId && selectedTemplate && (
                        <div style={{ 
                            marginTop: '12px', padding: '12px', 
                            background: 'rgba(212, 175, 55, 0.05)', 
                            borderRadius: '8px', border: '1px dashed rgba(212, 175, 55, 0.3)' 
                        }}>
                            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '8px' }}>
                                <div style={{ display: 'flex', alignItems: 'center', gap: '6px', fontSize: '0.75rem', color: 'var(--primary-gold)' }}>
                                    <Info size={14} /> 알림톡 템플릿 가이드
                                </div>
                                <button 
                                    onClick={handleCopyTemplate}
                                    style={{ 
                                        background: 'rgba(212, 175, 55, 0.2)', color: 'white', 
                                        border: 'none', borderRadius: '4px', padding: '4px 8px', 
                                        fontSize: '0.7rem', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '4px' 
                                    }}
                                >
                                    <Copy size={12} /> 내용 복사하기
                                </button>
                            </div>
                            <div style={{ fontSize: '0.85rem', color: '#e4e4e7', lineHeight: '1.4', wordBreak: 'break-all' }}>
                                {selectedTemplate.content}
                            </div>
                            <div style={{ marginTop: '8px', fontSize: '0.7rem', color: '#a1a1aa' }}>
                                * 알림톡은 템플릿 내용과 일치해야 발송됩니다. 변수 부분만 수정하여 입력해주세요.
                            </div>
                        </div>
                    )}
                </div>

                <textarea
                    value={message}
                    onChange={e => setMessage(e.target.value)}
                    placeholder={selectedTemplateId ? "알림톡 템플릿 내용과 일치하게 입력해주세요." : "회원에게 보낼 메시지를 입력하세요..."}
                    style={{
                        width: '100%', height: '80px', background: 'transparent', border: 'none',
                        color: 'white', fontSize: '1rem', resize: 'none', outline: 'none'
                    }}
                />
                
                {/* [NEW] Cost Estimation */}
                <div style={{ display: 'flex', justifyContent: 'flex-end', fontSize: '0.8rem', color: '#a1a1aa', borderBottom: '1px solid rgba(255,255,255,0.1)', paddingBottom: '8px', marginBottom: '8px' }}>
                    {(() => {
                        // Simple byte calculation (Korean ~2bytes, English 1byte)
                        // Solapi/LMS standard: SMS <= 90 bytes, LMS > 90 bytes
                        let bytes = 0;
                        for (let i = 0; i < message.length; i++) {
                            const code = message.charCodeAt(i);
                            bytes += (code >> 7) ? 2 : 1;
                        }
                        const isLMS = bytes > 90;
                        const cost = selectedTemplateId ? 15 : (isLMS ? 45 : 18); // Approx rates
                        return (
                            <span style={{ color: selectedTemplateId ? 'var(--primary-gold)' : (isLMS ? '#f59e0b' : '#10b981') }}>
                                {bytes} bytes ({selectedTemplateId ? '알림톡' : (isLMS ? 'LMS' : 'SMS')}) • 예상 비용: 약 {cost}원
                            </span>
                        );
                    })()}
                </div>

                {/* [NEW] Scheduling UI */}
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: '0px' }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                        <input 
                            type="checkbox" 
                            id="scheduleCheck" 
                            checked={isScheduled} 
                            onChange={handleScheduleToggle}
                            style={{ accentColor: 'var(--primary-gold)', width: '16px', height: '16px', cursor: 'pointer' }}
                        />
                        <label htmlFor="scheduleCheck" style={{ color: '#e4e4e7', fontSize: '0.9rem', cursor: 'pointer', display: 'flex', alignItems: 'center' }}>
                            ⏰ 예약 발송
                        </label>
                        
                        {isScheduled && (
                            <input 
                                ref={scheduleInputRef}
                                type="datetime-local" 
                                value={scheduledTime}
                                onChange={e => setScheduledTime(e.target.value)}
                                onClick={() => {
                                    try {
                                        if(scheduleInputRef.current) scheduleInputRef.current.showPicker();
                                    } catch(e) {
                                        // ignore
                                    }
                                }}
                                style={{ 
                                    background: 'rgba(0,0,0,0.3)', 
                                    border: '1px solid rgba(255,255,255,0.2)', 
                                    borderRadius: '6px', 
                                    padding: '4px 8px', 
                                    color: 'white', 
                                    marginLeft: '8px',
                                    fontSize: '0.9rem',
                                    cursor: 'pointer'
                                }}
                            />
                        )}
                    </div>
                
                    <button
                        onClick={handleSend}
                        disabled={sending || !message.trim()}
                        style={{
                            background: sending ? '#52525b' : 'var(--primary-gold)',
                            color: sending ? '#d4d4d8' : 'black',
                            border: 'none', borderRadius: '8px', padding: '8px 20px',
                            fontWeight: 'bold', cursor: sending ? 'wait' : 'pointer'
                        }}
                    >
                        {sending ? '처리 중...' : (isScheduled ? '예약 하기' : '전송 하기')}
                    </button>
                </div>
            </div>

            {/* Templates */}
            <div style={{ marginBottom: '25px' }}>
                <p style={{ color: '#a1a1aa', fontSize: '0.85rem', marginBottom: '8px' }}>자주 쓰는 문구 (비용 절약 💡)</p>
                <div style={{ display: 'flex', flexWrap: 'wrap', gap: '8px' }}>
                    {templates.map((t, i) => (
                        <button
                            key={i}
                            onClick={() => setMessage(t)}
                            style={{
                                background: 'rgba(255,255,255,0.1)', border: '1px solid rgba(255,255,255,0.1)',
                                borderRadius: '20px', padding: '8px 12px', color: '#e4e4e7', fontSize: '0.85rem',
                                cursor: 'pointer', textAlign: 'left'
                            }}
                        >
                            {t}
                        </button>
                    ))}
                </div>
            </div>

            {/* History */}
            <div style={{ flex: 1, overflowY: 'auto' }}>
                <h4 style={{ color: 'var(--primary-gold)', fontSize: '0.95rem', marginBottom: '10px' }}>발송 이력 (개별 + 공지)</h4>
                {(() => {
                    // Merge and sort messages and notices
                    const combined = [...history, ...notices];
                    combined.sort((a, b) => new Date(b.timestamp) - new Date(a.timestamp));
                    return combined.length === 0 ? (
                        <p style={{ color: '#52525b', textAlign: 'center', marginTop: '20px', fontSize: '0.9rem' }}>발송된 메시지가 없습니다.</p>
                    ) : (
                        <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
                            {combined.map(log => (
                                <div key={log.id} style={{ 
                                    background: log.type === 'notice' ? 'rgba(212, 175, 55, 0.1)' : 'rgba(0,0,0,0.3)', 
                                    padding: '12px', 
                                    borderRadius: '8px',
                                    border: log.type === 'notice' ? '1px solid rgba(212, 175, 55, 0.2)' : 'none'
                                }}>
                                    <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '5px', alignItems: 'center' }}>
                                        <div style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
                                            <span style={{ 
                                                fontSize: '0.7rem', 
                                                color: log.type === 'notice' ? 'var(--primary-gold)' : '#3B82F6',
                                                fontWeight: '700',
                                                padding: '2px 6px',
                                                background: log.type === 'notice' ? 'rgba(212, 175, 55, 0.15)' : 'rgba(59, 130, 246, 0.15)',
                                                borderRadius: '4px'
                                            }}>
                                                {log.type === 'notice' ? '공지' : '개별'}
                                            </span>
                                            <span style={{ fontSize: '0.8rem', color: '#a1a1aa' }}>
                                                {log.timestamp ? new Date(log.timestamp).toLocaleString() : '전송 중...'}
                                            </span>
                                        </div>
                                        {log.type === 'individual' && (
                                            <div style={{ display: 'flex', gap: '6px', alignItems: 'center' }}>
                                                {/* Push Status */}
                                                {log.pushStatus && (
                                                    log.pushStatus.sent ? (
                                                        <span style={{ fontSize: '0.75rem', color: '#10b981', background: 'rgba(16, 185, 129, 0.1)', padding: '2px 6px', borderRadius: '4px' }}>앱푸시 성공</span>
                                                    ) : (
                                                        <span style={{ fontSize: '0.75rem', color: '#6b7280', background: 'rgba(107, 114, 128, 0.1)', padding: '2px 6px', borderRadius: '4px' }}>앱푸시 실패</span>
                                                    )
                                                )}
                                                
                                                {/* Solapi Status */}
                                                {log.solapiStatus ? (
                                                    log.solapiStatus.sent ? (
                                                        <span style={{ fontSize: '0.75rem', color: '#3B82F6', background: 'rgba(59, 130, 246, 0.1)', padding: '2px 6px', borderRadius: '4px' }}>
                                                            {log.solapiStatus.method === 'ALIMTALK' ? '알림톡 성공' : '문자 성공'}
                                                        </span>
                                                    ) : (
                                                        <span style={{ fontSize: '0.75rem', color: '#ef4444', background: 'rgba(239, 68, 68, 0.1)', padding: '2px 6px', borderRadius: '4px' }} title={log.solapiStatus.error || '알 수 없는 오류'}>
                                                            문자 실패 {log.solapiStatus.error && log.solapiStatus.error.includes('TooManyRequests') ? '(요청 초과)' : ''}
                                                        </span>
                                                    )
                                                ) : (
                                                    <span style={{ fontSize: '0.75rem', color: '#f59e0b' }}>전송 완료</span>
                                                )}
                                            </div>
                                        )}
                                    </div>
                                    <div style={{ color: 'white', fontSize: '0.9rem' }}>{log.content || log.body}</div>
                                </div>
                            ))}

                            {/* Pagination: Load More */}
                            {history.length >= msgLimit && (
                                <button
                                    onClick={() => setMsgLimit(prev => prev + 10)}
                                    style={{
                                        width: '100%',
                                        padding: '10px',
                                        background: 'rgba(255,255,255,0.05)',
                                        color: '#a1a1aa',
                                        border: '1px dashed rgba(255,255,255,0.2)',
                                        borderRadius: '8px',
                                        marginTop: '5px',
                                        cursor: 'pointer',
                                        fontSize: '0.85rem'
                                    }}
                                >
                                    ▿ 이전 메시지 더보기 (10개 추가)
                                </button>
                            )}
                        </div>
                    );
                })()}
            </div>
        </div>
    );
};

export default MessagesTab;

import { useState, useEffect, useMemo, useRef } from 'react';
import CustomDatePicker from '../../common/CustomDatePicker';

const RegistrationTab = ({ pricingConfig, member, onAddSalesRecord, onUpdateMember }) => {
    const [isSubmitting, setIsSubmitting] = useState(false);
    const isSubmittingRef = useRef(false);

    // Renew State
    const [membershipType, setMembershipType] = useState('general');
    const [selectedOption, setSelectedOption] = useState('');
    const [duration, setDuration] = useState(1);
    const [paymentMethod, setPaymentMethod] = useState('card');
    
    // [Smart Date Logic] — "첫 출석일 시작" 체크박스 (MemberAddModal 통일)
    const [autoStart, setAutoStart] = useState(false);
    const [startDate, setStartDate] = useState(() => {
        const today = new Date();
        const end = member.endDate ? new Date(member.endDate) : null;

        if (end && end >= new Date(today.setHours(0, 0, 0, 0))) {
            const restartDate = new Date(end);
            restartDate.setDate(restartDate.getDate() + 1);
            return restartDate.toLocaleDateString('sv-SE', { timeZone: 'Asia/Seoul' });
        }
        return new Date().toLocaleDateString('sv-SE', { timeZone: 'Asia/Seoul' });
    });

    // [New] Base duration for upcoming memberships
    const [durationMonths, setDurationMonths] = useState(1);

    // Computed
    const [price, setPrice] = useState(0);
    const [notesText, setNotesText] = useState(member?.notes || '');
    const [customEndDate, setCustomEndDate] = useState('');
    const [customCredits, setCustomCredits] = useState(0);

    // Init Logic & Changed Membership Type hook
    useEffect(() => {
        if (pricingConfig && pricingConfig[membershipType] && pricingConfig[membershipType].options.length > 0) {
            setSelectedOption(pricingConfig[membershipType].options[0].id);
        }
    }, [membershipType, pricingConfig]);

    // Calculation Logic - Use useMemo for derived values
    const { calculatedPrice, calculatedCredits, calculatedEndDate, calculatedProductName } = useMemo(() => {
        if (!pricingConfig) return { calculatedPrice: 0, calculatedCredits: 0, calculatedEndDate: '', calculatedProductName: '' };

        const category = pricingConfig[membershipType];
        if (!category) return { calculatedPrice: 0, calculatedCredits: 0, calculatedEndDate: '', calculatedProductName: '' };

        const option = category.options.find(opt => opt.id === selectedOption);
        if (!option) return { calculatedPrice: 0, calculatedCredits: 0, calculatedEndDate: '', calculatedProductName: '' };

        let p = 0;
        let c = 0;
        let months = duration;
        let label = option.label;

        if (paymentMethod === 'cash' && option.cashPrice !== undefined) {
            p = option.cashPrice;
            c = option.credits === 9999 ? 9999 : option.credits * duration;
            setDurationMonths(months);
        } else {
            if (option.type === 'ticket') {
                p = option.basePrice;
                c = option.credits;
                months = option.months || 3;
            } else {
                c = option.credits === 9999 ? 9999 : option.credits * duration;
                if (duration === 1) p = option.basePrice;
                else if (duration === 3) p = option.discount3 || (option.basePrice * 3);
                else if (duration === 6) p = option.discount6 || (option.basePrice * 6);
                else p = option.basePrice * duration;
            }

            if (paymentMethod === 'cash' && duration >= 3 && p > 0 && !option.cashPrice) {
                p = Math.round(p * 0.95);
            }
            setDurationMonths(months);
        }

        const start = new Date(startDate);
        const end = new Date(start);
        end.setMonth(end.getMonth() + months);
        end.setDate(end.getDate() - 1);

        return {
            calculatedPrice: p,
            calculatedCredits: c,
            calculatedEndDate: end.toLocaleDateString('sv-SE', { timeZone: 'Asia/Seoul' }),
            calculatedProductName: `${label} ${duration > 1 && option.type !== 'ticket' ? `(${duration}개월)` : ''}`
        };
    }, [membershipType, selectedOption, duration, paymentMethod, startDate, pricingConfig]);

    useEffect(() => { setPrice(calculatedPrice); }, [calculatedPrice]);
    useEffect(() => { setCustomEndDate(calculatedEndDate); }, [calculatedEndDate]);
    useEffect(() => { setCustomCredits(calculatedCredits); }, [calculatedCredits]);

    // [INFO] 선등록 여부 확인
    const todayStr = new Date().toLocaleDateString('sv-SE', { timeZone: 'Asia/Seoul' });
    const isAdvance = member.endDate && new Date(member.endDate) >= new Date(todayStr);

    // Computed Info for TBD mode
    const finalStartDate = (isAdvance && autoStart) ? 'TBD' : startDate;
    const finalEndDate = (isAdvance && autoStart) ? 'TBD' : customEndDate;

    const handleRenew = async () => {
        if (isSubmittingRef.current) {
            console.warn('[handleRenew] isSubmittingRef stuck, force-resetting');
            isSubmittingRef.current = false;
            setIsSubmitting(false);
        }
        if (isSubmitting) return;
        
        let confirmMsg = `${calculatedProductName}\n금액: ${price.toLocaleString()}원\n\n등록하시겠습니까?`;
        if (!confirm(confirmMsg)) return;

        isSubmittingRef.current = true;
        setIsSubmitting(true);
        try {
            const today = new Date().toLocaleDateString('sv-SE', { timeZone: 'Asia/Seoul' });

            const salesData = {
                memberId: member.id,
                memberName: member.name,
                type: 'register',
                item: calculatedProductName,
                amount: price,
                paymentMethod: paymentMethod,
                date: today,
                startDate: finalStartDate,
                endDate: finalEndDate,
            };

            if (onAddSalesRecord) await onAddSalesRecord(salesData);

            const updateData = {};
            if (isAdvance) {
                updateData.upcomingMembership = {
                    membershipType: membershipType,
                    credits: customCredits,
                    startDate: finalStartDate,
                    endDate: finalEndDate,
                    durationMonths: durationMonths,
                    price: price
                };
                updateData.lastPaymentDate = new Date().toISOString();
                updateData.price = price;
                if (notesText !== (member.notes || '')) updateData.notes = notesText;
            } else {
                updateData.membershipType = membershipType;
                updateData.credits = customCredits;
                updateData.startDate = finalStartDate;
                updateData.endDate = finalEndDate;
                updateData.lastPaymentDate = new Date().toISOString();
                updateData.price = price;
                if (notesText !== (member.notes || '')) updateData.notes = notesText;
            }

            await onUpdateMember(member.id, updateData);
            
            alert('등록이 완료되었습니다.');
        } catch (err) {
            console.error('Registration error:', err);
            alert('등록 중 오류가 발생했습니다.');
        } finally {
            setIsSubmitting(false);
            isSubmittingRef.current = false;
        }
    };

    return (
        <div style={{ display: 'flex', flexDirection: 'column', gap: '14px' }}>
            {/* 회원권 종류 */}
            <div className="form-group">
                <label className="form-label">회원권 종류</label>
                <select
                    className="form-select"
                    style={{ fontFamily: 'var(--font-main)' }}
                    value={membershipType}
                    onChange={e => {
                        const newType = e.target.value;
                        const firstOptionId = pricingConfig[newType]?.options[0]?.id || '';
                        setMembershipType(newType);
                        setSelectedOption(firstOptionId);
                        setDuration(1);
                    }}
                >
                    {pricingConfig && Object.entries(pricingConfig).map(([key, conf]) => (
                        <option key={key} value={key}>{conf.label || key}</option>
                    ))}
                </select>
            </div>

            {/* 세부 옵션 */}
            <div className="form-group">
                <label className="form-label">세부 옵션</label>
                <select
                    className="form-select"
                    style={{ fontFamily: 'var(--font-main)' }}
                    value={selectedOption}
                    onChange={e => setSelectedOption(e.target.value)}
                >
                    {pricingConfig?.[membershipType]?.options?.map(opt => (
                        <option key={opt.id} value={opt.id}>{opt.label}</option>
                    ))}
                </select>
            </div>

            {/* 등록 기간 */}
            {(() => {
                const option = pricingConfig?.[membershipType]?.options?.find(opt => opt.id === selectedOption);
                if (option && option.type === 'subscription') {
                    return (
                        <div className="form-group">
                            <label className="form-label">등록 기간</label>
                            <div style={{ display: 'flex', gap: '8px' }}>
                                {[1, 3, 6].map(m => (
                                    <button
                                        key={m}
                                        className={`action-btn ${duration === m ? 'primary' : ''}`}
                                        style={{ flex: 1, opacity: duration === m ? 1 : 0.4, padding: '14px 0', fontSize: '1rem', fontWeight: 'bold' }}
                                        onClick={() => setDuration(m)}
                                    >
                                        {m}개월
                                    </button>
                                ))}
                            </div>
                        </div>
                    );
                }
                return null;
            })()}

            {/* 결제 방식 */}
            <div className="form-group">
                <label className="form-label">결제 방식</label>
                <div style={{ display: 'flex', gap: '10px' }}>
                    {[
                        { id: 'card', label: '카드' },
                        { id: 'cash', label: '현금' },
                        { id: 'transfer', label: '이체' }
                    ].map(p => (
                        <button
                            key={p.id}
                            className={`action-btn ${paymentMethod === p.id ? 'primary' : ''}`}
                            style={{ flex: 1, padding: '14px 0', fontSize: '1rem', fontWeight: 'bold' }}
                            onClick={() => setPaymentMethod(p.id)}
                        >
                            {p.label}
                        </button>
                    ))}
                </div>
            </div>

            {/* 수련 시작일 */}
            <div className="form-group">
                <label className="form-label">수련 시작일</label>
                <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
                    {/* 첫 출석일 시작 체크박스 — 선등록 시에만 표시 */}
                    {isAdvance && (
                        <label style={{
                            padding: '12px 8px',
                            borderRadius: '10px',
                            background: autoStart ? 'rgba(212,175,55,0.15)' : 'rgba(255,255,255,0.05)',
                            border: `1px solid ${autoStart ? 'var(--primary-gold)' : 'transparent'}`,
                            fontSize: '0.85rem',
                            color: autoStart ? 'var(--primary-gold)' : 'var(--text-secondary)',
                            display: 'flex',
                            alignItems: 'center',
                            justifyContent: 'center',
                            gap: '6px',
                            cursor: 'pointer',
                            transition: 'all 0.2s',
                            fontWeight: autoStart ? 'bold' : 'normal'
                        }}>
                            <input
                                type="checkbox"
                                style={{ width: '16px', height: '16px' }}
                                checked={autoStart}
                                onChange={e => setAutoStart(e.target.checked)}
                            />
                            🧘‍♀️ 기존 마감 후 첫 출석 시 시작
                        </label>
                    )}

                    {/* 날짜 입력 */}
                    {autoStart && isAdvance ? (
                        <div style={{ padding: '12px', borderRadius: '8px', background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.1)', color: 'white', textAlign: 'center', fontSize: '0.9rem' }}>
                            첫 출석일에 시작일/마감일 자동 확정
                        </div>
                    ) : (
                        <input
                            type="date"
                            className="form-input"
                            style={{ width: '100%', fontFamily: 'var(--font-main)', cursor: 'pointer' }}
                            value={startDate}
                            onClick={(e) => e.target.showPicker && e.target.showPicker()}
                            onChange={e => setStartDate(e.target.value)}
                        />
                    )}

                    {/* 마감일(종료일) 수정 */}
                    <div style={{ marginTop: '4px' }}>
                        <label style={{ display: 'flex', justifyContent: 'space-between', fontSize: '0.8rem', color: 'var(--text-secondary)', marginBottom: '8px' }}>
                            <span>마감일(종료일) 수정</span>
                            {autoStart && isAdvance && <span style={{ color: 'var(--primary-gold)' }}>*첫 출석 시 조정됨</span>}
                        </label>
                        <input
                            type="date"
                            className="form-input"
                            style={{ width: '100%', cursor: autoStart && isAdvance ? 'not-allowed' : 'pointer', opacity: autoStart && isAdvance ? 0.6 : 1 }}
                            value={autoStart && isAdvance ? '' : customEndDate}
                            disabled={autoStart && isAdvance}
                            onClick={(e) => !(autoStart && isAdvance) && e.target.showPicker && e.target.showPicker()}
                            onChange={e => setCustomEndDate(e.target.value)}
                        />
                    </div>

                    {/* 선등록 안내 */}
                    {isAdvance && (
                        <div style={{
                            fontSize: '0.75rem', padding: '10px',
                            background: 'rgba(56, 189, 248, 0.08)', borderRadius: '8px',
                            color: '#38bdf8', border: '1px solid rgba(56, 189, 248, 0.15)'
                        }}>
                            ℹ️ 잔여 기간이 남아있어 선등록으로 처리됩니다. {autoStart ? '기존 마감 후 첫 출석 시 활성화됩니다.' : '지정한 시작일에 활성화됩니다.'}
                        </div>
                    )}
                </div>
            </div>

            {/* 원장 메모 */}
            <div className="form-group">
                <label className="form-label" style={{ marginBottom: '6px' }}>원장 메모 (선택)</label>
                <textarea
                    className="form-input"
                    style={{ fontFamily: 'var(--font-main)', padding: '14px 18px', fontSize: '1rem', minHeight: '80px', resize: 'vertical' }}
                    value={notesText}
                    onChange={e => setNotesText(e.target.value)}
                    placeholder="특이사항이나 메모를 입력하세요"
                />
            </div>

            {/* 결제 요약 카드 — MemberAddModal과 동일 스타일 */}
            <div className="form-group" style={{ background: 'rgba(212,175,55,0.08)', padding: '20px', borderRadius: '16px', border: '1px solid rgba(212,175,55,0.2)', boxShadow: 'inset 0 2px 10px rgba(0,0,0,0.2)' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'baseline' }}>
                    <span style={{ fontSize: '0.85rem', color: 'rgba(255,255,255,0.6)', fontWeight: 'bold' }}>결제 금액</span>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '4px' }}>
                        <input
                            className="form-input"
                            style={{
                                fontSize: '1.4rem',
                                fontWeight: '900',
                                color: 'var(--primary-gold)',
                                background: 'transparent',
                                border: 'none',
                                textAlign: 'right',
                                width: '150px',
                                padding: 0,
                                height: 'auto'
                            }}
                            value={price.toLocaleString()}
                            onChange={(e) => {
                                const rawValue = e.target.value.replace(/[^0-9]/g, '');
                                setPrice(Number(rawValue));
                            }}
                        />
                        <span style={{ fontSize: '1.4rem', fontWeight: '900', color: 'var(--primary-gold)' }}>원</span>
                    </div>
                </div>
                <div style={{ fontSize: '0.95rem', color: 'var(--text-primary)', marginTop: '12px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', borderTop: '1px solid rgba(255,255,255,0.1)', paddingTop: '12px' }}>
                    <span style={{ fontWeight: 600 }}>횟수</span>
                    {customCredits > 200 || customCredits === 9999 ? (
                        <span style={{ fontWeight: 600 }}>무제한</span>
                    ) : (
                        <div style={{ display: 'flex', alignItems: 'center', gap: '4px' }}>
                            <input
                                className="form-input"
                                type="number"
                                style={{
                                    width: '60px', textAlign: 'right', padding: '6px 8px',
                                    background: 'rgba(255,255,255,0.08)', border: '1px solid rgba(255,255,255,0.15)',
                                    borderRadius: '8px', color: 'white', fontSize: '1rem', fontWeight: '700'
                                }}
                                value={customCredits}
                                onChange={(e) => setCustomCredits(Number(e.target.value))}
                            />
                            <span style={{ fontWeight: 600 }}>회</span>
                        </div>
                    )}
                </div>
            </div>

            {/* 등록 버튼 */}
            <button
                onClick={handleRenew}
                disabled={isSubmitting}
                className="action-btn primary"
                style={{
                    padding: '18px 0', fontSize: '1.1rem', fontWeight: '800',
                    borderRadius: '16px', boxShadow: '0 10px 20px rgba(212, 175, 55, 0.2)',
                    opacity: isSubmitting ? 0.6 : 1, cursor: isSubmitting ? 'not-allowed' : 'pointer',
                    marginTop: '10px'
                }}
            >
                {isSubmitting ? '처리 중...' : '등록 하기'}
            </button>
        </div>
    );
};

export default RegistrationTab;

import React, { useState, useRef } from 'react';
import { X, PaperPlaneTilt, Calendar, CurrencyKrw, Info, Copy } from '@phosphor-icons/react';
import { storageService } from '../../../services/storage';
import { useStudioConfig } from '../../../contexts/StudioContext';

const BulkMessageModal = ({ isOpen, onClose, selectedMemberIds, memberCount }) => {
    const { config } = useStudioConfig();
    const [message, setMessage] = useState('');
    const [sending, setSending] = useState(false);
    const [isScheduled, setIsScheduled] = useState(false);
    const [scheduledTime, setScheduledTime] = useState('');
    const [selectedTemplateId, setSelectedTemplateId] = useState('');
    const scheduleInputRef = useRef(null);

    if (!isOpen) return null;

    const templates = [
        "회원님, 재등록 기간입니다. 확인 부탁드려요! 🧘‍♀️",
        "안녕하세요! 이번 주 휴강 안내드립니다.",
        "오랜만이네요! 수련하러 오세요 ✨",
        "수강권이 7일 남았습니다.",
        "[공지] 다음 주 수업 일정 변경 안내"
    ];

    // [Solapi] AlimTalk Templates
    const alimTalkTemplates = config.ALIMTALK_TEMPLATES || [];
    const selectedTemplate = alimTalkTemplates.find(t => t.id === selectedTemplateId);

    const calculateCost = (msg) => {
        let bytes = 0;
        for (let i = 0; i < msg.length; i++) {
            const code = msg.charCodeAt(i);
            bytes += (code >> 7) ? 2 : 1;
        }
        const isLMS = bytes > 90;
        // AlimTalk is usually cheaper (e.g., 15 KRW), but fallback to LMS if failed. 
        // Let's assume standard LMS cost for safety estimation or 15 won if AlimTalk.
        const costPerMsg = selectedTemplateId ? 15 : (isLMS ? 45 : 18);
        return { bytes, isLMS, costPerMsg, totalCost: costPerMsg * memberCount };
    };

    const costInfo = calculateCost(message);

    const handleSend = async () => {
        if (!message.trim()) return;
        if (isScheduled && !scheduledTime) {
            alert("예약 시간을 선택해주세요.");
            return;
        }

        const method = selectedTemplateId ? '알림톡' : (costInfo.isLMS ? 'LMS' : 'SMS');
        if (!confirm(`${memberCount}명에게 ${method}를 전송하시겠습니까?\n예상 비용: 약 ${costInfo.totalCost.toLocaleString()}원`)) {
            return;
        }

        setSending(true);
        try {
            // [Solapi] Pass selectedTemplateId
            await storageService.sendBulkMessages(selectedMemberIds, message, isScheduled ? scheduledTime : null, selectedTemplateId);
            alert("전송이 시작되었습니다.");
            onClose();
            setMessage('');
            setIsScheduled(false);
            setScheduledTime('');
            setSelectedTemplateId('');
        } catch (error) {
            console.error("Bulk send failed:", error);
            alert("전송 실패: " + error.message);
        } finally {
            setSending(false);
        }
    };

    // [UX] Auto-open picker when scheduled is checked
    const handleScheduleToggle = (e) => {
        const checked = e.target.checked;
        setIsScheduled(checked);
        if (checked) {
            setTimeout(() => {
                try {
                    if (scheduleInputRef.current) scheduleInputRef.current.showPicker();
                } catch (err) { console.log('showPicker not supported', err); }
            }, 100);
        }
    };

    const handleTemplateSelect = (e) => {
        const id = e.target.value;
        setSelectedTemplateId(id);
        
        // [UX] Auto-fill message content when template is selected
        const template = alimTalkTemplates.find(t => t.id === id);
        if (template && template.content) {
            setMessage(template.content);
        } else if (!id) {
            setMessage('');
        }
    };

    const handleCopyTemplate = () => {
        if (selectedTemplate && selectedTemplate.content) {
            setMessage(selectedTemplate.content);
        }
    };

    return (
        <div style={{
            position: 'fixed', top: 0, left: 0, width: '100%', height: '100%',
            background: 'rgba(0,0,0,0.7)', display: 'flex', justifyContent: 'center', alignItems: 'center',
            zIndex: 1000, backdropFilter: 'blur(5px)'
        }}>
            <div className="fade-in" style={{
                background: '#1d1d2b', width: '90%', maxWidth: '500px',
                borderRadius: '16px', border: '1px solid rgba(255,255,255,0.1)',
                padding: '24px', color: 'white',
                boxShadow: '0 25px 50px -12px rgba(0,0,0,0.5)'
            }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
                    <h3 style={{ margin: 0, color: 'white', display: 'flex', alignItems: 'center', gap: '8px' }}>
                        <PaperPlaneTilt weight="fill" color="var(--primary-gold)" />
                        단체 메시지 전송
                    </h3>
                    <button onClick={onClose} style={{ background: 'none', border: 'none', color: '#a1a1aa', cursor: 'pointer' }}>
                        <X size={24} />
                    </button>
                </div>

                <div style={{ marginBottom: '16px', color: '#e4e4e7', fontSize: '0.95rem' }}>
                    <span style={{ color: 'var(--primary-gold)', fontWeight: 'bold' }}>{memberCount}명</span>의 회원에게 메시지를 보냅니다.
                </div>

                {/* [Solapi] Template Selection */}
                <div style={{ marginBottom: '16px' }}>
                    <label style={{ display: 'block', marginBottom: '6px', fontSize: '0.85rem', color: '#a1a1aa' }}>발송 유형 (알림톡/문자)</label>
                    <select
                        value={selectedTemplateId}
                        onChange={handleTemplateSelect}
                        style={{
                            width: '100%', padding: '10px', borderRadius: '8px',
                            background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.1)',
                            color: 'white', outline: 'none', cursor: 'pointer'
                        }}
                    >
                        {alimTalkTemplates.map(t => (
                            <option key={t.id} value={t.id} style={{ background: '#1d1d2b' }}>
                                {t.name}
                            </option>
                        ))}
                    </select>

                    {/* [NEW] AlimTalk Template Preview */}
                    {selectedTemplateId && selectedTemplate && (
                        <div style={{ 
                            marginTop: '12px', padding: '12px', 
                            background: 'rgba(212, 175, 55, 0.05)', 
                            borderRadius: '8px', border: '1px dashed rgba(212, 175, 55, 0.3)' 
                        }}>
                            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '8px' }}>
                                <div style={{ display: 'flex', alignItems: 'center', gap: '6px', fontSize: '0.75rem', color: 'var(--primary-gold)' }}>
