import { useState, useEffect } from 'react';
import { storageService } from '../../../services/storage';
import { Gear, AppWindow, ShieldCheck, MapPin, Monitor, Trash, Plus, FileText, DeviceMobile, Fingerprint, Browsers, Clock, CheckCircle, Image, ToggleLeft, ToggleRight, Info } from '@phosphor-icons/react';
import { useStudioConfig } from '../../../contexts/StudioContext';

const KioskSettingsTab = () => {
    const { config } = useStudioConfig();
    const branches = config.BRANCHES || [];
    const [settings, setSettings] = useState({ active: false, imageUrl: null });
    const [isUploading, setIsUploading] = useState(false);
    const [previewUrl, setPreviewUrl] = useState(null);

    const [selectedBranch, setSelectedBranch] = useState('all');

    useEffect(() => {
        const loadSettings = async () => {
            const data = await storageService.getKioskSettings(selectedBranch);
            setSettings(data);
            setPreviewUrl(data.imageUrl);
        };
        
        loadSettings();

        // [ROOT SOLUTION] 키오스크 설정 실시간 동기화 구독
        const unsubscribe = storageService.subscribe(() => {
            console.log(`[KioskSettingsTab] Settings updated for branch: ${selectedBranch}, syncing...`);
            loadSettings();
        }, ['settings']);

        return () => unsubscribe();
    }, [selectedBranch]);

    const handleImageUpload = (e) => {
        const file = e.target.files[0];
        if (!file) return;

        if (file.size > 5 * 1024 * 1024) {
            alert('파일 용량이 너무 큽니다. (최대 5MB)');
            return;
        }

        setIsUploading(true);
        const reader = new FileReader();
        reader.onload = (event) => {
            const img = new window.Image();
            img.onload = async () => {
                const canvas = document.createElement('canvas');
                // Use a larger width for full screen display
                const MAX_WIDTH = 1080; 
                let width = img.width;
                let height = img.height;

                if (width > MAX_WIDTH) {
                    height *= MAX_WIDTH / width;
                    width = MAX_WIDTH;
                }

                canvas.width = width;
                canvas.height = height;
                const ctx = canvas.getContext('2d');
                ctx.drawImage(img, 0, 0, width, height);

                // Compress slightly for performance, keeping decent quality for large screens
                const compressedBase64 = canvas.toDataURL('image/jpeg', 0.85);

                setPreviewUrl(compressedBase64);
                
                try {
                    const imageKey = `kiosk_notice_${selectedBranch}`;
                    await storageService.updateImage(imageKey, compressedBase64);
                    // Update settings with the same key reference conceptually, 
                    // though we store the data in images collection to reuse logic
                    await storageService.updateKioskSettings(selectedBranch, { ...settings, imageUrl: compressedBase64 });
                    setSettings(prev => ({ ...prev, imageUrl: compressedBase64 }));
                    alert('이미지가 성공적으로 업로드되었습니다.');
                } catch (err) {
                    console.error('[Admin] Kiosk image upload failed:', err);
                    alert("이미지 업로드에 실패했습니다.");
                    setPreviewUrl(settings.imageUrl); // Revert
                } finally {
                    setIsUploading(false);
                }
            };
            img.src = event.target.result;
        };
        reader.readAsDataURL(file);
    };

    const handleToggleActive = async () => {
        const newActive = !settings.active;
        try {
            await storageService.updateKioskSettings(selectedBranch, { ...settings, active: newActive });
            setSettings(prev => ({ ...prev, active: newActive }));
        } catch (err) {
            alert('설정 변경에 실패했습니다.');
        }
    };

    const handleRemoveImage = async () => {
        if (!window.confirm('이미지를 삭제하시겠습니까?')) return;
        try {
            await storageService.updateKioskSettings(selectedBranch, { ...settings, imageUrl: null, active: false });
            setSettings({ active: false, imageUrl: null });
            setPreviewUrl(null);
        } catch (err) {
            alert('이미지 삭제에 실패했습니다.');
        }
    };


    return (
        <div className="dashboard-card" style={{ maxWidth: '800px', margin: '0 auto' }}>
            <h3 className="card-label" style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '20px' }}>
                <Image size={24} weight="fill" color="var(--primary-gold)" />
                키오스크 화면 설정
            </h3>
            
            <div style={{ padding: '16px', background: 'rgba(212, 175, 55, 0.05)', borderRadius: '12px', border: '1px solid rgba(212, 175, 55, 0.2)', marginBottom: '24px', display: 'flex', gap: '12px', alignItems: 'flex-start' }}>
                <Info size={20} color="var(--primary-gold)" style={{ flexShrink: 0, marginTop: '2px' }} />
                <div style={{ fontSize: '0.9rem', color: 'var(--text-secondary)', lineHeight: '1.5' }}>
                    <p style={{ margin: '0 0 8px 0', color: 'var(--text-primary)', fontWeight: 'bold' }}>키오스크 공지 기능 안내</p>
                    이곳에서 이미지를 업로드하고 활성화하면, 출석체크 태블릿(키오스크) 화면 전체에 해당 이미지가 표시됩니다. 지점별로 설정하거나 전체 공통으로 설정할 수 있습니다.
                </div>
            </div>

            {/* Branch Selector */}
            <div style={{ display: 'flex', gap: '8px', marginBottom: '24px' }}>
                {[
                    { id: 'all', label: '전체' },
                    ...branches.map(b => ({ id: b.id, label: b.name.replace('점', '') }))
                ].map(branch => (
                    <button
                        key={branch.id}
                        onClick={() => setSelectedBranch(branch.id)}
                        style={{
                            flex: 1,
                            padding: '12px',
                            background: selectedBranch === branch.id ? 'var(--primary-gold)' : 'rgba(255,255,255,0.05)',
                            color: selectedBranch === branch.id ? 'black' : 'var(--text-secondary)',
                            border: `1px solid ${selectedBranch === branch.id ? 'var(--primary-gold)' : 'var(--border-color)'}`,
                            borderRadius: '8px',
                            fontWeight: selectedBranch === branch.id ? 'bold' : 'normal',
                            cursor: 'pointer',
                            transition: 'all 0.2s'
                        }}
                    >
                        {branch.label}
                    </button>
                ))}
            </div>

            <div style={{ display: 'flex', flexDirection: 'column', gap: '24px' }}>
                {/* 1. Image Upload Section */}
                <div style={{ background: 'rgba(255,255,255,0.02)', padding: '24px', borderRadius: '16px', border: '1px solid var(--border-color)' }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '16px' }}>
                        <h4 style={{ margin: 0, fontSize: '1.1rem' }}>화면 이미지</h4>
                        <div style={{ display: 'flex', gap: '10px' }}>
                            {previewUrl && (
                                <button
                                    onClick={handleRemoveImage}
                                    className="action-btn sm"
                                    style={{ background: 'rgba(244, 63, 94, 0.1)', color: '#F43F5E', border: '1px solid rgba(244, 63, 94, 0.3)' }}
                                >
                                    삭제
                                </button>
                            )}
                            <input type="file" accept="image/*" onChange={handleImageUpload} style={{ display: 'none' }} id="upload-kiosk-notice" disabled={isUploading} />
                            <label 
                                htmlFor="upload-kiosk-notice" 
                                className="action-btn sm" 
                                style={{ 
                                    background: 'var(--primary-gold)', 
                                    color: 'black', 
                                    cursor: isUploading ? 'not-allowed' : 'pointer',
                                    opacity: isUploading ? 0.7 : 1,
                                    fontWeight: 'bold'
                                }}
                            >
                                {isUploading ? '업로드 중...' : (previewUrl ? '이미지 변경' : '이미지 업로드')}
                            </label>
                        </div>
                    </div>

                    <div style={{ 
                        background: 'rgba(0,0,0,0.3)', 
                        borderRadius: '12px', 
                        minHeight: '300px', 
                        display: 'flex', 
                        alignItems: 'center', 
                        justifyContent: 'center', 
                        border: '1px dashed rgba(255,255,255,0.1)',
                        overflow: 'hidden',
                        position: 'relative'
                    }}>
                        {previewUrl ? (
                            <img src={previewUrl} alt="키오스크 공지" style={{ width: '100%', height: 'auto', maxHeight: '500px', objectFit: 'contain' }} />
                        ) : (
                            <div style={{ color: 'var(--text-tertiary)', textAlign: 'center' }}>
                                <Image size={48} weight="light" style={{ marginBottom: '8px', opacity: 0.5 }} />
                                <div>등록된 이미지가 없습니다</div>
                            </div>
                        )}
                        {isUploading && (
                            <div style={{
                                position: 'absolute', inset: 0,
                                background: 'rgba(0,0,0,0.5)',
                                display: 'flex', alignItems: 'center', justifyContent: 'center',
                                color: 'white', fontWeight: 'bold'
                            }}>
                                처리 중...
                            </div>
                        )}
                    </div>
                </div>

                {/* 2. Toggle Section */}
                <div style={{ 
                    background: 'rgba(255,255,255,0.02)', 
                    padding: '24px', 
                    borderRadius: '16px', 
                    border: '1px solid var(--border-color)',
                    display: 'flex',
                    justifyContent: 'space-between',
                    alignItems: 'center',
                    opacity: previewUrl ? 1 : 0.5,
                    pointerEvents: previewUrl ? 'auto' : 'none'
                }}>
                    <div>
                        <h4 style={{ margin: '0 0 4px 0', fontSize: '1.2rem', color: settings.active ? '#10B981' : 'var(--text-primary)' }}>
                            {settings.active ? '출석기에 표시 중' : '출석기에 미표시'}
                        </h4>
                        <p style={{ margin: 0, fontSize: '0.85rem', color: 'var(--text-secondary)' }}>
                            활성화하면 태블릿 화면에 다른 내용 대신 이 이미지가 우선 표시됩니다. (터치하면 닫힘)
                        </p>
                    </div>
                    <button 
                        onClick={handleToggleActive}
                        style={{
                            background: 'none', border: 'none', cursor: 'pointer',
                            color: settings.active ? '#10B981' : 'var(--text-tertiary)',
                            padding: 0, display: 'flex'
                        }}
                        disabled={!previewUrl}
                    >
                        {settings.active ? 
                            <ToggleRight size={56} weight="fill" /> : 
                            <ToggleLeft size={56} weight="regular" />
                        }
                    </button>
                </div>
            </div>
        </div>
    );
};

export default KioskSettingsTab;

import React, { useState, useMemo, useEffect, useCallback } from 'react';
import { ClockCounterClockwise, Trash, Sparkle, CaretLeft, CaretRight, CalendarBlank, TrendUp, UserFocus } from '@phosphor-icons/react';
import { ResponsiveContainer, LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, LabelList } from 'recharts';
import { guessClassTime, guessClassInfo } from '../../../utils/classUtils';
import { storageService } from '../../../services/storage';
import { useStudioConfig } from '../../../contexts/StudioContext';
import ImageLightbox from '../../common/ImageLightbox';

// ─── Mini Calendar Popup ───
const MiniCalendar = ({ selectedDate, onSelect, onClose, config }) => {
    const themeColor = config?.THEME?.PRIMARY_COLOR || '#D4AF37';
    const sel = new Date(selectedDate + 'T00:00:00+09:00');
    const [viewYear, setViewYear] = useState(sel.getFullYear());
    const [viewMonth, setViewMonth] = useState(sel.getMonth());

    const todayStr = new Date().toLocaleDateString('sv-SE', { timeZone: 'Asia/Seoul' });
    const daysInMonth = new Date(viewYear, viewMonth + 1, 0).getDate();
    const startDay = new Date(viewYear, viewMonth, 1).getDay();
    const dayNames = ['일', '월', '화', '수', '목', '금', '토'];

    const dates = [];
    for (let i = 0; i < startDay; i++) dates.push(null);
    for (let i = 1; i <= daysInMonth; i++) dates.push(i);

    const handleSelect = (day) => {
        if (!day) return;
        const dateStr = `${viewYear}-${String(viewMonth + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
        // 미래 날짜 차단
        if (dateStr > todayStr) return;
        onSelect(dateStr);
        onClose();
    };

    const prevMonth = () => {
        if (viewMonth === 0) { setViewYear(y => y - 1); setViewMonth(11); }
        else setViewMonth(m => m - 1);
    };
    const nextMonth = () => {
        if (viewMonth === 11) { setViewYear(y => y + 1); setViewMonth(0); }
        else setViewMonth(m => m + 1);
    };

    return (
        <div style={{ position: 'absolute', top: '100%', left: '50%', transform: 'translateX(-50%)', zIndex: 100, marginTop: '8px' }}>
            {/* Backdrop */}
            <div style={{ position: 'fixed', top: 0, left: 0, right: 0, bottom: 0, zIndex: -1 }} onClick={onClose} />
            <div style={{
                background: 'var(--bg-surface, #1a1a2e)',
                border: '1px solid rgba(212,175,55,0.3)',
                borderRadius: '12px',
                padding: '16px',
                boxShadow: '0 8px 32px rgba(0,0,0,0.5)',
                minWidth: '280px'
            }}>
                {/* Header */}
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '12px' }}>
                    <button onClick={prevMonth} style={calNavBtn}><CaretLeft size={14} /></button>
                    <span style={{ fontWeight: 'bold', fontSize: '0.95rem' }}>{viewYear}년 {viewMonth + 1}월</span>
                    <button onClick={nextMonth} style={calNavBtn}><CaretRight size={14} /></button>
                </div>
                {/* Day names */}
                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', gap: '2px', marginBottom: '4px' }}>
                    {dayNames.map(d => (
                        <div key={d} style={{ textAlign: 'center', fontSize: '0.7rem', color: 'var(--text-secondary)', padding: '4px', fontWeight: 'bold' }}>{d}</div>
                    ))}
                </div>
                {/* Dates */}
                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', gap: '2px' }}>
                    {dates.map((day, i) => {
                        if (!day) return <div key={`e-${i}`} />;
                        const dateStr = `${viewYear}-${String(viewMonth + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
                        const isSelected = dateStr === selectedDate;
                        const isToday = dateStr === todayStr;
                        const isFuture = dateStr > todayStr;
                        const isSunday = new Date(viewYear, viewMonth, day).getDay() === 0;
                        return (
                            <button
                                key={day}
                                onClick={() => handleSelect(day)}
                                disabled={isFuture}
                                style={{
                                    width: '36px', height: '36px',
                                    borderRadius: '50%',
                                    border: isToday ? '2px solid var(--primary-gold)' : 'none',
                                    background: isSelected ? 'var(--primary-gold)' : 'transparent',
                                    color: isSelected ? 'black' : isFuture ? 'rgba(255,255,255,0.15)' : isSunday ? '#ff6b6b' : 'var(--text-primary)',
                                    fontWeight: isSelected || isToday ? 'bold' : 'normal',
                                    fontSize: '0.85rem',
                                    cursor: isFuture ? 'not-allowed' : 'pointer',
                                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                                    transition: 'all 0.15s ease',
                                    margin: '0 auto'
                                }}
                                onMouseEnter={e => { if (!isFuture && !isSelected) e.currentTarget.style.background = 'rgba(212,175,55,0.15)'; }}
                                onMouseLeave={e => { if (!isFuture && !isSelected) e.currentTarget.style.background = 'transparent'; }}
                            >
                                {day}
                            </button>
                        );
                    })}
                </div>
                {/* Today shortcut */}
                <button
                    onClick={() => { onSelect(todayStr); onClose(); }}
                    style={{
                        marginTop: '10px', width: '100%', padding: '6px',
                        background: `${themeColor}20`, border: `1px solid ${themeColor}40`,
                        borderRadius: '6px', color: themeColor, fontWeight: 'bold',
                        fontSize: '0.8rem', cursor: 'pointer'
                    }}
                >오늘로 이동</button>
            </div>
        </div>
    );
};

const calNavBtn = {
    background: 'none', border: '1px solid rgba(255,255,255,0.1)', borderRadius: '50%',
    width: '28px', height: '28px', display: 'flex', alignItems: 'center', justifyContent: 'center',
    cursor: 'pointer', color: 'var(--text-primary)'
};

// ─── Main Component ───
const LogsTab = ({ todayClasses, logs, currentLogPage, setCurrentLogPage, members = [], onMemberClick, summary }) => {
    const { config } = useStudioConfig();
    const branches = config.BRANCHES || [];
    const getBranchName = (id) => branches.find(b => b.id === id)?.name || id;
    const getBranchColor = (id) => branches.find(b => b.id === id)?.color || 'var(--primary-gold)';
    const getBranchThemeColor = (id) => branches.find(b => b.id === id)?.color || 'var(--primary-gold)';

    const todayStr = new Date().toLocaleDateString('sv-SE', { timeZone: 'Asia/Seoul' });
    const [selectedDate, setSelectedDate] = useState(todayStr);
    const [selectedClassKey, setSelectedClassKey] = useState(null);
    const [showCalendar, setShowCalendar] = useState(false);
    const [historicalLogs, setHistoricalLogs] = useState([]);
    const [loadingHistorical, setLoadingHistorical] = useState(false);
    const [lightboxImage, setLightboxImage] = useState(null);
    const [searchTerm, setSearchTerm] = useState('');
    const [localBranch, setLocalBranch] = useState('all');

    const isToday = selectedDate === todayStr;

    // 과거 날짜 선택 시 Firestore에서 데이터 가져오기
    const fetchHistoricalData = useCallback(async (dateStr) => {
        if (dateStr === todayStr) return;
        setLoadingHistorical(true);
        try {
            const data = await storageService.getAttendanceByDate(dateStr);
            setHistoricalLogs(data);
        } catch (e) {
            console.error('[LogsTab] Failed to fetch historical data:', e);
            setHistoricalLogs([]);
        } finally {
            setLoadingHistorical(false);
        }
    }, [todayStr]);

    useEffect(() => {
        if (!isToday) {
            fetchHistoricalData(selectedDate);
        }
        setSelectedClassKey(null);
        setCurrentLogPage(1);
    }, [selectedDate, isToday, fetchHistoricalData, setCurrentLogPage]);

    useEffect(() => {
        setCurrentLogPage(1);
    }, [searchTerm, localBranch, setCurrentLogPage]);

    const [trendData, setTrendData] = useState(null);
    const [loadingTrend, setLoadingTrend] = useState(false);

    // [NEW] Fetch past 30 days data for the selected class
    useEffect(() => {
        if (!selectedClassKey) {
            setTrendData(null);
            return;
        }

        const [tName, tInst, tBranch, tTime] = selectedClassKey.split('-');
        let isMounted = true;

        const loadTrend = async () => {
            setLoadingTrend(true);
            try {
                // Determine past 21 days (3 weeks)
                const datesToFetch = [];
                const d = new Date(selectedDate + 'T00:00:00+09:00');
                
                // Start from the currently selected date, and go backwards 21 days
                for (let i = 0; i < 21; i++) {
                    const temp = new Date(d);
                    temp.setDate(temp.getDate() - i);
                    datesToFetch.push(temp.toLocaleDateString('sv-SE', { timeZone: 'Asia/Seoul' }));
                }

                // Fetch all dates in parallel
                const results = await Promise.all(datesToFetch.map(dateStr => 
                    storageService.getAttendanceByDate(dateStr, tBranch)
                ));

                const chartDataMap = {};
                
                // Initialize map with empty counts to maintain timeline gaps
                datesToFetch.forEach(dateStr => {
                    const md = dateStr.slice(5); // "MM-DD"
                    // Only plotting days where checking actually found the class, 
                    // or keeping zeros? Let's keep zeros only if the class was actually scheduled.
                    // simpler approach: just find instances of the class.
                });

                const rawPlotData = [];

                results.forEach((dayLogs, idx) => {
                    const targetDateStr = datesToFetch[idx];
                    let count = 0;
                    
                    dayLogs.forEach(log => {
                        const info = guessClassInfo(log, config.DEFAULT_SCHEDULE_TEMPLATE);
                        const cName = info?.className || log.className || '일반';
                        const cInst = info?.instructor || log.instructor || '선생님';
                        const cTime = info?.startTime || '00:00';
                        
                        if (log.status !== 'denied' && cName === tName && cInst === tInst && cTime === tTime) {
                            count++;
                        }
                    });

                    // Only add to chart if count > 0, to avoid connecting empty dots 
                    // for days the class doesn't run.
                    if (count > 0 || idx === 0 /* Always show current selected date */) {
                        const dObj = new Date(targetDateStr + 'T00:00:00+09:00');
                        rawPlotData.push({
                            date: targetDateStr.slice(5).replace('-', '/'), // "MM/DD"
                            fullDate: targetDateStr,
                            timestamp: dObj.getTime(),
                            count: count,
                            dayName: ['일', '월', '화', '수', '목', '금', '토'][dObj.getDay()]
                        });
                    }
                });

                // Sort chronologically (oldest first)
                rawPlotData.sort((a, b) => a.timestamp - b.timestamp);

                if (isMounted) {
                    setTrendData(rawPlotData);
                }
            } catch (err) {
                console.error("[LogsTab] Failed to fetch trend data:", err);
            } finally {
                if (isMounted) setLoadingTrend(false);
            }
        };

        loadTrend();

        return () => { isMounted = false; };
    }, [selectedClassKey, selectedDate]);

    // 현재 표시할 로그 결정
    const activeLogs = (() => {
        if (isToday) {
            return logs.filter(l => {
                // [FIX] Use stored 'date' field first for robustness (avoids client locale/timezone issues)
                if (l.date) return l.date === todayStr;
                
                // Fallback: Parse timestamp if date field is missing (legacy)
                if (!l.timestamp) return false;
                const logDate = new Date(l.timestamp).toLocaleDateString('sv-SE', { timeZone: 'Asia/Seoul' });
                return logDate === todayStr;
            });
        }
        return historicalLogs;
    })();

    // 수업별 요약 카드 생성 (오늘은 todayClasses prop, 과거는 활성 로그에서 집계)
    const classCards = (() => {
        if (isToday) return todayClasses;
        const groups = {};

        activeLogs.forEach(log => {
            const info = guessClassInfo(log, config.DEFAULT_SCHEDULE_TEMPLATE);
            const classTime = info?.startTime || '00:00';
            const canonicalClassName = info?.className || log.className || '일반';
            const canonicalInstructor = info?.instructor || log.instructor || '선생님';

            const key = `${canonicalClassName}-${canonicalInstructor}-${log.branchId}-${classTime}`;
            
            if (!groups[key]) {
                groups[key] = {
                    className: canonicalClassName,
                    instructor: canonicalInstructor,
                    branchId: log.branchId,
                    classTime: classTime,
                    count: 0,
                    deniedCount: 0,
                    memberNames: [] 
                };
            }
            if (log.status === 'denied') groups[key].deniedCount++;
            else {
                groups[key].count++;
                // If it's a historical log, we might not have easy access to multiAttendedMemberIds here,
                // but we can at least show those tagged as multi-session in the log itself.
                if (log.memberName && (log.sessionCount > 1 || log.isMultiSession)) {
                    if (!groups[key].memberNames.includes(log.memberName)) {
                        groups[key].memberNames.push(log.memberName);
                    }
                }
            }
        });
        
        // [UX] Sort by classTime Descending (Latest First)
        return Object.values(groups).sort((a, b) => {
            if (!a.classTime) return 1;
            if (!b.classTime) return -1;
            return b.classTime.localeCompare(a.classTime);
        });
    })();

    const handleClassClick = (cls) => {
        const key = `${cls.className}-${cls.instructor}-${cls.branchId}-${cls.classTime || 'no-time'}`;
        // [UX] Toggle selection: if already selected, deselect (show all)
        setSelectedClassKey(prev => prev === key ? null : key);
        setCurrentLogPage(1);
    };

    const handleDateChange = (dateStr) => {
        setSelectedDate(dateStr);
    };

    const handlePrevDay = () => {
        const d = new Date(selectedDate + 'T00:00:00+09:00');
        d.setDate(d.getDate() - 1);
        setSelectedDate(d.toLocaleDateString('sv-SE', { timeZone: 'Asia/Seoul' }));
    };

    const handleNextDay = () => {
        const d = new Date(selectedDate + 'T00:00:00+09:00');
        d.setDate(d.getDate() + 1);
        const nextStr = d.toLocaleDateString('sv-SE', { timeZone: 'Asia/Seoul' });
        if (nextStr <= todayStr) setSelectedDate(nextStr);
    };

    // 날짜 포맷: "2월 16일 (일)"
    const formatDisplayDate = (dateStr) => {
        const d = new Date(dateStr + 'T00:00:00+09:00');
        const m = d.getMonth() + 1;
        const day = d.getDate();
        const dayName = ['일', '월', '화', '수', '목', '금', '토'][d.getDay()];
        return `${m}월 ${day}일 (${dayName})`;
    };

    // [UI] Custom Tooltip for Chart
    const CustomTooltip = ({ active, payload, label }) => {
        if (active && payload && payload.length) {
            const data = payload[0].payload;
            return (
                <div style={{
                    background: 'rgba(20,20,30,0.95)',
                    border: '1px solid rgba(212,175,55,0.3)',
                    padding: '8px 12px',
                    borderRadius: '8px',
                    color: 'white',
                    fontSize: '0.85rem'
                }}>
                    <div style={{ color: 'var(--text-secondary)', marginBottom: '4px' }}>
                        {data.fullDate} ({data.dayName})
                    </div>
                    <div style={{ color: 'var(--primary-gold)', fontWeight: 'bold', fontSize: '1rem' }}>
                        출석: {payload[0].value}명
                    </div>
                </div>
            );
        }
        return null;
    };

    return (
        <>
        <div style={{ display: 'flex', flexDirection: 'column', gap: '24px' }}>
            {/* ─── Date Navigation ─── */}
            <div style={{
                display: 'flex', justifyContent: 'center', alignItems: 'center', gap: '12px',
                padding: '12px 0', position: 'relative'
            }}>
                <button onClick={handlePrevDay} style={dateNavBtn}><CaretLeft size={18} weight="bold" /></button>
                <button
                    onClick={() => setShowCalendar(v => !v)}
                    style={{
                        background: isToday ? 'rgba(212,175,55,0.1)' : 'rgba(255,255,255,0.05)',
                        border: isToday ? '1px solid rgba(212,175,55,0.3)' : '1px solid rgba(255,255,255,0.1)',
                        borderRadius: '10px',
                        padding: '8px 20px',
                        color: isToday ? 'var(--primary-gold)' : 'var(--text-primary)',
                        fontWeight: 'bold',
                        fontSize: '1rem',
                        cursor: 'pointer',
                        display: 'flex', alignItems: 'center', gap: '8px',
                        transition: 'all 0.2s ease'
                    }}
                >
                    <CalendarBlank size={18} />
                    {formatDisplayDate(selectedDate)}
                    {isToday && <span style={{ fontSize: '0.7rem', background: 'var(--primary-gold)', color: 'black', padding: '2px 6px', borderRadius: '4px', fontWeight: 'bold' }}>오늘</span>}
                </button>
                <button
                    onClick={handleNextDay}
                    disabled={selectedDate >= todayStr}
                    style={{ ...dateNavBtn, opacity: selectedDate >= todayStr ? 0.3 : 1, cursor: selectedDate >= todayStr ? 'not-allowed' : 'pointer' }}
                ><CaretRight size={18} weight="bold" /></button>

                {!isToday && (
                    <button
                        onClick={() => setSelectedDate(todayStr)}
                        style={{
                            background: 'var(--primary-gold)', color: 'black', border: 'none',
                            padding: '6px 14px', borderRadius: '8px', fontWeight: 'bold',
                            fontSize: '0.8rem', cursor: 'pointer',
                            boxShadow: '0 2px 8px rgba(212,175,55,0.3)'
                        }}
                    >오늘</button>
                )}

                {showCalendar && (
                    <MiniCalendar
                        selectedDate={selectedDate}
                        onSelect={handleDateChange}
                        onClose={() => setShowCalendar(false)}
                        config={config}
                    />
                )}
            </div>

            {/* ─── Summary Section (Facial Data) ─── */}
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '15px' }}>
                <div className="dashboard-card" style={{ border: '1px solid rgba(59, 130, 246, 0.3)', background: 'rgba(59, 130, 246, 0.05)', padding: '16px' }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px' }}>
                        <UserFocus size={20} weight="fill" color="#60A5FA" />
                        <span style={{ fontSize: '0.9rem', fontWeight: 'bold' }}>안면 데이터 수집 현황</span>
                    </div>
                    <div style={{ display: 'flex', alignItems: 'baseline', gap: '6px' }}>
                        <span style={{ fontSize: '1.5rem', fontWeight: '800', color: 'var(--primary-gold)' }}>{summary?.facialDataCount || 0}</span>
                        <span style={{ fontSize: '0.9rem', opacity: 0.6 }}>명 수집됨</span>
                        <span style={{ marginLeft: 'auto', fontSize: '1rem', fontWeight: 'bold', color: '#60A5FA' }}>{summary?.facialDataRatio || 0}%</span>
                    </div>
                    <div style={{ marginTop: '8px', height: '4px', background: 'rgba(255,255,255,0.05)', borderRadius: '2px', overflow: 'hidden' }}>
                        <div style={{ width: `${summary?.facialDataRatio || 0}%`, height: '100%', background: '#60A5FA', transition: 'width 0.5s ease-out' }} />
                    </div>
                    <p style={{ fontSize: '0.7rem', color: 'var(--text-secondary)', marginTop: '8px', margin: '8px 0 0 0' }}>
                        * 활성 회원 대비 안면 데이터가 등록된 비중입니다.
                    </p>
                </div>
                {/* Additional summary cards can be added here if needed */}
                <div className="dashboard-card" style={{ padding: '16px', background: 'rgba(255,255,255,0.02)' }}>
                    <div className="card-label" style={{ fontSize: '0.85rem', marginBottom: '8px' }}>오늘 총 출석</div>
                    <div style={{ display: 'flex', alignItems: 'baseline', gap: '6px' }}>
                        <span style={{ fontSize: '1.5rem', fontWeight: '800' }}>{activeLogs.length}</span>
                        <span style={{ fontSize: '0.9rem', opacity: 0.6 }}>건</span>
                    </div>
                </div>
            </div>

            {/* ─── Loading State ─── */}
            {loadingHistorical && (
                <div style={{ textAlign: 'center', padding: '30px', color: 'var(--text-secondary)' }}>
                    <div style={{
                        width: '32px', height: '32px', border: '3px solid rgba(212,175,55,0.2)',
                        borderTop: '3px solid var(--primary-gold)', borderRadius: '50%',
                        animation: 'spin 0.8s linear infinite', margin: '0 auto 12px'
                    }} />
                    출석 데이터를 불러오는 중...
                    <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
                </div>
            )}

            {/* ─── Class Summary Cards ─── */}
            {!loadingHistorical && classCards.length > 0 && (
                <div className="dashboard-card" style={{ border: '1px solid rgba(212,175,55,0.2)' }}>
                    <h3 className="card-label" style={{ marginBottom: '15px', color: 'var(--primary-gold)', display: 'flex', alignItems: 'center', gap: '8px' }}>
                        <ClockCounterClockwise size={18} /> {isToday ? '오늘' : formatDisplayDate(selectedDate)} 수업별 출석 요약
                    </h3>
                    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '12px' }}>
                        {classCards.map((cls, idx) => {
                            const key = `${cls.className}-${cls.instructor}-${cls.branchId}-${cls.classTime || 'no-time'}`;
                            const isSelected = selectedClassKey === key;
                            return (
                                <div
                                    key={key}
                                    onClick={() => handleClassClick(cls)}
                                    style={{
                                        padding: '12px',
                                        borderRadius: '10px',
                                        background: isSelected ? 'rgba(212,175,55,0.1)' : 'rgba(255,255,255,0.03)',
                                        border: isSelected ? '1px solid var(--primary-gold)' : '1px solid rgba(255,255,255,0.05)',
                                        position: 'relative',
                                        cursor: 'pointer',
                                        transition: 'all 0.2s ease',
                                        boxShadow: isSelected ? '0 0 15px rgba(212,175,55,0.2)' : 'none'
                                    }}
                                >
                                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '4px' }}>
                                        <div style={{ display: 'flex', flexDirection: 'column', gap: '2px' }}>
                                            {cls.classTime && (
                                                <div style={{ fontSize: '0.75rem', color: 'var(--primary-gold)', fontWeight: 'bold' }}>
                                                    {cls.classTime}
                                                </div>
                                            )}
                                            <div style={{ fontSize: '0.9rem', fontWeight: 'bold', color: isSelected ? 'var(--primary-gold)' : 'inherit' }}>{cls.className}</div>
                                        </div>
                                        <span style={{
                                            fontSize: '0.65rem', padding: '2px 6px', borderRadius: '4px',
                                            background: `${getBranchColor(cls.branchId)}20`,
                                            color: getBranchThemeColor(cls.branchId),
                                            fontWeight: 'bold', border: `1px solid ${getBranchColor(cls.branchId)}33`
                                        }}>
                                            {getBranchName(cls.branchId)}
                                        </span>
                                    </div>
                                    <div style={{ fontSize: '0.75rem', opacity: 0.6, marginBottom: '8px' }}>{cls.instructor} 선생님</div>
                                    <div style={{ display: 'flex', alignItems: 'flex-end', gap: '4px' }}>
                                        <span style={{ fontSize: '1.4rem', fontWeight: '800', color: 'var(--primary-gold)', lineHeight: 1 }}>{cls.count}</span>
                                        <span style={{ fontSize: '0.8rem', opacity: 0.5 }}>명 참여</span>
                                        {cls.deniedCount > 0 && (
                                            <span style={{
                                                fontSize: '0.7rem', color: '#ff4d4f', background: 'rgba(255, 77, 79, 0.1)',
                                                padding: '2px 6px', borderRadius: '4px', border: '1px solid rgba(255, 77, 79, 0.2)',
                                                fontWeight: 'bold', marginLeft: '6px'
                                            }}>
                                                ⛔ 거부 {cls.deniedCount}명
                                            </span>
                                        )}
                                    </div>
                                    {/* [NEW] Show multi-attendance member names */}
                                    {cls.memberNames?.length > 0 && (
                                        <div style={{ marginTop: '8px', paddingTop: '8px', borderTop: '1px solid rgba(255,255,255,0.05)', display: 'flex', flexWrap: 'wrap', gap: '6px' }}>
                                            {cls.memberNames.map(name => (
                                                <span key={name} style={{
                                                    fontSize: '0.8rem', 
                                                    color: 'var(--primary-gold)', // Just color change requested
                                                    fontWeight: 'bold'
                                                }}>
                                                    {name}
                                                </span>
                                            ))}
                                        </div>
                                    )}
                                    {/* [UX] Removed "Filtering..." text as requested */}
                                </div>
                            );
                        })}
                    </div>
                    
                    {/* [NEW] Class Attendance Trend Chart */}
                    {selectedClassKey && (
                        <div style={{ 
                            marginTop: '20px', 
                            paddingTop: '20px', 
                            borderTop: '1px solid rgba(212, 175, 55, 0.2)',
                            animation: 'fadeInDown 0.3s ease-out'
                        }}>
                            <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '16px' }}>
                                <TrendUp size={18} color="var(--primary-gold)" />
                                <h4 style={{ margin: 0, fontSize: '0.95rem', color: 'var(--text-primary)' }}>해당 수업 과거 출석 추세 (최근 3주)</h4>
                            </div>
                            
                            {loadingTrend ? (
                                <div style={{ height: '200px', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--text-secondary)' }}>
                                    데이터 분석 중...
                                </div>
                            ) : trendData && trendData.length > 0 ? (
                                <div style={{ width: '100%', height: '200px' }}>
                                    <ResponsiveContainer width="100%" height="100%">
                                        <LineChart
                                            data={trendData}
                                            margin={{ top: 20, right: 20, left: -20, bottom: 0 }}
                                        >
                                            <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.05)" vertical={false} />
                                            <XAxis 
                                                dataKey="date" 
                                                stroke="rgba(255,255,255,0.3)" 
                                                fontSize={12} 
                                                tickMargin={10}
                                                tickFormatter={(value, idx) => {
                                                    // Only show first, last, and middle ticks if many data points to avoid clutter
                                                    if (trendData.length > 10 && idx !== 0 && idx !== trendData.length - 1 && idx !== Math.floor(trendData.length / 2)) {
                                                        return '';
                                                    }
                                                    return value;
                                                }}
                                            />
                                            <YAxis 
                                                stroke="rgba(255,255,255,0.3)" 
                                                fontSize={12} 
                                                allowDecimals={false}
                                                domain={[0, 'dataMax + 2']}
                                            />
                                            <Tooltip content={<CustomTooltip />} cursor={{ stroke: 'rgba(212,175,55,0.2)', strokeWidth: 2 }} />
                                            <Line 
                                                type="monotone" 
                                                dataKey="count" 
                                                stroke="var(--primary-gold)" 
                                                strokeWidth={3}
                                                activeDot={{ r: 6, fill: '#fff', stroke: 'var(--primary-gold)', strokeWidth: 2 }}
                                                animationDuration={1000}
                                            >
                                                <LabelList dataKey="count" position="top" fill="rgba(255,255,255,0.8)" fontSize={11} offset={8} />
                                            </Line>
                                        </LineChart>
                                    </ResponsiveContainer>
                                </div>
                            ) : (
                                <div style={{ height: '100px', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--text-secondary)', fontSize: '0.85rem' }}>
                                    최근 3주 내에 동일한 시간대의 수업 기록이 없습니다.
                                </div>
                            )}
                        </div>
                    )}
                </div>
            )}

            {/* ─── Empty State ─── */}
            {!loadingHistorical && classCards.length === 0 && activeLogs.length === 0 && (
                <div className="dashboard-card" style={{ textAlign: 'center', padding: '40px 20px', color: 'var(--text-secondary)' }}>
                    <CalendarBlank size={48} style={{ opacity: 0.3, marginBottom: '12px' }} />
                    <div style={{ fontSize: '1rem', fontWeight: 'bold', marginBottom: '6px' }}>
                        {formatDisplayDate(selectedDate)}에 출석 기록이 없습니다.
                    </div>
                    <div style={{ fontSize: '0.85rem', opacity: 0.6 }}>
                        다른 날짜를 선택해보세요.
                    </div>
                </div>
            )}

            {/* ─── Activity Log List ─── */}
            {!loadingHistorical && (
                <div className="dashboard-card">
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '15px', flexWrap: 'wrap', gap: '10px' }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '8px', flex: 1 }}>
                            <h3 className="card-label" style={{ margin: 0, whiteSpace: 'nowrap' }}>
                                {isToday ? '오늘 활동 로그' : `${formatDisplayDate(selectedDate)} 활동 로그`}
                            </h3>
                            <span style={{ fontSize: '0.75rem', color: 'var(--text-secondary)', background: 'rgba(255,255,255,0.05)', padding: '2px 8px', borderRadius: '4px' }}>
                                {activeLogs.length}건
                            </span>
                        </div>

                        <div style={{ display: 'flex', gap: '10px', alignItems: 'center' }}>
                            {selectedClassKey && (
                                <button
                                    onClick={() => setSelectedClassKey(null)}
                                    style={{
                                        background: 'var(--primary-gold)', color: 'black', border: 'none',
                                        padding: '4px 10px', borderRadius: '6px', fontSize: '0.75rem',
                                        fontWeight: 'bold', cursor: 'pointer',
                                        display: 'flex', alignItems: 'center', gap: '4px', whiteSpace: 'nowrap'
                                    }}
                                >
                                    <ClockCounterClockwise size={14} /> 필터 해제
                                </button>
                            )}
                            
                            {/* Branch Filter */}
                            <select 
                                value={localBranch}
                                onChange={(e) => setLocalBranch(e.target.value)}
                                style={{
                                    background: 'rgba(255,255,255,0.05)',
                                    border: '1px solid rgba(255,255,255,0.1)',
                                    borderRadius: '6px',
                                    padding: '4px 8px',
                                    color: 'var(--text-primary)',
                                    fontSize: '0.8rem',
                                    outline: 'none',
                                    cursor: 'pointer'
                                }}
                            >
                                <option value="all">전체 지점</option>
                                {(config.BRANCHES || []).map(b => (
                                    <option key={b.id} value={b.id}>{b.name}</option>
                                ))}
                            </select>

                            {/* Name Search */}
                            <div style={{ position: 'relative' }}>
                                <input 
                                    type="text"
                                    placeholder="이름 검색..."
                                    value={searchTerm}
                                    onChange={(e) => setSearchTerm(e.target.value)}
                                    style={{
                                        background: 'rgba(255,255,255,0.05)',
                                        border: '1px solid rgba(255,255,255,0.1)',
                                        borderRadius: '6px',
                                        padding: '4px 8px',
                                        paddingRight: '25px',
                                        color: 'var(--text-primary)',
                                        fontSize: '0.8rem',
                                        width: '120px',
                                        outline: 'none'
                                    }}
                                />
                                {searchTerm && (
                                    <button 
                                        onClick={() => setSearchTerm('')}
                                        style={{ position: 'absolute', right: '5px', top: '50%', transform: 'translateY(-50%)', background: 'none', border: 'none', color: '#71717a', cursor: 'pointer', fontSize: '1rem', display: 'flex', alignItems: 'center' }}
                                    >×</button>
                                )}
                            </div>
                        </div>

                    </div>
                    <div style={{ marginTop: '10px' }}>
                        {(() => {
                            const filteredLogs = (selectedClassKey
                                ? activeLogs.filter(l => {
                                    const info = guessClassInfo(l, config.DEFAULT_SCHEDULE_TEMPLATE);
                                    const classTime = info?.startTime || '00:00';
                                    const canonicalClassName = info?.className || l.className || '일반';
                                    const canonicalInstructor = info?.instructor || l.instructor || '선생님';
                                    return `${canonicalClassName}-${canonicalInstructor}-${l.branchId}-${classTime}` === selectedClassKey;
                                })
                                : activeLogs
                            ).filter(l => {
                                // Apply local filters
                                const matchesBranch = localBranch === 'all' || l.branchId === localBranch;
                                const matchesSearch = !searchTerm || 
                                    (l.memberName && l.memberName.toLowerCase().includes(searchTerm.toLowerCase())) ||
                                    (l.name && l.name.toLowerCase().includes(searchTerm.toLowerCase()));
                                return matchesBranch && matchesSearch;
                            }).sort((a, b) => new Date(b.timestamp) - new Date(a.timestamp));

                            const itemsPerPage = 15;
                            const startIndex = (currentLogPage - 1) * itemsPerPage;
                            const paginatedLogs = filteredLogs.slice(startIndex, startIndex + itemsPerPage);
                            const totalLogPages = Math.ceil(filteredLogs.length / itemsPerPage);

                            if (filteredLogs.length === 0) {
                                return <div style={{ textAlign: 'center', padding: '20px', color: 'var(--text-secondary)', fontSize: '0.9rem' }}>표시할 로그가 없습니다.</div>;
                            }

                            return (
                                <>
                                    {paginatedLogs.map((log, index) => (
                                        <div
                                            key={log.id || index}
                                            onClick={() => {
                                                if (log.memberId && onMemberClick) {
                                                    const member = members.find(m => m.id === log.memberId);
                                                    if (member) onMemberClick(member);
                                                }
                                            }}
                                            className="log-item"
                                            style={{
                                                display: 'flex', alignItems: 'center', padding: '12px',
                                                marginBottom: '6px', background: 'rgba(255,255,255,0.02)',
                                                borderRadius: '8px',
                                                cursor: log.memberId ? 'pointer' : 'default',
                                                transition: 'all 0.2s ease',
                                                borderLeft: `3px solid ${
                                                    log.status === 'denied' ? '#ff4d4f' :
                                                    log.type === 'checkin' ? 'var(--accent-success)' :
                                                    log.type === 'register' ? 'var(--primary-gold)' :
                                                    log.type === 'extend' ? '#3B82F6' :
                                                    'var(--text-secondary)'
                                                }`
                                            }}
                                            onMouseEnter={(e) => { if (log.memberId) e.currentTarget.style.background = 'rgba(255,255,255,0.05)'; }}
                                            onMouseLeave={(e) => { if (log.memberId) e.currentTarget.style.background = 'rgba(255,255,255,0.02)'; }}
                                        >
                                            <div style={{ width: '60px', fontSize: '0.75rem', opacity: 0.6, textAlign: 'center' }}>
                                                {new Date(log.timestamp).toLocaleTimeString('ko-KR', { timeZone: 'Asia/Seoul', hour: '2-digit', minute: '2-digit', hour12: false })}
                                            </div>
                                            {/* 사진 썸네일 */}
                                            {log.photoUrl && (
                                                <div
                                                    onClick={(e) => { e.stopPropagation(); setLightboxImage(log.photoUrl); }}
                                                    style={{
                                                        width: '28px', height: '28px', borderRadius: '50%', flexShrink: 0,
                                                        overflow: 'hidden', cursor: 'pointer',
                                                        border: '2px solid rgba(212,175,55,0.4)'
                                                    }}
                                                >
                                                    <img src={log.photoUrl} alt="" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                                                </div>
                                            )}
                                            <div style={{ flex: 1, paddingLeft: '12px' }}>
                                                <div style={{ display: 'flex', alignItems: 'center', gap: '8px', flexWrap: 'wrap' }}>
                                                    <span style={{ fontWeight: 'bold' }}>{log.memberName || log.name || '알 수 없음'}</span>
                                                    <span style={{ fontSize: '0.7rem', color: 'var(--primary-gold)', background: 'rgba(212,175,55,0.1)', padding: '1px 6px', borderRadius: '4px' }}>
                                                        {log.className || '일반'}
                                                    </span>
                                                    <span className="badge" style={{
                                                        fontSize: '0.65rem', padding: '2px 6px',
                                                        background: `${getBranchColor(log.branchId)}20`,
                                                        color: getBranchThemeColor(log.branchId),
                                                        border: `1px solid ${getBranchColor(log.branchId)}33`,
                                                        fontWeight: 'bold'
                                                    }}>
                                                        {getBranchName(log.branchId)}
                                                    </span>
                                                    {log.status === 'denied' && (
                                                        <span style={{
                                                            fontSize: '0.65rem', padding: '1px 6px', borderRadius: '10px',
                                                            background: 'rgba(255, 77, 79, 0.15)', color: '#ff4d4f',
                                                            border: '1px solid rgba(255, 77, 79, 0.3)', fontWeight: 'bold',
                                                            display: 'flex', alignItems: 'center', gap: '3px'
                                                        }}>
                                                            ⛔ 출석거부 ({log.denialReason === 'expired' ? '기간만료' : '횟수소진'})
                                                        </span>
                                                    )}
                                                    {(log.sessionCount > 1 || log.isMultiSession) && (
                                                        <span style={{
                                                            fontSize: '0.65rem', padding: '1px 6px', borderRadius: '10px',
                                                            background: 'var(--primary-gold)', color: 'black', fontWeight: 'bold',
                                                            display: 'flex', alignItems: 'center', gap: '3px'
                                                        }}>
                                                            <Sparkle size={10} weight="fill" />
                                                            {log.sessionCount || '2'}회차 Passion
                                                        </span>
                                                    )}
                                                    {log.facialMatched && (
                                                        <span style={{
                                                            fontSize: '0.65rem', padding: '1px 6px', borderRadius: '10px',
                                                            background: 'rgba(59, 130, 246, 0.15)', color: '#60A5FA',
                                                            border: '1px solid rgba(59, 130, 246, 0.3)', fontWeight: 'bold',
                                                            display: 'flex', alignItems: 'center', gap: '3px'
                                                        }}>
                                                            <UserFocus size={10} weight="fill" />
                                                            안면 일치
                                                        </span>
                                                    )}
                                                    {isToday && summary?.multiAttendedMemberIds?.includes(log.memberId) && (
                                                        <span className="badge" style={{
                                                            fontSize: '0.65rem', padding: '2px 6px',
                                                            background: 'rgba(245, 158, 11, 0.25)', color: '#FBBF24',
                                                            border: '1px solid rgba(245, 158, 11, 0.5)', fontWeight: 'bold',
                                                            height: 'max-content'
                                                        }}>
                                                            오늘 {summary?.attendanceCountMap?.[log.memberId] || 2}회 출석 🔥
                                                        </span>
                                                    )}
                                                </div>
                                                <div style={{ fontSize: '0.85rem', opacity: 0.8, marginTop: '2px', color: log.status === 'denied' ? '#ff4d4f' : 'inherit' }}>
                                                    {log.status === 'denied'
                                                        ? `출석 시도가 거부되었습니다 (${log.denialReason === 'expired' ? '기간만료' : '횟수소진'})`
                                                        : (log.action?.includes('출석') ? `${log.className || '일반'} 수업 참여 (${log.instructor || '관리자'} 선생님)` : log.action)
                                                    }
                                                </div>
                                            </div>
                                            {(log.type === 'checkin' || log.type === 'register') && isToday && (
                                                <button
                                                    onClick={async (e) => {
                                                        e.stopPropagation();
                                                        if (confirm('이 출석 기록을 삭제하시겠습니까?')) {
                                                            const restoreCredit = confirm('해당 회원의 수강권을 복구하시겠습니까? (취소 시 기록만 삭제)');
                                                            const result = await storageService.deleteAttendance(log.id, restoreCredit);
                                                            if (result.success) {
                                                                // [FIX] 삭제 후 UI 강제 갱신
                                                                setTimeout(() => {
                                                                    storageService.notifyListeners('logs');
                                                                    storageService.notifyListeners('members');
                                                                }, 500);
                                                                alert('출석 기록이 삭제되었습니다.');
                                                            } else {
                                                                alert(`삭제 실패: ${result.message}`);
                                                            }
                                                        }
                                                    }}
                                                    style={{
                                                        background: 'none', border: 'none',
                                                        color: 'rgba(244, 63, 94, 0.5)', cursor: 'pointer', padding: '8px'
                                                    }}
                                                    onMouseOver={(e) => e.currentTarget.style.color = '#F43F5E'}
                                                    onMouseOut={(e) => e.currentTarget.style.color = 'rgba(244, 63, 94, 0.5)'}
                                                >
                                                    <Trash size={16} />
                                                </button>
                                            )}
                                        </div>
                                    ))}

                                    {totalLogPages > 1 && (
                                        <div style={{ display: 'flex', justifyContent: 'center', gap: '10px', marginTop: '20px' }}>
                                            <button disabled={currentLogPage === 1} onClick={() => setCurrentLogPage(p => p - 1)} className="action-btn sm">&lt;</button>
                                            <span style={{ display: 'flex', alignItems: 'center', fontSize: '0.9rem' }}>{currentLogPage} / {totalLogPages}</span>
                                            <button disabled={currentLogPage === totalLogPages} onClick={() => setCurrentLogPage(p => p + 1)} className="action-btn sm">&gt;</button>
                                        </div>
                                    )}
                                </>
                            );
                        })()}
                    </div>
                </div>
            )}
        </div>

            {lightboxImage && (
                <ImageLightbox src={lightboxImage} onClose={() => setLightboxImage(null)} />
            )}
    </>
    );
};

// ─── Styles ───
const dateNavBtn = {
    background: 'none',
    border: '1px solid rgba(255,255,255,0.1)',
    borderRadius: '50%',
    width: '36px', height: '36px',
    display: 'flex', alignItems: 'center', justifyContent: 'center',
    cursor: 'pointer',
    color: 'var(--text-primary)',
    transition: 'all 0.2s ease'
};

export default LogsTab;

import React, { useState, useMemo, useEffect } from 'react';
import { BellRinging, Check, Info, Plus, NotePencil, PaperPlaneTilt, UserFocus } from '@phosphor-icons/react';
import { useStudioConfig } from '../../../contexts/StudioContext';



const MembersTab = ({
    members,
    filteredMembers,
    summary,
    searchTerm,
    setSearchTerm,
    filterType,
    handleToggleFilter,
    selectExpiringMembers,
    selectedMemberIds,
    toggleMemberSelection,
    selectFilteredMembers,
    currentPage,
    setCurrentPage,
    itemsPerPage,
    handleOpenEdit,
    setShowAddModal,
    setShowBulkMessageModal,
    pushTokens,
    getDormantSegments,
    setBulkMessageInitialText,
    setActiveTab,
    onNoteClick,
    todayReRegMemberIds
}) => {
    const { config } = useStudioConfig();
    const branches = config.BRANCHES || [];
    const getBranchName = (id) => branches.find(b => b.id === id)?.name || id;
    const getBranchColor = (id) => branches.find(b => b.id === id)?.color || 'var(--primary-gold)';
    const getBranchThemeColor = (id) => branches.find(b => b.id === id)?.color || 'var(--primary-gold)';

    const [localSort, setLocalSort] = useState('default'); // 'default', 'credits_asc', 'credits_desc', 'enddate_asc', 'enddate_desc'

    // [FIX] 자정 넘김 시 날짜 자동 갱신 — dateKey가 변경되면 todayKstStr/todayStartMs도 재계산
    const [dateKey, setDateKey] = useState(() => new Date().toLocaleDateString('sv-SE', { timeZone: 'Asia/Seoul' }));
    useEffect(() => {
        const interval = setInterval(() => {
            const now = new Date().toLocaleDateString('sv-SE', { timeZone: 'Asia/Seoul' });
            if (now !== dateKey) setDateKey(now);
        }, 60000); // 매 1분 체크
        return () => clearInterval(interval);
    }, [dateKey]);

    const todayKstStr = useMemo(() => dateKey, [dateKey]);
    const todayStartMs = useMemo(() => {
        return new Date(dateKey).getTime();
    }, [dateKey]);

    const finalFiltered = useMemo(() => {
        let result = filteredMembers;
        if (filterType === 'dormant' && getDormantSegments) {
            const segments = getDormantSegments(filteredMembers);
            result = segments['all'] || [];
        }

        // Apply local sorting
        if (localSort === 'credits_asc') {
            result = [...result].sort((a, b) => (a.credits || 0) - (b.credits || 0));
        } else if (localSort === 'credits_desc') {
            result = [...result].sort((a, b) => (b.credits || 0) - (a.credits || 0));
        } else if (localSort === 'enddate_asc') {
            result = [...result].sort((a, b) => {
                if (!a.endDate || a.endDate === 'unlimited' || a.endDate === 'TBD') return 1;
                if (!b.endDate || b.endDate === 'unlimited' || b.endDate === 'TBD') return -1;
                return new Date(a.endDate) - new Date(b.endDate);
            });
        } else if (localSort === 'enddate_desc') {
            result = [...result].sort((a, b) => {
                if (!a.endDate || a.endDate === 'unlimited' || a.endDate === 'TBD') return -1;
                if (!b.endDate || b.endDate === 'unlimited' || b.endDate === 'TBD') return 1;
                return new Date(b.endDate) - new Date(a.endDate);
            });
        }
        return result;
    }, [filteredMembers, filterType, getDormantSegments, localSort]);

    if (!summary || !filteredMembers) return <div style={{ padding: '20px', textAlign: 'center', color: 'var(--text-secondary)' }}>데이터 로딩 중...</div>;
    return (
        <div className="members-tab-container">

            <div style={{ marginBottom: '20px', display: 'flex', justifyContent: 'center' }}>
                <button onClick={() => setShowAddModal(true)} className="action-btn primary" style={{ flex: 'none', width: 'auto', minWidth: '350px', height: '54px', fontSize: '1.2rem', borderRadius: '12px', boxShadow: '0 8px 24px var(--primary-gold-glow)', fontWeight: 'bold', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px' }}>
                    <Plus size={24} weight="bold" /> 신규 회원 등록하기
                </button>
            </div>



            {/* Summary Grid */}
            <div className="stats-grid">
                <div className={`dashboard-card interactive ${filterType === 'all' ? 'highlight' : ''}`}
                    onClick={() => handleToggleFilter('all')}>
                    <div className="card-label" style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
                        전체 회원
                        <div className="tooltip-container" onClick={e => e.stopPropagation()}>
                            <Info size={14} style={{ opacity: 0.7 }} />
                            <span className="tooltip-text">현재 지점에 등록된<br />모든 회원 (삭제/탈퇴 제외)</span>
                        </div>
                    </div>
                    <div className="card-value">{summary.totalMembers}명</div>
                </div>
                <div className={`dashboard-card interactive ${filterType === 'active' ? 'highlight' : ''}`}
                    onClick={() => handleToggleFilter('active')}>
                    <div className="card-label" style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
                        활성 회원
                        <div className="tooltip-container" onClick={e => e.stopPropagation()}>
                            <Info size={14} style={{ opacity: 0.7 }} />
                            <span className="tooltip-text">잔여 횟수 1회 이상이며(0회 제외)<br />만료일이 오늘 또는 이후인 회원</span>
                        </div>
                    </div>
                    <div className="card-value gold">{summary.activeMembers}명</div>
                </div>
                <div className={`dashboard-card interactive ${filterType === 'attendance' ? 'highlight' : ''}`}
                    onClick={() => handleToggleFilter('attendance')}>
                    <div className="card-label">오늘 출석</div>
                    <div className="card-value">{summary.todayAttendance}명 / <span style={{ fontSize: '1rem', opacity: 0.8 }}>{summary.totalAttendanceToday}회</span></div>
                    {/* [NEW] Denied Stats Display */}
                    {summary.deniedCount > 0 && (
                        <div style={{ marginTop: '8px', paddingTop: '8px', borderTop: '1px solid rgba(255,255,255,0.1)', fontSize: '0.85rem', color: '#ff4d4f', fontWeight: 'bold', display: 'flex', alignItems: 'center', gap: '4px' }}>
                            <span>⛔ 거부 {summary.deniedCount}명</span>
                            <span style={{ fontSize: '0.75rem', opacity: 0.8, fontWeight: 'normal' }}>
                                (기간만료 {summary.deniedExpiredCount || 0}, 횟수소진 {summary.deniedNoCreditsCount || 0})
                            </span>
                        </div>
                    )}
                </div>
                <div className={`dashboard-card interactive ${filterType === 'registration' ? 'highlight' : ''}`}
                    onClick={() => handleToggleFilter('registration')}>
                    <div className="card-label" style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
                        오늘 전체 등록
                        <div className="tooltip-container" onClick={e => e.stopPropagation()}>
                            <Info size={14} style={{ opacity: 0.7 }} />
                            <span className="tooltip-text">오늘 등록된 모든 수강권 합계<br />(신규 가입 + 기존 회원 재등록)</span>
                        </div>
                    </div>
                    <div className="card-value success" style={{ fontSize: '1.8rem' }}>
                        {summary.todayRegistration}명
                    </div>
                    <div style={{ fontSize: '0.85rem', color: '#86efac', display: 'flex', gap: '8px', marginTop: '4px', fontWeight: 'bold' }}>
                        <span>신규 {summary.todayNewCount || 0}</span>
                        <span style={{ opacity: 0.4 }}>|</span>
                        <span>재등록 {summary.todayReRegCount || 0}</span>
                    </div>
                </div>
                <div className={`dashboard-card interactive ${filterType === 'expiring' ? 'highlight' : ''}`}
                    onClick={selectExpiringMembers}
                    style={{ transition: 'all 0.3s ease' }}>
                    <div className="card-label" style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
                        만료/횟수 임박
                        <div className="tooltip-container" onClick={e => e.stopPropagation()}>
                            <Info size={14} style={{ opacity: 0.7 }} />
                            <span className="tooltip-text" style={{ width: '220px', left: '-100px' }}>
                                잔여 2회 이하 또는<br />만료 7일 전 ~ 만료 후 30일 이내
                            </span>
                        </div>
                    </div>
                    <div className="card-value error">{summary.expiringMembersCount}명</div>
                </div>
                {/* [NEW] Dormant Members Card */}
                <div className={`dashboard-card interactive ${filterType === 'dormant' ? 'highlight' : ''}`}
                    onClick={() => handleToggleFilter('dormant')}
                    style={{ transition: 'all 0.3s ease' }}>
                    <div className="card-label" style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
