import { useState, useEffect, useRef } from 'react';
import { X } from '@phosphor-icons/react';

/**
 * ImageLightbox - 이미지 터치 시 전체 화면으로 확대하여 보여주는 모달 컴포넌트
 * 
 * @param {string} src - 표시할 이미지 URL
 * @param {function} onClose - 모달 닫기 핸들러
 */
const ImageLightbox = ({ src, onClose }) => {
    const [scale, setScale] = useState(1);
    const [position, setPosition] = useState({ x: 0, y: 0 });
    const [isDragging, setIsDragging] = useState(false);
    const [startPos, setStartPos] = useState({ x: 0, y: 0 });
    const [initialDistance, setInitialDistance] = useState(null);
    const containerRef = useRef(null);

    // ESC 키로 닫기
    useEffect(() => {
        const handleKeyDown = (e) => {
            if (e.key === 'Escape') onClose();
        };
        window.addEventListener('keydown', handleKeyDown);
        return () => window.removeEventListener('keydown', handleKeyDown);
    }, [onClose]);

    // 배경 스크롤 방지
    useEffect(() => {
        document.body.style.overflow = 'hidden';
        return () => {
            document.body.style.overflow = '';
        };
    }, []);

    // 두 손가락 사이 거리 계산
    const getDistance = (touches) => {
        const dx = touches[0].clientX - touches[1].clientX;
        const dy = touches[0].clientY - touches[1].clientY;
        return Math.sqrt(dx * dx + dy * dy);
    };

    const handleTouchStart = (e) => {
        if (e.touches.length === 2) {
            // 핀치 줌 시작
            setInitialDistance(getDistance(e.touches));
        } else if (e.touches.length === 1 && scale > 1) {
            // 드래그 시작 (확대된 상태에서만)
            setIsDragging(true);
            setStartPos({
                x: e.touches[0].clientX - position.x,
                y: e.touches[0].clientY - position.y
            });
        }
    };

    const handleTouchMove = (e) => {
        if (e.touches.length === 2 && initialDistance) {
            // 핀치 줌
            const currentDistance = getDistance(e.touches);
            const newScale = Math.min(Math.max(scale * (currentDistance / initialDistance), 1), 4);
            setScale(newScale);
            setInitialDistance(currentDistance);
            
            // 줌이 1로 돌아가면 위치 초기화
            if (newScale <= 1) {
                setPosition({ x: 0, y: 0 });
            }
        } else if (e.touches.length === 1 && isDragging && scale > 1) {
            // 드래그
            const newX = e.touches[0].clientX - startPos.x;
            const newY = e.touches[0].clientY - startPos.y;
            setPosition({ x: newX, y: newY });
        }
    };

    const handleTouchEnd = () => {
        setIsDragging(false);
        setInitialDistance(null);
    };

    // 더블 탭으로 줌 토글
    const lastTap = useRef(0);
    const handleDoubleTap = (e) => {
        const now = Date.now();
        if (now - lastTap.current < 300) {
            e.preventDefault();
            if (scale > 1) {
                setScale(1);
                setPosition({ x: 0, y: 0 });
            } else {
                setScale(2);
            }
        }
        lastTap.current = now;
    };

    // 배경 클릭으로 닫기 (이미지 외부 영역)
    const handleBackdropClick = (e) => {
        if (e.target === containerRef.current) {
            onClose();
        }
    };

    return (
        <div
            ref={containerRef}
            onClick={handleBackdropClick}
            style={{
                position: 'fixed',
                top: 0,
                left: 0,
                right: 0,
                bottom: 0,
                backgroundColor: 'rgba(0, 0, 0, 0.95)',
                zIndex: 10000,
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                animation: 'fadeIn 0.2s ease-out'
            }}
        >
            {/* 닫기 버튼 */}
            <button
                onClick={onClose}
                style={{
                    position: 'absolute',
                    top: '20px',
                    right: '20px',
                    width: '44px',
                    height: '44px',
                    borderRadius: '50%',
                    background: 'rgba(255, 255, 255, 0.15)',
                    border: 'none',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    cursor: 'pointer',
                    zIndex: 10001
                }}
            >
                <X size={24} color="white" weight="bold" />
            </button>

            {/* 줌 힌트 */}
            <div style={{
                position: 'absolute',
                bottom: '30px',
                left: '50%',
                transform: 'translateX(-50%)',
                color: 'rgba(255, 255, 255, 0.5)',
                fontSize: '0.8rem',
                textAlign: 'center',
                pointerEvents: 'none'
            }}>
                {scale > 1 ? '드래그하여 이동' : '두 손가락으로 확대 • 더블 탭으로 줌'}
            </div>

            {/* 이미지 */}
            <img
                src={src}
                alt="확대 보기"
                onClick={handleDoubleTap}
                onTouchStart={handleTouchStart}
                onTouchMove={handleTouchMove}
                onTouchEnd={handleTouchEnd}
                style={{
                    maxWidth: '95vw',
                    maxHeight: '90vh',
                    objectFit: 'contain',
                    transform: `scale(${scale}) translate(${position.x / scale}px, ${position.y / scale}px)`,
                    transition: isDragging ? 'none' : 'transform 0.2s ease-out',
                    touchAction: 'none',
                    userSelect: 'none'
                }}
                draggable={false}
            />
        </div>
    );
};

export default ImageLightbox;

import React, { useContext, useEffect, useState } from 'react';
import { PWAContext } from '../../contexts/PWAContextDef';
import { DownloadSimple } from '@phosphor-icons/react';

const InstallBanner = ({ onManualInstallClick }) => {
    const { isStandalone, deviceOS, installApp } = useContext(PWAContext) || {};
    const [isVisible, setIsVisible] = useState(false);
    const [dismissed, setDismissed] = useState(false);

    useEffect(() => {
        // 이미 PWA로 설치되어 있거나, 사용자가 닫은 적이 있으면 렌더링하지 않음
        const hasDismissed = localStorage.getItem('hide_install_banner') === 'true';
        setDismissed(hasDismissed);

        if (!isStandalone && !hasDismissed) {
            // 초기 렌더링 시 깜빡임 방지용 약간의 딜레이
            const timer = setTimeout(() => setIsVisible(true), 1500);
            return () => clearTimeout(timer);
        } else {
            setIsVisible(false);
        }
    }, [isStandalone]);

    if (!isVisible || isStandalone || dismissed) return null;

    const handleInstallClick = async () => {
        if (deviceOS === 'android') {
            const installed = await installApp();
            // 기본 설치 프롬프트가 안 뜨는 경우 예비용 모달 오픈
            if (!installed && onManualInstallClick) {
                onManualInstallClick();
            }
        } else {
            // iOS는 항상 수동 가이드 모달
            if (onManualInstallClick) {
                onManualInstallClick();
            }
        }
    };

    const handleDismiss = (e) => {
        e.stopPropagation();
        setIsVisible(false);
        localStorage.setItem('hide_install_banner', 'true');
    };

    return (
        <div style={{
            position: 'fixed',
            bottom: '80px', // 네비게이션 바 바로 위
            left: '50%',
            transform: 'translateX(-50%)',
            zIndex: 2000,
            animation: 'slideUpBounce 0.6s cubic-bezier(0.175, 0.885, 0.32, 1.275) forwards',
            width: 'calc(100% - 40px)',
            maxWidth: '350px'
        }}>
            <div 
                style={{
                    background: 'rgba(20, 20, 25, 0.85)',
                    backdropFilter: 'blur(12px)',
                    border: '1px solid rgba(212, 175, 55, 0.3)',
                    borderRadius: '24px',
                    padding: '12px 18px',
                    boxShadow: '0 8px 32px rgba(0, 0, 0, 0.4)',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'space-between',
                    gap: '12px',
                    cursor: 'pointer'
                }}
                onClick={handleInstallClick}
            >
                <div style={{
                    width: '36px', height: '36px',
                    borderRadius: '50%',
                    background: 'linear-gradient(135deg, var(--primary-gold), #b8860b)',
                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                    color: '#000',
                    flexShrink: 0
                }}>
                    <DownloadSimple size={20} weight="bold" />
                </div>
                
                <div style={{ flex: 1 }}>
                    <h4 style={{ margin: 0, fontSize: '0.9rem', color: '#fff', fontWeight: 'bold' }}>
                        앱 설치하고 1초 접속 ⚡️
                    </h4>
                    <p style={{ margin: '2px 0 0', fontSize: '0.75rem', color: 'rgba(255,255,255,0.6)' }}>
                        터치해서 홈 화면에 바로 추가하세요
                    </p>
                </div>

                <button
                    onClick={handleDismiss}
                    style={{
                        background: 'transparent',
                        border: 'none',
                        color: 'rgba(255,255,255,0.4)',
                        padding: '8px',
                        fontSize: '1.2rem',
                        cursor: 'pointer',
                        lineHeight: 1
                    }}
                >
                    &times;
                </button>
            </div>
            <style>{`
                @keyframes slideUpBounce {
                    0% { transform: translate(-50%, 100px); opacity: 0; }
                    100% { transform: translate(-50%, 0); opacity: 1; }
                }
            `}</style>
        </div>
    );
};

