import { useState, useEffect } from 'react';
import { useStudioConfig } from '../../../contexts/StudioContext';
import { Brain } from '../../../components/CommonIcons';

const AI_LOADING_MESSAGES = [
    "마음을 연결하고 있어요...",
    "깊이 분석 중입니다...",
    "오늘의 당신을 이해하고 있어요...",
    "호흡에 집중해 보세요...",
    "잠시, 고요함 속에 머물러요..."
];

export const AILoadingIndicator = ({ compact = false, message = null }) => {
    const { config } = useStudioConfig();
    const [msgIndex, setMsgIndex] = useState(0);
    
    useEffect(() => {
        if (message) return; // Don't cycle if custom message provided
        const interval = setInterval(() => {
            setMsgIndex(prev => (prev + 1) % AI_LOADING_MESSAGES.length);
        }, 2500);
        return () => clearInterval(interval);
    }, [message]);

    const displayMessage = message || AI_LOADING_MESSAGES[msgIndex];
    
    if (compact) {
        return (
            <div style={{ 
                display: 'flex', alignItems: 'center', gap: '12px', 
                padding: '12px 20px', borderRadius: '20px',
                background: 'rgba(212, 175, 55, 0.08)',
                border: '1px solid rgba(212, 175, 55, 0.15)'
            }}>
                <div className="ai-thinking-icon" style={{ 
                    width: '28px', height: '28px', 
                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                    color: config.THEME?.PRIMARY_COLOR || '#d4af37'
                }}>
                    <Brain size={24} weight="duotone" />
                </div>
                <span style={{ color: 'rgba(255,255,255,0.8)', fontSize: '0.9rem' }}>{displayMessage}</span>
            </div>
        );
    }
    
    return (
        <div style={{ 
            display: 'flex', flexDirection: 'column', alignItems: 'center', 
            justifyContent: 'center', gap: '24px', padding: '40px'
        }}>
            {/* Rotating/Pulsing Icon */}
            <div className="ai-thinking-icon" style={{ 
                width: '80px', height: '80px', borderRadius: '50%',
                background: 'rgba(212, 175, 55, 0.1)',
                border: '2px solid rgba(212, 175, 55, 0.3)',
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                color: config.THEME?.PRIMARY_COLOR || '#d4af37',
                boxShadow: '0 0 30px rgba(212, 175, 55, 0.2)'
            }}>
                <Brain size={40} weight="duotone" />
            </div>
            
            {/* Message */}
            <div style={{ textAlign: 'center' }}>
                <div style={{ 
                    color: 'rgba(255,255,255,0.9)', fontSize: '1.1rem', fontWeight: '500',
                    marginBottom: '8px', transition: 'opacity 0.3s ease'
                }}>
                    {displayMessage}
                </div>
                <div style={{ color: 'rgba(255,255,255,0.4)', fontSize: '0.85rem' }}>
                    AI가 생각하고 있어요
                </div>
            </div>
        </div>
    );
};

import React from 'react';
import { AILoadingIndicator } from './AILoadingIndicator';
import { Microphone, LockKey, User } from '../../../components/CommonIcons';
import { useStudioConfig } from '../../../contexts/StudioContext';

export const ChatDialog = ({
    chatHistory,
    currentAIChat,
    isAILoading,
    chatEndRef,
    stopAllAudio,
    handleChatResponse,
    manualInput,
    setManualInput,
    handleManualSubmit,
    isAnalyzing,
    onStartMeditation
}) => {
    return (
        <div style={{
            position: 'absolute', bottom: '0', left: '0', right: '0',
            background: 'linear-gradient(to top, rgba(10,10,12,0.95) 40%, rgba(10,10,12,0.8) 80%, transparent)',
            display: 'flex', flexDirection: 'column', zIndex: 100,
            paddingTop: '60px'
        }}>
            {/* 2. Messages Area */}
            <div className="no-scrollbar" style={{ 
                flex: 1, overflowY: 'auto', padding: '0 20px 20px', 
                display: 'flex', flexDirection: 'column', gap: '16px' 
            }}>
                {chatHistory.map((chat, idx) => (
                    <div key={idx} style={{
                        alignSelf: chat.role === 'user' ? 'flex-end' : 'flex-start',
                        maxWidth: '80vw', opacity: 0.9, lineHeight: '1.5',
                        display: 'flex', flexDirection: 'row', alignItems: 'flex-end', gap: '8px'
                    }}>
                        {chat.role === 'model' && (
                            <div style={{
                                width: '36px', height: '36px', borderRadius: '50%',
                                background: 'rgba(255,255,255,0.1)', display: 'flex', alignItems: 'center', justifyContent: 'center',
                                overflow: 'hidden', border: '1px solid rgba(255,255,255,0.05)', flexShrink: 0,
                                color: 'var(--primary-gold)'
                            }}>
                                <User size={20} weight="fill" />
                            </div>
                        )}
                        <div style={{
                            background: chat.role === 'user' ? 'rgba(212,175,55,0.15)' : 'rgba(255,255,255,0.05)',
                            color: chat.role === 'user' ? 'var(--primary-gold)' : 'white',
                            padding: '12px 18px',
                            borderRadius: chat.role === 'user' ? '18px 18px 4px 18px' : '18px 18px 18px 4px',
                            border: chat.role === 'user' ? '1px solid rgba(212,175,55,0.3)' : '1px solid rgba(255,255,255,0.1)',
                            fontSize: '0.95rem'
                        }}>{chat.content}</div>
                    </div>
                ))}
                
                {/* AI Response Area */}
                {currentAIChat && !isAILoading && (
                    <div style={{ display: 'flex', justifyContent: 'flex-start', alignItems: 'flex-start', gap: '8px' }}>
                        <div style={{
                            width: '40px', height: '40px', borderRadius: '50%',
                            background: 'rgba(255,255,255,0.1)', display: 'flex', alignItems: 'center', justifyContent: 'center',
                            overflow: 'hidden', border: '1px solid rgba(255,255,255,0.1)', flexShrink: 0,
                            color: 'var(--primary-gold)'
                        }}>
                            <User size={24} weight="fill" />
                        </div>
                        <div style={{ display: 'flex', flexDirection: 'row', alignItems: 'flex-end', gap: '6px' }}>
                            <div style={{
                                background: 'rgba(255,255,255,0.08)', color: 'white', padding: '14px 18px',
                                borderRadius: '4px 18px 18px 18px', maxWidth: '75vw', fontSize: '1.0rem', lineHeight: '1.6',
                                boxShadow: '0 4px 15px rgba(0,0,0,0.3)', border: '1px solid rgba(255,255,255,0.15)', backdropFilter: 'blur(10px)'
                            }}>{currentAIChat.message || currentAIChat.question || "오늘 하루는 어떠셨나요?"}</div>
                            <span style={{ fontSize: '0.7rem', color: 'rgba(255,255,255,0.4)', marginBottom: '2px' }}>
                                {new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                            </span>
                        </div>
                    </div>
                )}

                {isAILoading && (
                    <div style={{ alignSelf: 'center', marginTop: '10px' }}>
                        <AILoadingIndicator compact={true} message={chatHistory.length === 0 ? `AI ${config.AI_CONFIG?.NAME || 'AI'}가 당신의 마음을 듣고 있어요...` : null} />
                    </div>
                )}
                <div ref={chatEndRef} style={{ height: '2px', width: '100%' }} />
            </div>

            {/* 3. Bottom Options & Input */}
            <div style={{
                background: '#1a1a1d', borderTop: '1px solid rgba(255,255,255,0.1)',
                padding: '15px', paddingBottom: 'calc(15px + env(safe-area-inset-bottom))',
                display: 'flex', flexDirection: 'column', gap: '12px', zIndex: 20
            }}>
                {/* 시작 버튼 한정 */}
                {!isAILoading && currentAIChat?.isFinalAnalysis && (
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '10px', animation: 'fadeIn 0.5s ease' }}>
                        <button onClick={onStartMeditation} style={{
                            width: '100%', background: 'var(--primary-gold)', color: 'black',
                            padding: '18px', borderRadius: '20px', fontSize: '1.1rem', fontWeight: 800, border: 'none',
                            cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px',
                            boxShadow: '0 10px 20px rgba(212,175,55,0.3)'
                        }}>🧘 명상 시작하기</button>
                        <p style={{ textAlign: 'center', fontSize: '0.8rem', color: 'rgba(255,255,255,0.4)' }}>
                            당신에게 맞는 명상을 준비했어요
                        </p>
                    </div>
                )}

                {/* 대화 선택지 버튼 */}
                {!isAILoading && currentAIChat?.options?.length > 0 && !currentAIChat?.isFinalAnalysis && (
                    <div className="no-scrollbar" style={{ display: 'flex', gap: '8px', overflowX: 'auto', paddingBottom: '10px', scrollbarWidth: 'none', justifyContent: 'flex-start' }}>
                        {currentAIChat.options.map((opt, i) => (
                            <button key={i} onClick={() => { stopAllAudio(); handleChatResponse(opt); }}
                                style={{
                                    flex: '0 0 auto', background: 'rgba(255,255,255,0.08)', border: '1px solid rgba(255,255,255,0.15)',
                                    padding: '10px 18px', borderRadius: '18px', color: 'rgba(255,255,255,0.9)', 
                                    fontSize: '0.9rem', cursor: 'pointer', transition: 'all 0.2s', backdropFilter: 'blur(5px)'
                                }}>{opt}</button>
                        ))}
                    </div>
                )}

                {/* 입력창 (마이크/텍스트) */}
                {!currentAIChat?.isFinalAnalysis && !currentAIChat?.isTransition && !isAnalyzing && (
                    <form onSubmit={handleManualSubmit} style={{ display: 'flex', gap: '10px', alignItems: 'stretch', height: '52px' }}>
                        {/* Audio Mock Record Button */}
                        <button type="button" style={{
                            width: '52px', borderRadius: '16px', border: 'none',
                            background: 'rgba(255,255,255,0.05)', color: 'white', display: 'flex', alignItems: 'center', justifyContent: 'center',
                            flexShrink: 0
                        }}>
                            <Microphone size={24} weight="fill" />
                        </button>

                        <div style={{ flex: 1, position: 'relative', display: 'flex', alignItems: 'center' }}>
                            <input 
                                type="text"
                                value={manualInput}
                                onChange={e => setManualInput(e.target.value)}
                                placeholder="직접 마음 상태를 입력하세요..."
                                disabled={isAILoading}
                                style={{
                                    width: '100%', height: '100%', background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.1)',
                                    borderRadius: '16px', color: 'white', padding: '0 45px 0 15px', fontSize: '0.95rem'
                                }}
                            />
                            {isAILoading && <LockKey size={18} color="rgba(255,255,255,0.3)" style={{ position: 'absolute', right: '15px' }} />}
                        </div>
                    </form>
                )}
            </div>
        </div>
    );
};

import React from 'react';
import { useNavigate } from 'react-router-dom';
import { useStudioConfig } from '../../../contexts/StudioContext';
import { X, Heartbeat, Brain, Sparkle } from '../../../components/CommonIcons';

export const FeedbackView = ({ 
    activeMode, 
    feedbackData, 
    formatTime, 
    timeLeft, 
    modeName, 
    onClose 
}) => {
    const { config } = useStudioConfig();
    const navigate = useNavigate();
    const duration = activeMode?.time || (activeMode?.id === 'breath' ? 3 * 60 : (activeMode?.id === 'calm' ? 7 * 60 : 15 * 60));
    const actualTime = Math.max(0, duration - timeLeft);

    return (
        <div style={{
            position: 'fixed', inset: 0, background: '#0a0a0c', zIndex: 4000,
            overflowY: 'auto', padding: '20px', WebkitOverflowScrolling: 'touch'
        }}>
            <div style={{
                minHeight: '100%', display: 'flex', flexDirection: 'column', 
                alignItems: 'center', justifyContent: 'flex-start', margin: 'auto'
            }}>
            <button onClick={onClose} style={{
                position: 'absolute', top: '20px', right: '20px',
                background: 'rgba(255,255,255,0.1)', border: 'none', color: 'white',
                width: '50px', height: '50px', borderRadius: '50%',
                display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer'
            }}><X size={24} /></button>

            <div style={{
                background: 'linear-gradient(145deg, rgba(30,30,35,0.9), rgba(15,15,20,0.9))',
                borderRadius: '30px', padding: '40px', maxWidth: '600px', width: '100%',
                border: `1px solid ${activeMode?.color}40`,
                boxShadow: `0 20px 80px ${activeMode?.color}20`,
                animation: 'fadeIn 0.5s ease-out'
            }}>
                <div style={{ textAlign: 'center', marginBottom: '30px' }}>
                    <div style={{
                        width: '80px', height: '80px', borderRadius: '50%',
                        background: `${activeMode?.color}20`, margin: '0 auto 20px',
                        display: 'flex', alignItems: 'center', justifyContent: 'center',
                        color: activeMode?.color
                    }}>
                        <Brain size={40} weight="light" />
                    </div>
                    <h2 style={{ color: 'white', fontSize: '1.8rem', fontWeight: 600, marginBottom: '10px' }}>
                        명상 수련 완료
                    </h2>
                    <p style={{ color: 'rgba(255,255,255,0.6)', fontSize: '1.1rem' }}>
                        {modeName} • {Math.floor(actualTime / 60)}분 {actualTime % 60}초 수련
                    </p>
                </div>

                {feedbackData ? (
                    <div style={{ 
                        background: 'rgba(0,0,0,0.3)', borderRadius: '20px', padding: '25px',
                        border: '1px solid rgba(255,255,255,0.05)'
                    }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '15px' }}>
                            <Heartbeat size={24} color={activeMode?.color || config.THEME?.PRIMARY_COLOR || '#d4af37'} />
                            <h3 style={{ color: 'white', fontSize: '1.2rem', fontWeight: 500, margin: 0 }}>
                                AI의 마음 관찰 일지
                            </h3>
                        </div>
                        
                        {/* ✅ [FIX 3] 관찰일지 출력 로직 개선: message 외에 feedbackPoints도 제대로 노출 */}
                        <div style={{ 
                            color: 'rgba(255,255,255,0.9)', lineHeight: 1.8, fontSize: '1.1rem',
                            whiteSpace: 'pre-wrap', marginBottom: '20px'
                        }}>
                            {feedbackData.message && <p style={{ marginBottom: '15px' }}>{feedbackData.message}</p>}
                            {feedbackData.feedbackPoints && feedbackData.feedbackPoints.length > 0 ? (
                                <ul style={{ listStyle: 'none', padding: 0, margin: 0, display: 'flex', flexDirection: 'column', gap: '10px' }}>
                                    {feedbackData.feedbackPoints.map((point, index) => (
                                        <li key={index} style={{ display: 'flex', gap: '10px', alignItems: 'flex-start' }}>
                                            <Sparkle size={18} color={activeMode?.color || config.THEME?.PRIMARY_COLOR || '#d4af37'} style={{ marginTop: '4px', flexShrink: 0 }} />
                                            <span>{point}</span>
                                        </li>
                                    ))}
                                </ul>
                            ) : (!feedbackData.message && (
                                <p style={{ color: 'rgba(255,255,255,0.5)', fontStyle: 'italic' }}>명상 데이터 분석 내용을 요약하지 못했습니다.</p>
                            ))}
                        </div>
                        
                        {feedbackData.analysis && (
                            <div style={{ 
                                marginTop: '20px', paddingTop: '20px', borderTop: '1px solid rgba(255,255,255,0.1)',
                                display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '15px'
                            }}>
                                <div style={{ background: 'rgba(255,255,255,0.05)', padding: '15px', borderRadius: '15px' }}>
                                    <span style={{ display: 'block', color: 'rgba(255,255,255,0.5)', fontSize: '0.85rem', marginBottom: '5px' }}>호흡 안정도</span>
                                    <span style={{ color: 'white', fontSize: '1.2rem', fontWeight: 600 }}>{feedbackData.analysis.stabilityScore}/100</span>
                                </div>
                                <div style={{ background: 'rgba(255,255,255,0.05)', padding: '15px', borderRadius: '15px' }}>
                                    <span style={{ display: 'block', color: 'rgba(255,255,255,0.5)', fontSize: '0.85rem', marginBottom: '5px' }}>에너지 변화</span>
                                    <span style={{ color: 'white', fontSize: '1.1rem', fontWeight: 500 }}>{feedbackData.analysis.energyShift}</span>
                                </div>
                            </div>
                        )}
                    </div>
                ) : (
                    <div style={{ textAlign: 'center', padding: '40px 0' }}>
                        <div className="breathing-circle" style={{ 
                            width: '40px', height: '40px', margin: '0 auto 20px',
                            background: activeMode?.color, borderRadius: '50%' 
                        }} />
                        <p style={{ color: 'rgba(255,255,255,0.6)' }}>명상 데이터를 분석하고 있습니다...</p>
                    </div>
                )}

                {/* ✅ [FIX 1] 버튼이 검은색 배경에 묻히지 않도록 기본 Fallback Color 적용 */}
                <button onClick={onClose} style={{
                    width: '100%', padding: '20px', marginTop: '30px',
                    background: activeMode?.color || config.THEME?.PRIMARY_COLOR || '#d4af37', border: 'none', borderRadius: '15px',
                    color: 'black', fontWeight: 800, fontSize: '1.2rem', cursor: 'pointer',
                    boxShadow: `0 10px 30px ${activeMode?.color || config.THEME?.PRIMARY_COLOR || '#d4af37'}40`
                }}>
                    마음 챙김 마치고 돌아가기
                </button>
            </div>
            </div>
        </div>
    );
};

import React from 'react';

export const PoseCanvas = ({ videoRef, canvasRef }) => (
    <div style={{ position: 'absolute', inset: 0, zIndex: 1, opacity: 0.6 }}>
        <video 
            ref={videoRef} 
            autoPlay 
            playsInline 
            muted 
            style={{ width: '100%', height: '100%', objectFit: 'cover', transform: 'scaleX(-1)' }} 
        />
        <canvas
            ref={canvasRef}
            width={window.innerWidth}
            height={window.innerHeight}
            style={{
                position: 'absolute', inset: 0,
                width: '100%', height: '100%',
                transform: 'scaleX(-1)', // Mirror to match video
                pointerEvents: 'none'
            }}
        />
        <div style={{
            position: 'absolute', top: '50%', left: '50%', transform: 'translate(-50%, -50%)',
            width: '280px', height: '350px',
            border: '1px solid rgba(255, 215, 0, 0.3)', borderRadius: '120px',
            boxShadow: '0 0 80px rgba(255, 215, 0, 0.1) inset'
        }} />
    </div>
);

import React from 'react';
import { X } from '../../../components/CommonIcons';

export const VolumeControlPanel = ({
    showVolumePanel,
    setShowVolumePanel,
    audioVolumes,
    setAudioVolumes,
    currentAudioRef,
    updateAmbientVolume,
    updateBinauralVolume,
    soundEnabled,
    setSoundEnabled
}) => {
    if (!showVolumePanel) return null;

    return (
        <div style={{
            position: 'absolute', bottom: '180px', left: '50%', transform: 'translateX(-50%)',
            width: '280px', background: 'rgba(0,0,0,0.85)', backdropFilter: 'blur(20px)',
            borderRadius: '24px', padding: '20px', zIndex: 30,
            border: '1px solid rgba(255,255,255,0.15)', boxShadow: '0 20px 60px rgba(0,0,0,0.6)',
            animation: 'fadeIn 0.3s ease'
        }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '15px' }}>
                <span style={{ color: 'var(--primary-gold)', fontSize: '0.85rem', fontWeight: 700 }}>🎛️ 볼륨 조절</span>
                <button onClick={() => setShowVolumePanel(false)} style={{ background: 'none', border: 'none', color: 'rgba(255,255,255,0.5)', cursor: 'pointer', padding: '4px' }}>
                    <X size={18} />
                </button>
            </div>
            
            {/* Voice Volume */}
            <div style={{ marginBottom: '12px' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '6px' }}>
                    <span style={{ fontSize: '0.8rem', color: 'rgba(255,255,255,0.7)' }}>🗣️ 음성 안내</span>
                    <span style={{ fontSize: '0.75rem', color: 'var(--primary-gold)' }}>{Math.round(audioVolumes.voice * 100)}%</span>
                </div>
                <input type="range" min="0" max="100" value={Math.round(audioVolumes.voice * 100)}
                    onChange={(e) => {
                        const val = parseInt(e.target.value) / 100;
                        setAudioVolumes(prev => ({ ...prev, voice: val }));
                        if (currentAudioRef.current) currentAudioRef.current.volume = val;
                    }}
                    style={{ width: '100%', accentColor: 'var(--primary-gold)', height: '4px' }} />
            </div>
            
            {/* Ambient Volume */}
            <div style={{ marginBottom: '12px' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '6px' }}>
                    <span style={{ fontSize: '0.8rem', color: 'rgba(255,255,255,0.7)' }}>🌊 환경음</span>
                    <span style={{ fontSize: '0.75rem', color: 'var(--primary-gold)' }}>{Math.round(audioVolumes.ambient * 100)}%</span>
                </div>
                <input type="range" min="0" max="100" value={Math.round(audioVolumes.ambient * 100)}
                    onChange={(e) => {
                        const val = parseInt(e.target.value) / 100;
                        setAudioVolumes(prev => ({ ...prev, ambient: val }));
                        updateAmbientVolume(val);
                    }}
                    style={{ width: '100%', accentColor: '#4ade80', height: '4px' }} />
            </div>
            
            {/* Binaural Volume */}
            <div>
                <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '6px' }}>
                    <span style={{ fontSize: '0.8rem', color: 'rgba(255,255,255,0.7)' }}>🎵 주파수</span>
                    <span style={{ fontSize: '0.75rem', color: 'var(--primary-gold)' }}>{Math.round(audioVolumes.binaural * 100)}%</span>
                </div>
                <input type="range" min="0" max="100" value={Math.round(audioVolumes.binaural * 100)}
                    onChange={(e) => {
                        const val = parseInt(e.target.value) / 100;
                        setAudioVolumes(prev => ({ ...prev, binaural: val }));
                        updateBinauralVolume(val);
                    }}
                    style={{ width: '100%', accentColor: '#a29bfe', height: '4px' }} />
            </div>
            
            {/* Mute All Toggle */}
            <button onClick={() => {
                setSoundEnabled(!soundEnabled);
                if (soundEnabled) {
                    // Mute all
                    updateAmbientVolume(0);
                    updateBinauralVolume(0);
                } else {
                    // Restore
                    updateAmbientVolume(audioVolumes.ambient);
                    updateBinauralVolume(audioVolumes.binaural);
                }
            }} style={{
                marginTop: '12px', width: '100%', padding: '10px', borderRadius: '12px',
                background: soundEnabled ? 'rgba(255,255,255,0.08)' : 'rgba(255,0,0,0.15)',
                border: '1px solid rgba(255,255,255,0.1)', color: soundEnabled ? 'rgba(255,255,255,0.7)' : '#ff6b6b',
                fontSize: '0.8rem', cursor: 'pointer', fontWeight: 600
            }}>{soundEnabled ? '🔇 전체 음소거' : '🔊 소리 켜기'}</button>
        </div>
    );
};

import { useState, useEffect } from 'react';
import { Bell, BellSlash, CheckCircle, Warning, Info } from '@phosphor-icons/react';
import { storageService } from '../../services/storage';
import { useStudioConfig } from '../../contexts/StudioContext';

const PushNotificationSettings = ({ memberId }) => {
    const { config } = useStudioConfig();
    const [status, setStatus] = useState(null);
    const [loading, setLoading] = useState(true);
    const [reregistering, setReregistering] = useState(false);
    const [message, setMessage] = useState('');

    useEffect(() => {
        checkStatus();
    }, []);

    const checkStatus = async () => {
        setLoading(true);
        try {
            const pushStatus = await storageService.checkPushNotificationStatus();
            setStatus(pushStatus);
            setMessage(pushStatus.message);
        } catch (error) {
            console.error('Push status check failed:', error);
            setMessage('푸시 알림 상태를 확인할 수 없습니다.');
        } finally {
            setLoading(false);
        }
    };

    const handleReregister = async () => {
        if (!memberId) {
            alert('회원 정보가 없습니다.');
            return;
        }

        setReregistering(true);
        setMessage('푸시 알림을 재설정하는 중...');

        try {
            const result = await storageService.reregisterPushToken(memberId);

            if (result.success) {
                setMessage(result.message);
                // 상태 새로고침
                await checkStatus();
            } else {
                setMessage(result.message);
            }
        } catch (error) {
            console.error('Reregistration failed:', error);
            setMessage(`재설정 실패: ${error.message}`);
        } finally {
            setReregistering(false);
        }
    };

    if (loading) {
        return (
            <div style={styles.container}>
                <div style={styles.loadingText}>푸시 알림 상태 확인 중...</div>
            </div>
        );
    }

    const getStatusIcon = () => {
        if (!status) return <Info size={24} color="#a1a1aa" />;
        if (!status.supported) return <BellSlash size={24} color="#ef4444" />;
        if (status.permission === 'denied') return <Warning size={24} color="#f59e0b" />;
        if (status.hasToken) return <CheckCircle size={24} color="#10b981" weight="fill" />;
        return <Bell size={24} color="#6b7280" />;
    };

    const getStatusColor = () => {
        if (!status || !status.supported) return '#ef4444';
        if (status.permission === 'denied') return '#f59e0b';
        if (status.hasToken) return '#10b981';
        return '#6b7280';
    };

    const needsAction = status && status.supported && (!status.hasToken || status.permission !== 'granted');

    return (
        <div style={styles.container}>
            <div style={styles.header}>
                <div style={styles.iconWrapper}>
                    {getStatusIcon()}
                </div>
                <div style={styles.headerText}>
                    <h3 style={styles.title}>푸시 알림 설정</h3>
                    <p style={{ ...styles.subtitle, color: getStatusColor() }}>
                        {message}
                    </p>
                </div>
            </div>

            {/* 상세 정보 */}
            {status && status.supported && (
                <div style={styles.detailsContainer}>
                    <div style={styles.detailItem}>
                        <span style={styles.detailLabel}>브라우저 지원:</span>
                        <span style={status.supported ? styles.detailSuccess : styles.detailError}>
                            {status.supported ? '✓ 지원됨' : '✗ 미지원'}
                        </span>
                    </div>
                    <div style={styles.detailItem}>
                        <span style={styles.detailLabel}>알림 권한:</span>
                        <span style={
                            status.permission === 'granted' ? styles.detailSuccess :
                                status.permission === 'denied' ? styles.detailError :
                                    styles.detailWarning
                        }>
                            {status.permission === 'granted' ? '✓ 허용됨' :
                                status.permission === 'denied' ? '✗ 차단됨' :
                                    '○ 미설정'}
                        </span>
                    </div>
                    <div style={styles.detailItem}>
                        <span style={styles.detailLabel}>Service Worker:</span>
                        <span style={status.serviceWorker ? styles.detailSuccess : styles.detailError}>
                            {status.serviceWorker ? '✓ 활성화' : '✗ 비활성화'}
                        </span>
                    </div>
                    <div style={styles.detailItem}>
                        <span style={styles.detailLabel}>푸시 토큰:</span>
                        <span style={status.hasToken ? styles.detailSuccess : styles.detailError}>
                            {status.hasToken ? '✓ 등록됨' : '✗ 미등록'}
                        </span>
                    </div>
                </div>
            )}

            {/* 조치 필요 시 버튼 및 안내 */}
            {needsAction && (
                <div style={styles.actionContainer}>
                    <div style={styles.infoBox}>
                        <Info size={18} color="#3b82f6" style={{ flexShrink: 0 }} />
                        <div style={styles.infoText}>
                            {status.permission === 'denied' ? (
                                <span>
                                    브라우저 설정에서 알림을 허용해주세요:<br />
                                    <strong>1.</strong> 주소창 왼쪽의 자물쇠(🔒) 아이콘 클릭<br />
                                    <strong>2.</strong> 알림 → 허용으로 변경<br />
                                    <strong>3.</strong> 페이지 새로고침 후 아래 버튼 클릭
                                </span>
                            ) : (
                                <span>
                                    푸시 알림을 받으려면 아래 버튼을 눌러 설정을 완료해주세요.
                                </span>
                            )}
                        </div>
                    </div>

                    <button
                        onClick={handleReregister}
                        disabled={reregistering || status.permission === 'denied'}
                        style={{
                            ...styles.button,
                            ...(reregistering || status.permission === 'denied' ? styles.buttonDisabled : {})
                        }}
                    >
                        {reregistering ? (
                            <>
                                <div style={styles.spinner}></div>
                                재설정 중...
                            </>
                        ) : (
                            <>
                                <Bell size={18} style={{ marginRight: '8px' }} />
                                푸시 알림 재설정하기
                            </>
                        )}
                    </button>
                </div>
            )}

            {/* 성공 상태 */}
            {status && status.hasToken && status.permission === 'granted' && (
                <div style={styles.successBox}>
                    <CheckCircle size={20} color="#10b981" weight="fill" />
                    <span style={styles.successText}>
                        푸시 알림이 정상적으로 설정되어 있습니다.
                    </span>
                </div>
            )}

            {/* 재설정 버튼 (문제가 있을 때만) */}
            {status && status.hasToken && status.permission === 'granted' && (
                <button
                    onClick={handleReregister}
                    disabled={reregistering}
                    style={styles.secondaryButton}
                >
                    <Bell size={16} style={{ marginRight: '6px' }} />
                    재설정
                </button>
            )}
        </div>
    );
};

