                    <div style={{ fontWeight: 'bold', fontSize: '0.9rem', color: 'white', marginBottom: '4px' }}>{pose.name}</div>
                    <div style={{ fontSize: '0.75rem', color: 'var(--primary-gold)', marginBottom: '8px' }}>{pose.benefit}</div>
                    <div style={{
                        fontSize: '0.8rem',
                        color: 'rgba(255,255,255,0.7)',
