                                                {currentMonthStr}월
                                            </button>
                                            <button
                                                onClick={() => setScheduleMonth('next')}
                                                style={{
                                                    background: activeMonth === 'next' ? 'var(--primary-gold)' : 'transparent',
                                                    color: activeMonth === 'next' ? 'black' : 'rgba(255,255,255,0.6)',
                                                    border: 'none',
                                                    borderRadius: '20px',
                                                    padding: '4px 12px',
                                                    fontSize: '0.8rem',
                                                    fontWeight: 'bold',
                                                    cursor: 'pointer'
                                                }}
                                            >
                                                {nextMonthStr}월 &gt;
                                            </button>
