import { useRef, useCallback, useEffect } from 'react';

export const useMeditationAudio = (ttcEnabled, isPlayingRef, step, logDebug, setTtsState, audioVolumes, soundEnabled) => {
    const audioContextRef = useRef(null);
    const oscLeftRef = useRef(null);
    const oscRightRef = useRef(null);
    const gainNodeRef = useRef(null);
    const currentAudioRef = useRef(null);
    const ambientAudioRef = useRef(null);

    // Audio Context Getter
    const getAudioContext = useCallback(() => {
        if (!audioContextRef.current) {
            audioContextRef.current = new (window.AudioContext || window.webkitAudioContext)();
        }
        return audioContextRef.current;
    }, []);

    // ---------------------------------------------------------
    // 1. Binaural Beats Engine
    // ---------------------------------------------------------
    const playBinauralBeats = useCallback((carrierFreq = 200, beatFreq = 4, volume = 0.25) => {
        const audioCtx = getAudioContext();
        if (audioCtx.state === 'suspended') audioCtx.resume();

        const oscL = audioCtx.createOscillator();
        const oscR = audioCtx.createOscillator();
        const gainNode = audioCtx.createGain();

        oscL.type = 'sine'; oscR.type = 'sine';
        oscL.frequency.value = carrierFreq;
        oscR.frequency.value = carrierFreq + beatFreq;

        const pannerL = audioCtx.createStereoPanner();
        const pannerR = audioCtx.createStereoPanner();
        pannerL.pan.value = -1; pannerR.pan.value = 1;

        oscL.connect(pannerL); pannerL.connect(gainNode);
        oscR.connect(pannerR); pannerR.connect(gainNode);

        gainNode.connect(audioCtx.destination);
        gainNode.gain.value = volume;

        oscL.start(); oscR.start();

        oscLeftRef.current = oscL;
        oscRightRef.current = oscR;
        gainNodeRef.current = gainNode;
        
        logDebug && logDebug("BinauralBeats:Start", { carrierFreq, beatFreq, volume });
    }, [getAudioContext, logDebug]);

    const stopBinauralBeats = useCallback(() => {
        if (oscLeftRef.current) { try { oscLeftRef.current.stop(); } catch { /* ignore */ } oscLeftRef.current = null; }
        if (oscRightRef.current) { try { oscRightRef.current.stop(); } catch { /* ignore */ } oscRightRef.current = null; }
        if (gainNodeRef.current) gainNodeRef.current = null;
    }, []);

    const updateBinauralVolume = useCallback((volume) => {
        if (gainNodeRef.current && audioContextRef.current) {
            const currentTime = audioContextRef.current.currentTime;
            gainNodeRef.current.gain.setTargetAtTime(volume, currentTime, 0.5);
        }
    }, []);

    // ---------------------------------------------------------
    // 2. Ambient Environments Engine
    // ---------------------------------------------------------
    const updateAmbientVolume = useCallback((volume) => {
        if (ambientAudioRef.current) {
            ambientAudioRef.current.volume = volume;
        }
    }, []);

    const playAmbientMusic = useCallback((ambientDef, volume) => {
        if (!ambientDef || ambientDef.id === 'none') {
            if (ambientAudioRef.current) {
                ambientAudioRef.current.pause();
                ambientAudioRef.current = null;
            }
            return;
        }

        if (!ambientAudioRef.current || !ambientAudioRef.current.src.includes(ambientDef.audioUrl)) {
            if (ambientAudioRef.current) ambientAudioRef.current.pause();
            const audio = new Audio(ambientDef.audioUrl);
            audio.loop = true;
            audio.volume = volume;
            ambientAudioRef.current = audio;
        }

        ambientAudioRef.current.play().catch(e => {
            console.warn("Ambient play failed:", e);
            logDebug && logDebug("Ambient:Error", e);
        });
    }, [logDebug]);

    const stopAmbientMusic = useCallback(() => {
        if (ambientAudioRef.current) {
            ambientAudioRef.current.pause();
        }
    }, []);

    const stopAmbientMusicAndReset = useCallback(() => {
        if (ambientAudioRef.current) {
            ambientAudioRef.current.pause();
            ambientAudioRef.current.currentTime = 0;
            ambientAudioRef.current = null;
        }
    }, []);

    // ---------------------------------------------------------
    // 3. TTS Engines (Cloud & Local)
    // ---------------------------------------------------------
    const stopVoiceOnly = useCallback(() => {
        if (window.speechSynthesis) window.speechSynthesis.cancel();
        if (currentAudioRef.current) {
            try { currentAudioRef.current.pause(); currentAudioRef.current.currentTime = 0; } catch { /* ignore */ }
            currentAudioRef.current = null;
        }
    }, []);

    const playAudio = useCallback((base64String, customVolume, onEndedCallback) => {
        if (!ttcEnabled || !base64String) return null;
        
        try {
            stopVoiceOnly();
            
            const audio = new Audio(`data:audio/mp3;base64,${base64String}`);
            audio.volume = customVolume !== undefined ? customVolume : (soundEnabled ? audioVolumes.voice : 0);
            currentAudioRef.current = audio;

            setTtsState && setTtsState({ isSpeaking: true, engine: 'Cloud TTS', volume: audio.volume });
            logDebug && logDebug("PlayAudio:Start", { vol: volume });

            audio.onended = () => { 
                logDebug && logDebug("PlayAudio:Ended");
                setTtsState && setTtsState(prev => ({ ...prev, isSpeaking: false }));
                if (currentAudioRef.current === audio) currentAudioRef.current = null;
                if (onEndedCallback) onEndedCallback();
            };
            
            const playPromise = audio.play();
            if (playPromise !== undefined) {
                playPromise.catch(e => {
                    console.error("🔊 Audio Playback Failed:", e);
                    logDebug && logDebug("PlayAudio:Error", e);
                    setTtsState && setTtsState(prev => ({ ...prev, isSpeaking: false }));
                });
            }
            
            // [FIX] More robust race condition check to ensure audio isn't prematurely paused
            // Only pause if we are explicitly IN a session and the user has actively hit pause.
            if (step === 'session' && isPlayingRef && isPlayingRef.current === false) {
                audio.pause();
                currentAudioRef.current = null;
            }
            
            return audio;
        } catch (e) {
            console.error("🔊 Audio Error:", e);
            logDebug && logDebug("PlayAudio:Catch", e);
            setTtsState && setTtsState(prev => ({ ...prev, isSpeaking: false }));
            return null;
        }
    }, [ttcEnabled, stopVoiceOnly, setTtsState, logDebug, isPlayingRef, step]);

    const speak = useCallback((text) => {
        logDebug && logDebug("Speak:Start", text);
        console.log("🗣️ [TTS Check] Speaking:", text);
        if (!text || typeof window === 'undefined' || !ttcEnabled || !window.speechSynthesis) return;
        
        stopVoiceOnly(); 
        
        const utterance = new SpeechSynthesisUtterance(text);
        utterance.lang = 'ko-KR';
        utterance.rate = 0.9;
        utterance.pitch = 1.0;
        utterance.volume = 0.8;

        utterance.onstart = () => setTtsState && setTtsState({ isSpeaking: true, engine: 'Local TTS', volume: 0.8 });
        utterance.onend = () => setTtsState && setTtsState(prev => ({ ...prev, isSpeaking: false }));
        utterance.onerror = () => setTtsState && setTtsState(prev => ({ ...prev, isSpeaking: false }));
        
        setTimeout(() => {
            if (window.speechSynthesis && ttcEnabled && (step !== 'session' || isPlayingRef.current)) {
                window.speechSynthesis.speak(utterance);
            }
        }, 100);
    }, [ttcEnabled, step, stopVoiceOnly, logDebug, setTtsState, isPlayingRef]);

    const speakFallback = useCallback((text) => {
        if (!text || typeof window === 'undefined' || !ttcEnabled || !window.speechSynthesis) return;
        
        logDebug && logDebug("SpeakFallback", text);
        stopVoiceOnly();

        const utterance = new SpeechSynthesisUtterance(text);
        utterance.lang = 'ko-KR';
        utterance.rate = 0.9;
        utterance.pitch = 1.0; 
        utterance.volume = 0.8; 
        
        setTimeout(() => {
            if (window.speechSynthesis && ttcEnabled) {
                window.speechSynthesis.speak(utterance);
            }
        }, 100);
    }, [ttcEnabled, stopVoiceOnly, logDebug]);

    // ---------------------------------------------------------
    // 4. Global Cleanup
    // ---------------------------------------------------------
    const stopAllAudio = useCallback((stopAmbient = false) => {
        stopVoiceOnly();
        
        if (stopAmbient) stopAmbientMusic();
        
        stopBinauralBeats();
        
        logDebug && logDebug("StopAllAudio", { stopAmbient });
    }, [stopVoiceOnly, stopAmbientMusic, stopBinauralBeats, logDebug]);

    // Cleanup AudioContext on unmount
    useEffect(() => {
        return () => {
            if (audioContextRef.current) {
                audioContextRef.current.close().catch(e => console.error(e));
                audioContextRef.current = null;
            }
        };
    }, []);

    // Provide raw refs to caller if needed
    return {
        audioContextRef,
        ambientAudioRef,
        currentAudioRef,
        
        getAudioContext,
        playBinauralBeats,
        stopBinauralBeats,
        updateBinauralVolume,
        playAmbientMusic,
        stopAmbientMusic,
        stopAmbientMusicAndReset,
        updateAmbientVolume,
        playAudio,
        speak,
        speakFallback,
        stopVoiceOnly,
        stopAllAudio
    };
};

import { useMemo } from 'react';
import { getHolidayName } from '../utils/holidays';

export const useRevenueStats = (sales, members, currentDate, currentBranch, revenueStats) => {
    return useMemo(() => {
        const year = currentDate.getFullYear();
        const month = currentDate.getMonth() + 1;
        const monthStr = `${year}-${String(month).padStart(2, '0')}`;

        const allItems = [];
        const salesKeySet = new Set(); // Format: `${memberId}_${date}`
        const seenSalesKeys = new Set(); // Format: `${memberId}_${date}_${amount}`
        const memberIdsWithRegisterSales = new Set(); // [FIX] Members with primary sales records
        const memberNameMap = new Map();
        
        (members || []).forEach(m => memberNameMap.set(m.name, m.id));

        // 1. Process New Sales Data First (Primary Source)
        (sales || []).forEach(s => {
            const resolvedMemberId = s.memberId || memberNameMap.get(s.memberName);
            const member = (members || []).find(m => m.id === resolvedMemberId);
            const saleBranch = s.branchId;
            const memberBranch = member?.homeBranch;

            if (currentBranch !== 'all') {
                // If branch filter applied, check saleBranch FIRST, then memberBranch
                const matchFound = (saleBranch && saleBranch === currentBranch) || 
                                   (!saleBranch && memberBranch && memberBranch === currentBranch);
                if (!matchFound) return;
            }

            // [FIX] Robust date extraction handling both string and Firestore Timestamp
            let dateStr;
            const rawDate = s.date || s.timestamp;
            
            if (!rawDate) {
                console.warn('[Revenue] Sales record missing both date and timestamp:', s.id, s.memberName);
                return;
            }
            
            if (typeof rawDate === 'string' && rawDate.includes('T')) {
                const d = new Date(rawDate);
                dateStr = d.toLocaleDateString('sv-SE', { timeZone: 'Asia/Seoul' });
            } else if (typeof rawDate === 'object' && rawDate.toDate) {
                // Handle Firestore Timestamp just in case
                dateStr = rawDate.toDate().toLocaleDateString('sv-SE', { timeZone: 'Asia/Seoul' });
            } else {
                dateStr = String(rawDate); // Fallback string conversion
            }

            // Determine isNew
            let isNew = false;
            if (s.type === 'extend') {
                isNew = false;
            } else if (s.type === 'register' || !s.type) {
                // [FIX] Assume 'register' if type is missing and it matches registration date
                if (member && member.regDate === dateStr) {
                    isNew = true;
                } else {
                    isNew = false;
                }
            }

            const rawAmount = Number(s.amount) || 0;

            // Self Deduplication to match useAdminData.js
            if (resolvedMemberId) {
                const uniqueSaleKey = `${resolvedMemberId}_${dateStr}_${rawAmount}`;
                if (seenSalesKeys.has(uniqueSaleKey)) {
                    return; // Drop duplicate
                }
                seenSalesKeys.add(uniqueSaleKey);
                
                // Track register sales to prevent legacy fallback duplicate
                if (s.type === 'register' || s.type === 'legacy' || (!s.type && isNew)) {
                    memberIdsWithRegisterSales.add(resolvedMemberId);
                }
            }

            allItems.push({
                id: s.id,
                memberId: resolvedMemberId,
                date: dateStr,
                amount: rawAmount,
                name: s.memberName,
                type: s.type || 'register', // Fallback type
                item: s.item,
                isNew: isNew
            });

            // Add to dedup set
            if (resolvedMemberId) {
                salesKeySet.add(`${resolvedMemberId}_${dateStr}`);
            }
        });

        // 2. Process Legacy Members Data (Secondary Source)
        // Performance Improvement: Use a Map for O(1) lookups instead of filtering `finalItems` later
        const legacyMemberData = new Map();

        (members || []).forEach(m => {
            const amt = Number(m.amount) || 0;
            if (m.regDate && amt > 0) {
                // Basic validation for reasonable date structure before keeping it
                if (typeof m.regDate !== 'string' || m.regDate.length < 10) return;

                if (currentBranch !== 'all' && m.homeBranch !== currentBranch) return;

                // [FIX] Deduplication Check: Ignore if a register sales record exists for this member
                if (memberIdsWithRegisterSales.has(m.id)) return;
                // Double fallback using legacy matching (just in case they have multiple)
                if (salesKeySet.has(`${m.id}_${m.regDate}`)) return;

                legacyMemberData.set(m.id, {
                    id: m.id,
                    memberId: m.id,
                    date: m.regDate,
                    amount: amt,
                    name: m.name,
                    type: 'legacy',
                    item: m.subject || '수강권',
                    isNew: true 
                });
            }
        });

        const finalItems = [...allItems, ...Array.from(legacyMemberData.values())];
        finalItems.sort((a, b) => new Date(b.date) - new Date(a.date));

        // [Debug] Log Revenue Data
        // console.log('Revenue Debug:', {
        //     totalItems: finalItems.length,
        //     sampleItems: finalItems.slice(0, 5)
        // });

        // Optimization: Use a Map to grouping daily amounts for O(1) lookups
        const dailyAmountsMap = new Map();
        finalItems.forEach(item => {
            const currentObj = dailyAmountsMap.get(item.date) || { 
                amount: 0, count: 0, amountNew: 0, amountReReg: 0, amountNewCount: 0, amountReRegCount: 0, salesList: [] 
            };
            
            currentObj.amount += item.amount;
            currentObj.count += 1;
            currentObj.salesList.push(item);
            
            if (item.isNew) {
                currentObj.amountNew += item.amount;
                currentObj.amountNewCount += 1;
            } else {
                currentObj.amountReReg += item.amount;
                currentObj.amountReRegCount += 1;
            }
            
            dailyAmountsMap.set(item.date, currentObj);
        });

        // 2. Monthly Stats (for Calendar)
        const daily = {};
        const daysInMonth = new Date(year, month, 0).getDate();
        
        // Simple mapping for display
        const holidayMap = {
            'holiday_new_year': '신정',
            'holiday_lunar_new_year': '설날',
            'holiday_samiljeol': '삼일절',
            'holiday_childrens_day': '어린이날',
            'holiday_buddha': '석가탄신일',
            'holiday_memorial': '현충일',
            'holiday_liberation': '광복절',
            'holiday_chuseok': '추석',
            'holiday_foundation': '개천절',
            'holiday_hangul': '한글날',
            'holiday_christmas': '크리스', // Shortened for space
            'holiday_election': '선거일'
        };

        let monthlyTotal = 0;
        let monthlyNew = 0;
        let monthlyReReg = 0;
        let monthlyCount = 0;

        for (let d = 1; d <= daysInMonth; d++) {
            const dKey = `${monthStr}-${String(d).padStart(2, '0')}`;
            const dateObj = new Date(year, month - 1, d);
            const dayOfWeek = dateObj.getDay(); // 0=Sun
            const holidayRaw = getHolidayName(dKey);
            
            // Fetch aggregated data from map (O(1) instead of filter loop)
            const dayData = dailyAmountsMap.get(dKey) || { 
                amount: 0, count: 0, amountNew: 0, amountReReg: 0, amountNewCount: 0, amountReRegCount: 0, salesList: [] 
            };

            daily[dKey] = {
                date: dKey,
                amount: dayData.amount,
                count: dayData.count,
                amountNew: dayData.amountNew,
                amountReReg: dayData.amountReReg,
                amountNewCount: dayData.amountNewCount,
                amountReRegCount: dayData.amountReRegCount,
                salesList: dayData.salesList,
                isSunday: dayOfWeek === 0,
                isSaturday: dayOfWeek === 6,
                holidayName: holidayRaw ? (holidayMap[holidayRaw] || '공휴일') : null
            };
            
            monthlyTotal += dayData.amount;
            monthlyNew += dayData.amountNew;
            monthlyReReg += dayData.amountReReg;
            monthlyCount += dayData.count;
        }

        // Overwrite totals securely with Server Stats if looking at all branches
        if (revenueStats && currentBranch === 'all') {
            monthlyTotal = revenueStats.monthly?.[monthStr]?.total || 0;
            monthlyNew = revenueStats.monthly?.[monthStr]?.new || 0;
            monthlyReReg = revenueStats.monthly?.[monthStr]?.reReg || 0;
            // monthlyCount relies on the 500 recent items which cover current month completely
        }


        // 3. Comparative Stats (Yesterday, Day Before, Last Week)
        const today = new Date();
        const getOffsetDateString = (offsetDays) => {
            const d = new Date(today);
            d.setDate(today.getDate() - offsetDays);
            return d.toLocaleDateString('sv-SE');
        }

        const todayStr = getOffsetDateString(0);
        const yesterdayStr = getOffsetDateString(1);
        const dayBeforeStr = getOffsetDateString(2);
        const lastWeekStr = getOffsetDateString(7);

        const getDailyTotalOptimized = (dStr) => dailyAmountsMap.get(dStr)?.amount || 0;

        const statYesterday = getDailyTotalOptimized(yesterdayStr);
        const statDayBefore = getDailyTotalOptimized(dayBeforeStr);
        const statToday = getDailyTotalOptimized(todayStr); 
        const statLastWeekStr = getDailyTotalOptimized(lastWeekStr);


        // 4. Trend Graph (Last 14 Days)
        const trendData = [];
        for (let i = 13; i >= 0; i--) {
            const d = new Date(today);
            d.setDate(today.getDate() - i);
            const dStr = d.toLocaleDateString('sv-SE');
            trendData.push({
                date: dStr,
                displayDate: `${d.getMonth() + 1}/${d.getDate()}`,
                amount: getDailyTotalOptimized(dStr)
            });
        }

        // 5. Monthly Trend (Last 6 Months)
        const monthlyTrendData = [];
        const currentDayOfM = currentDate.getDate(); // 1~31

        for (let i = 5; i >= 0; i--) {
            const d = new Date(year, month - 1 - i, 1);
            const mStr = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
            const label = `${d.getMonth() + 1}월`;
            
            let amount = 0;
            let partialAmount = 0;

            if (revenueStats && currentBranch === 'all') {
                amount = revenueStats.monthly?.[mStr]?.total || 0;
                for (let day = 1; day <= currentDayOfM; day++) {
                    const dayStr = `${mStr}-${String(day).padStart(2, '0')}`;
                    partialAmount += revenueStats.daily?.[dayStr]?.total || 0;
                }
            } else {
                dailyAmountsMap.forEach((val, key) => {
                    if (key.startsWith(mStr)) {
                        amount += val.amount;
                        const dayPart = parseInt(key.substring(8, 10), 10);
                        if (dayPart <= currentDayOfM) {
                            partialAmount += val.amount;
                        }
                    }
                });
            }

            monthlyTrendData.push({
                name: label,
                monthParams: mStr, 
                amount: amount,
                partialAmount: partialAmount
            });
        }

        return {
            dailyStats: Object.values(daily),
            monthlyStats: {
                totalRevenue: monthlyTotal,
                totalRevenueNew: monthlyNew,
                totalRevenueReReg: monthlyReReg,
                totalCount: monthlyCount
            },
            comparativeStats: {
                yesterday: statYesterday,
                dayBefore: statDayBefore,
                today: statToday
            },
            recentTrend: trendData,
            monthlyTrend: monthlyTrendData
        };

    }, [members, sales, currentDate, currentBranch, revenueStats]);
};

import { useCallback } from 'react';

// [AUDIO] High-quality TTS assets
import audioWelcome from '../assets/audio/welcome.mp3';
import audioSuccess from '../assets/audio/success.mp3';
import audioDuplicateSuccess from '../assets/audio/duplicate_success.mp3';
import audioSuccessConsecutive from '../assets/audio/success_consecutive.mp3';
import audioSuccessExtra from '../assets/audio/success_extra.mp3';
import audioDenied from '../assets/audio/denied.mp3';
import audioError from '../assets/audio/error.mp3';
import audioLastSession from '../assets/audio/last_session.mp3';

let currentAudio = null;
let currentTimeout = null;

export const useTTS = () => {
    // [TTS] Voice Feedback Helper
    const speak = useCallback((type) => {
        const audioMap = {
            'welcome': audioWelcome,
            'success': audioSuccess,
            'success_consecutive': audioSuccessConsecutive, // [NEW] 연강 출석입니다
            'success_extra': audioSuccessExtra,             // [NEW] 추가 출석입니다
            'duplicate': audioSuccessExtra,                 // [FIX] 중복 출석 안내 오디오 매핑 교체
            'denied': audioDenied,
            'error': audioError,
            'last_session': audioSuccess
        };

        const source = audioMap[type];

        if (!source) {
            console.warn(`[TTS] No audio mapping for type: ${type}`);
            return;
        }

        try {
            // [UX] 하드웨어 스피커(블루투스 등) 슬립 모드 깨우기 (Wake-up)
            // 브라우저의 TTS 엔진을 이용해 아주 짧은 무음을 재생하여 앰프를 켭니다.
            if ('speechSynthesis' in window) {
                const wakeUp = new SpeechSynthesisUtterance('');
                wakeUp.volume = 0.01;
                wakeUp.rate = 2.0;
                window.speechSynthesis.speak(wakeUp);
            }

            // [FIX] 기존 재생 중인 오디오와 대기 중인 타이머 취소 (겹침 방지)
            if (currentTimeout) {
                clearTimeout(currentTimeout);
                currentTimeout = null;
            }
            if (currentAudio) {
                currentAudio.pause();
                currentAudio.currentTime = 0;
            }

            // 대기 시간을 최소화하여 화면 팝업과 동시에 소리가 나도록 수정
            currentAudio = new Audio(source);
            currentTimeout = setTimeout(() => {
                if (currentAudio) {
                    currentAudio.play().catch(e => console.warn('[TTS] Playback failed', e));
                }
                currentTimeout = null;
            }, 50);
        } catch (e) {
            console.error('[TTS] Audio creation failed', e);
        }
    }, []);

    return { speak };
};

