import { getDaysRemaining, getKSTHour } from '../utils/dates';
import ImageLightbox from '../components/common/ImageLightbox';

// Safe localStorage wrapper with error handling
const safeSessionStorage = {
    getItem: (key) => {
        try {
            return localStorage.getItem(key);
        } catch (e) {
            console.warn('localStorage access denied:', e);
            return null;
        }
    },
    setItem: (key, value) => {
        try {
            localStorage.setItem(key, value);
        } catch (e) {
            console.warn('localStorage write denied:', e);
        }
    },
    removeItem: (key) => {
        try {
            localStorage.removeItem(key);
        } catch (e) {
            console.warn('localStorage remove denied:', e);
        }
    }
};

const MemberProfile = () => {
    const { config } = useStudioConfig();
    const [images, setImages] = useState({});

    // Derive dynamic assets with SaaS Core Fallback
    const logo = images.logo || config.ASSETS?.LOGO?.WIDE;
    const memberBg = images.memberBg || config.ASSETS?.MEMBER_BG;
    const timeTable1 = images.timeTable1 || config.ASSETS?.TIMETABLE?.BRANCH1;
    const timeTable2 = images.timeTable2 || config.ASSETS?.TIMETABLE?.BRANCH2;
    const priceTable1 = images.priceTable1 || config.ASSETS?.PRICETABLE?.BRANCH1;
    const priceTable2 = images.priceTable2 || config.ASSETS?.PRICETABLE?.BRANCH2;

    const [member, setMember] = useState(null);
    const [loading, setLoading] = useState(true);
    const { language, t } = useLanguage();

    const [langLabelIndex, setLangLabelIndex] = useState(0);
    const langLabels = ["언어", "Language", "Язык", "语言", "言語"];

    // [FIX] AI 중복 호출 방지용 Ref
    const lastAiExpArgs = useRef('');
    const lastAiAnalysisArgs = useRef('');

    // [REFACTOR] Member UI Hook
    const {
        activeTab, setActiveTab,
        selectedNoticeId, setSelectedNoticeId,
        scheduleView, setScheduleView,
        scheduleMonth, setScheduleMonth,
        scheduleBranch, setScheduleBranch,
        lightboxImage, setLightboxImage,
        greetingVisible, setGreetingVisible,
        modals, openConfirmModal, closeConfirmModal,
        openInstallGuide, closeInstallGuide,
        loginForm, setLoginFormValue, setLoginForm
    } = useMemberUI();

    // [Push] Auto Push Permission Request
    useEffect(() => {
        if (member && typeof window !== 'undefined' && 'Notification' in window) {
            if (window.Notification.permission === 'default') {
                const pushTimer = setTimeout(() => {
                    console.log("[Push Check] Auto-requesting push permission for member...");
                    // Try to request permission automatically
                    window.Notification.requestPermission().then(permission => {
                        setPushStatus(permission);
                        if (permission === 'granted') {
                            storageService.requestPushPermission(member.id).catch(err => console.warn(err));
                        }
                    });
                }, 3500); // UI 안정화 후 3.5초 뒤 띄움
                return () => clearTimeout(pushTimer);
            }
        }
    }, [member]);

    const handleNotificationToggle = async (e) => {
        if (e.target.checked) {
            try {
                const result = await storageService.reregisterPushToken(member.id);
                if (result.success) {
                    setPushStatus('granted');
                    alert('푸시 알림이 설정되었습니다.');
                } else {
                    throw new Error(result.message);
                }
            } catch (error) {
                console.error("Push registration failed", error);
                alert('알림 설정 실패: ' + error.message);
            }
        } else {
            if (window.confirm('푸시 알림을 끄시겠습니까? (브라우저 설정에서 차단해야 완벽하게 꺼집니다)')) {
                setPushStatus('denied');
            }
        }
    };

    useEffect(() => {
        const interval = setInterval(() => {
            setLangLabelIndex((prev) => (prev + 1) % langLabels.length);
        }, 3000);
        return () => clearInterval(interval);
    }, [langLabels.length]);

    // 🤖 AI Preloader (Background Task for Performance)
    useEffect(() => {
        const preloadAI = () => {
             // Only run if browser supports it, otherwise skip optimization
            if (typeof window !== 'undefined' && 'requestIdleCallback' in window) {
                window.requestIdleCallback(async () => {
                    // Wait 4s for initial render and animations to settle
                    await new Promise(r => setTimeout(r, 4000));
                    
                    try {
                        console.log("🧘 [Background] Preloading AI Engines...");
                        // Prefetch AI modules so they are ready when user clicks 'Meditation'
                        const modules = [
                            import('@mediapipe/pose'),
                            import('@tensorflow/tfjs-core'),
                            import('@tensorflow/tfjs-backend-webgl')
                        ];
                        await Promise.all(modules);
                        console.log("✨ [Background] AI Engines Cached & Ready");
                    } catch (e) {
                        console.debug("[Background] AI Preload deferred/failed", e);
                    }
                }, { timeout: 10000 });
            }
        };
        preloadAI();
    }, []);

    // [OPTIMIZED] Persist language preference ONLY when it actually changes
    useEffect(() => {
        if (member && member.id && member.language !== language) {
            console.log(`[Language] Updating member preference to: ${language}`);
            storageService.updateMember(member.id, { language: language });
        }

        // [FIX] Restore Anonymous Auth Session if missing
        // This ensures 'fcm_tokens' writes succeed even if the page was reloaded
        if (member && !auth.currentUser) {
            import("firebase/auth").then(({ signInAnonymously }) => {
                signInAnonymously(auth)
                    .then(() => {
                        console.log("[MemberProfile] Anonymous session restored for push tokens");
                        // Retry token sync if it might have failed earlier
                        if (Notification.permission === 'granted') {
                            storageService.requestPushPermission(member.id);
                        }
                    })
                    .catch(e => console.warn("[MemberProfile] Session restore failed:", e));
            });
        }

        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [language, member?.id, member?.language]);

    // [Deep Link] Parse 'tab' from URL to auto-navigate
    useEffect(() => {
        const handleLocationChange = () => {
            const params = new URLSearchParams(window.location.search);
            const tab = params.get('tab');
            const noticeId = params.get('noticeId');
            
            if (noticeId) {
                console.log(`[DeepLink] Specific notice requested: ${noticeId}`);
                setSelectedNoticeId(noticeId);
                setActiveTab('notices');
            } else if (tab && ['home', 'history', 'schedule', 'prices', 'notices', 'messages'].includes(tab)) {
                console.log(`[DeepLink] Navigating to tab: ${tab}`);
                setActiveTab(tab);
            }

            // [FIX] Clear the query param after use so browser reload returns to home
            // Use a short delay to ensure React state has processed it
            if (tab || noticeId) {
                setTimeout(() => {
                    const newUrl = window.location.pathname;
                    window.history.replaceState({}, '', newUrl);
                }, 500);
            }
        };

        // Initial check
        handleLocationChange();

        // Listen for history changes (replaceState doesn't trigger popstate, but our SW uses client.navigate)
        window.addEventListener('popstate', handleLocationChange);

        // [ENHANCEMENT] Special listener for deep links if app is already open
        const interval = setInterval(() => {
            if (window.location.search.includes('tab=')) {
                handleLocationChange();
            }
        }, 1000);

        return () => {
            window.removeEventListener('popstate', handleLocationChange);
            clearInterval(interval);
        };
    }, []);

    const [logs, setLogs] = useState([]);
    const [logLimit, setLogLimit] = useState(10);
    const [notices, setNotices] = useState([]);
    const [weatherData, setWeatherData] = useState(null); // Changed to object { key, temp }
    const [aiExperience, setAiExperience] = useState(null);
    const [aiAnalysis, setAiAnalysis] = useState(null);
    const [individualMessages, setIndividualMessages] = useState([]);
    const [messages, setMessages] = useState([]);

    const [pushStatus, setPushStatus] = useState(() => {
        if (typeof Notification === 'undefined') return 'default';
        if (Notification.permission === 'denied') return 'denied';
        if (Notification.permission === 'granted') return 'granted';
        return 'default';
    });

    // PWA Install State - Restored and updated
    const pwaCtx = useContext(PWAContext) || {};
    const { deferredPrompt, installApp, deviceOS } = pwaCtx;
    const isPwaStandalone = pwaCtx.isStandalone;

    // Destructure styles
    const { authInput: authInputStyle, authButton: authButtonStyle } = profileStyles;


    const loadMemberData = async (memberId) => {
        try {
            setLoading(true);

            // [PERFORMANCE] Parallel Data Loading
            const [memberData, history, noticeData, imagesData, messagesData] = await Promise.all([
                storageService.fetchMemberById(memberId),
                storageService.getAttendanceByMemberId(memberId),
                storageService.loadNotices(),
                storageService.getImages(),
                storageService.getMessagesByMemberId(memberId)
            ]);

            if (memberData) {
                // [FIX] Preserve displayName from existing state or storage if available
                setMember(prev => ({
                    ...memberData,
                    displayName: prev?.displayName || JSON.parse(safeSessionStorage.getItem('member') || '{}').displayName || memberData.name
                }));
                // [FIX] Sort history by timestamp descending (newest first)
                const sortedHistory = (history || []).sort((a, b) => {
                    const timeA = new Date(a.timestamp || a.date || 0).getTime();
                    const timeB = new Date(b.timestamp || b.date || 0).getTime();
                    return timeB - timeA;
                });
                setLogs(sortedHistory);
                setIndividualMessages(messagesData || []);

                // [FIX] Sort notices explicitly by timestamp/date descending (newest first)
                const sortedNotices = (noticeData || []).sort((a, b) => {
                    const dateA = new Date(a.timestamp || a.date || 0);
                    const dateB = new Date(b.timestamp || b.date || 0);
                    return dateB - dateA; // Descending (newest first)
                });
                setNotices(sortedNotices);

                setImages(imagesData || {});

                setScheduleBranch(memberData.homeBranch || 'gwangheungchang');
                fetchWeather();

                // [FIX] Filter out denied logs from AI analysis
                const validHistory = history.filter(h => h.status !== 'denied');

                if (!weatherData) {
                    loadAIExperience(memberData, validHistory);
                }

                const currentAnalysisArgs = `${memberData.name}_${validHistory.length}_${getKSTHour()}_${language}`;
                if (lastAiAnalysisArgs.current !== currentAnalysisArgs) {
                    lastAiAnalysisArgs.current = currentAnalysisArgs;
                    storageService.getAIAnalysis(memberData.name, validHistory.length, validHistory, getKSTHour(), language, 'member')
                        .then(analysis => setAiAnalysis(analysis))
                        .catch(() => setAiAnalysis({ message: t('analysisPending'), isError: true }));
                }

                // [Fix] Push Token Self-Healing: If permission already granted, re-sync with server
                // This recovers badges even if the fcm_tokens collection was wiped.
                if (Notification.permission === 'granted' || localStorage.getItem('push_enabled') === 'true') {
                    console.log("[Push Check] Syncing lost tokens for current device...");
                    storageService.requestPushPermission(memberId).catch(err => console.warn(err));
                    setPushStatus('granted');
                }
            } else {
                setLoginFormValue('error', t('errorMemberNotFound') || "회원 정보를 찾을 수 없습니다.");
                safeSessionStorage.removeItem('member');
            }
        } catch (e) {
            console.error("Load member failed:", e);
            setLoginFormValue('error', t('unknownError') || "알 수 없는 오류가 발생했습니다.");
        } finally {
            setLoading(false);
        }
    };

    // [REAL-TIME] Real-time Listener for Member and Attendance
    useEffect(() => {
        const savedMember = safeSessionStorage.getItem('member');
        if (!savedMember) return;
        const memberId = JSON.parse(savedMember).id;
        // v1.0.5 - Clean and verified


        const unsubMember = onSnapshot(doc(db, 'members', memberId), (snap) => {
            if (snap.exists()) {
                const data = { id: snap.id, ...snap.data() };
                console.log("[MemberProfile] Real-time member update received");
                setMember(data);
                safeSessionStorage.setItem('member', JSON.stringify(data));
            }
        });

        const q = query(
            collection(db, 'attendance'),
            where('memberId', '==', memberId),
            orderBy('timestamp', 'desc'),
            firestoreLimit(logLimit)
        );
        const unsubAttendance = onSnapshot(q, (snap) => {
            const history = snap.docs.map(doc => ({ id: doc.id, ...doc.data() }));
            console.log(`[MemberProfile] Real-time attendance update: ${history.length} records`);
            setLogs(history);
        });

        return () => {
            if (unsubMember) unsubMember();
            if (unsubAttendance) unsubAttendance();
        };
    }, [logLimit]);

    // [PERF] 메시지 리스너는 아래 useEffect(line ~445)에서 통합 관리
    // 중복 리스너 제거 — Firestore 연결 1개 절약

    const loadAIExperience = async (m, attendanceData = null, wData = null) => {
        if (!m) return;

        // [OPTIMIZATION] Check if we already have a specialized AI message (not fallback)
        // effectively prevents re-fetching just because weather loaded
        if (aiExperience && !aiExperience.isFallback) return;

        const now = new Date();
        const hour = getKSTHour();

        const days = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
        const day = days[now.getDay()];

        const validAttendance = attendanceData ? attendanceData.filter(l => l.status !== 'denied') : [];
        const currentArgs = `${m.id}_${validAttendance.length}_${day}_${hour}_${wData?.key || 'null'}_${language}`;
        
        if (lastAiExpArgs.current === currentArgs) return;
        lastAiExpArgs.current = currentArgs;

        try {
            // [FIX] Calculate diligence data for personalized AI
            const streak = attendanceData ? storageService.getMemberStreak(m.id, validAttendance) : 0;
            // [FIX] Use timestamp instead of date (which is typically undefined in attendance logs)
            const lastAtt = validAttendance.length > 0 ? (validAttendance[0].timestamp || validAttendance[0].date) : null;

            const exp = await storageService.getAIExperience(
                m.name,
                m.attendanceCount || validAttendance.length,
                day,
                hour,
                null, // upcoming class
                wData ? `${t('weather_' + wData.key)} (${wData.temp}°C)` : 'Sunny',
                m.credits || 0,
                getDaysRemaining(m.endDate),
                language,
                { streak, lastAttendanceAt: lastAtt }, // [FIX] Pass real diligence data
                'profile'
            );
            if (exp) {
                setAiExperience(exp);
                storageService.setGreetingCache(m.id, exp);
            }
        } catch (e) {
            console.error("AI load failed:", e);
            setAiExperience({
                message: getTraditionalYogaMessage(),
                bgTheme: 'sunny'
            });
        }
    };

    // [GENIUS ANIMATION] Trigger fade effect when AI message arrives
    useEffect(() => {
        if (aiExperience?.message) {
            setGreetingVisible(false);
            const timer = setTimeout(() => setGreetingVisible(true), 150);
            return () => clearTimeout(timer);
        }
    }, [aiExperience?.message]);

    useEffect(() => {
        const storedMember = safeSessionStorage.getItem('member');
        if (storedMember) {
            try {
                const m = JSON.parse(storedMember);
                const cachedGreeting = storageService.getGreetingCache(m.id);
                if (cachedGreeting) {
                    // Check if cache is still valid (e.g. within same hour)
                    // Simple check: if we have it, use it. Admin 'Data Insight' might need fresh, but Greeting is fine.
                    setAiExperience(cachedGreeting);
                }
                loadMemberData(m.id);
            } catch (e) {
                console.warn("Failed to parse stored member", e);
                setLoading(false);
            }
        } else {
            setLoading(false);
        }
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, []);

    useEffect(() => {
        // [Optimized] Agent checks moved to useState initialization for immediate feedback without flash.

        // handleBeforeInstallPrompt moved to Context

        const unsubscribe = storageService.subscribe(async () => {
            // [FIX] Sort notices explicitly by timestamp descending in real-time update
            const freshNotices = storageService.getNotices();
            setNotices([...freshNotices].sort((a, b) => new Date(b.timestamp || b.date || 0) - new Date(a.timestamp || a.date || 0)));

            const imgs = await storageService.getImages();
            setImages(imgs);
            if (member) {
                storageService.fetchMemberById(member.id).then(m => {
                    if (m) setMember(m);
                });
                storageService.getAttendanceByMemberId(member.id).then(h => {
                    const sortedH = [...h].sort((a, b) => new Date(b.timestamp || b.date || 0) - new Date(a.timestamp || a.date || 0));
                    setLogs(sortedH);
                });
            }
        });

        // [REAL-TIME] Dedicated Messages Listener
        let msgUnsub = () => { };
        if (member?.id) {
            console.log(`[MemberProfile] Setting up real-time message listener for: ${member.id}`);
            const q = query(
                collection(db, 'messages'),
                where('memberId', '==', member.id),
                orderBy('timestamp', 'desc'),
                firestoreLimit(30)
            );
            msgUnsub = onSnapshot(q, async (snap) => {
                const individualMsgs = snap.docs.map(doc => ({
                    id: doc.id,
                    ...doc.data(),
                    type: 'admin_individual'
                }));
                setIndividualMessages(individualMsgs);
            }, (err) => {
                console.warn("[MemberProfile] Message listener failed (likely pending index):", err);
                storageService.getMessagesByMemberId(member.id).then(setIndividualMessages);
            });
        }

        return () => {
            // window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
            unsubscribe();
            msgUnsub();
        };
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [member?.id]);

    // [FIX] Update messages tab dynamically when either personal messages or global notices change
    useEffect(() => {
        const noticeMessages = notices.slice(0, 10).map(n => ({
            ...n,
            type: 'notice',
            content: n.content,
            timestamp: n.timestamp || n.date
        }));

        const allMessages = [...individualMessages, ...noticeMessages].sort((a, b) => {
            const timeA = new Date(a.timestamp || 0).getTime();
            const timeB = new Date(b.timestamp || 0).getTime();
            return timeB - timeA;
        });

        setMessages(allMessages);
    }, [individualMessages, notices]);

    // async function loadPracticeEvents(memberId) {
    //     try {
    //         const events = await storageService.getPracticeEvents(memberId, 5);
    //         setPracticeEvents(events);
    //     } catch (e) {
    //         console.error('Failed to load practice events:', e);
    //     }
    // }

    async function fetchWeather() {
        try {
            const res = await fetch('https://api.open-meteo.com/v1/forecast?latitude=37.5665&longitude=126.9780&current_weather=true');
            const data = await res.json();
            const weatherCode = data.current_weather.weathercode;

            let weatherKey = 'clear';
            if (weatherCode >= 1 && weatherCode <= 3) weatherKey = 'partly_cloudy';
            if (weatherCode > 3) weatherKey = 'cloudy';
            if (weatherCode >= 45 && weatherCode <= 48) weatherKey = 'fog';
            if (weatherCode >= 51 && weatherCode <= 67) weatherKey = 'rain';
            if (weatherCode >= 71 && weatherCode <= 77) weatherKey = 'snow';
            if (weatherCode >= 95) weatherKey = 'thunderstorm';

            const wData = { key: weatherKey, temp: data.current_weather.temperature };
            setWeatherData(wData);

            if (member) {
                // [FIX] Filter out denied logs
                const validLogs = logs.filter(l => l.status !== 'denied');
                loadAIExperience(member, validLogs, wData);
            }
        } catch (err) {
            console.log('Weather fetch failed', err);
            if (member) {
                const validLogs = logs.filter(l => l.status !== 'denied');
                loadAIExperience(member, validLogs, null);
            }
        }
    }

    async function handleLogin(e) {
        e.preventDefault();
        const trimmedName = loginForm.name.trim();
        const trimmedPhone = loginForm.phone.trim();

        if (!trimmedName || trimmedPhone.length < 4) {
            setLoginFormValue('error', t('inputError'));
            return;
        }

        setLoading(true);
        try {
            const result = await storageService.loginMember(trimmedName, trimmedPhone);
            if (result.success) {
                // [FIX] Use the returned displayName (input name) for UI consistency
                const memberWithDisplay = { 
                    ...result.member,
                    displayName: result.member.displayName || result.member.name 
                };
                safeSessionStorage.setItem('member', JSON.stringify(memberWithDisplay));
                
                // Update local state immediately with displayName
                setMember(memberWithDisplay);
                
                // Load fresh data (this might overwrite member, so we need to merge carefully in loadMemberData or just rely on state)
                loadMemberData(result.member.id);

                // [Fix] Reset token on every login to ensure delivery
                storageService.requestPushPermission(result.member.id).catch(err => console.warn(err));
            } else {
                setLoginFormValue('error', result.message);
                setLoading(false);
            }
        } catch (err) {
            console.error(err);
            setLoginFormValue('error', t('loginFailed') || "로그인 실패");
            setLoading(false);
        }
    }

    const handleLogout = () => {
        if (window.confirm(t('logoutConfirm'))) {
            safeSessionStorage.removeItem('member');
            setMember(null);
            setLoginForm({ name: '', phone: '', error: '' });
        }
    };

    useEffect(() => {
        if (member) {
            setAiExperience(null);
            // [FIX] Filter out denied logs
            const validLogs = logs.filter(l => l.status !== 'denied');
            
            lastAiExpArgs.current = ''; // 강제 다시 업데이트
            loadAIExperience(member, validLogs, weatherData);

            setAiAnalysis(null);
            const currentAnalysisArgs = `${member.name}_${validLogs.length}_${getKSTHour()}_${language}`;
            lastAiAnalysisArgs.current = currentAnalysisArgs;
            storageService.getAIAnalysis(member.name, validLogs.length, validLogs, getKSTHour(), language, 'member')
                .then(analysis => setAiAnalysis(analysis))
                .catch(() => setAiAnalysis({ message: t('analysisPending'), isError: true }));

            if (notices.length > 0) {
                storageService.translateNotices(notices, language).then(translated => {
                    setNotices(translated);
                });
            }
        }
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [language]);

    const getTraditionalYogaMessage = () => {
        const now = new Date();
        const hour = getKSTHour();
        const month = now.getMonth() + 1;

        let timeMsg = "";
        if (hour >= 5 && hour < 9) timeMsg = t('trad_dawn');
        else if (hour >= 9 && hour < 12) timeMsg = t('trad_morning');
        else if (hour >= 12 && hour < 17) timeMsg = t('trad_afternoon');
        else if (hour >= 17 && hour < 21) timeMsg = t('trad_evening');
        else timeMsg = t('trad_night');

        let seasonMsg = "";
        if (month >= 3 && month <= 5) seasonMsg = t('season_spring');
        else if (month >= 6 && month <= 8) seasonMsg = t('season_summer');
        else if (month >= 9 && month <= 11) seasonMsg = t('season_autumn');
        else seasonMsg = t('season_winter');
        return timeMsg + seasonMsg;
    };



    if (loading) return (
        <div style={{ padding: '20px', minHeight: '100vh', background: '#08080A' }}>
             {/* Skeleton Header */}
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '30px', paddingTop: 'env(safe-area-inset-top)' }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
                     <div className="skeleton" style={{ width: '30px', height: '30px', borderRadius: '50%' }} />
                     <div className="skeleton" style={{ width: '100px', height: '24px' }} />
                </div>
                <div className="skeleton" style={{ width: '80px', height: '32px' }} />
            </div>

            {/* Skeleton Content */}
            <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
                <div className="skeleton" style={{ width: '100%', height: '180px', borderRadius: '20px' }} />
                <div className="skeleton" style={{ width: '100%', height: '100px', borderRadius: '20px' }} />
                <div className="skeleton" style={{ width: '100%', height: '100px', borderRadius: '20px' }} />
            </div>

             {/* Skeleton Bottom Nav */}
            <div style={{ position: 'fixed', bottom: 'calc(20px + env(safe-area-inset-bottom))', left: '20px', right: '20px', height: '75px', borderRadius: '25px', background: 'rgba(20,20,20,0.8)', border: '1px solid rgba(255,255,255,0.1)' }} />
        </div>
    );

    if (!member) {
        return (
            <div style={{
                minHeight: '100vh',
                position: 'relative',
                overflowX: 'hidden',
                overflowY: 'auto',
                background: '#000000',
                display: 'flex',
                flexDirection: 'column',
                alignItems: 'center',
                justifyContent: 'center',
                padding: '20px'
            }}>
                {/* Background layers identical to profile for seamless transition */}
                <div
                    style={{
                        position: 'fixed',
                        top: 0,
                        left: 0,
                        right: 0,
                        bottom: 0,
                        backgroundImage: `linear-gradient(rgba(0,0,0,0.7), rgba(0,0,0,0.8)), url(${config.ASSETS?.MEMBER_BG || ''})`,
                        backgroundSize: 'cover',
                        backgroundPosition: 'center',
                        zIndex: 1
                    }}
                />
                <div style={{ position: 'fixed', top: 0, left: 0, right: 0, bottom: 0, background: 'rgba(0,0,0,0.1)', zIndex: 4, pointerEvents: 'none' }} />

                <div style={{
                    position: 'relative',
                    zIndex: 10,
                    animation: 'slideUp 0.8s ease-out',
                    textAlign: 'center',
                    width: '100%',
                    maxWidth: '360px'
                }}>
                    <div style={{ marginBottom: '40px' }}>
                        <img src={config.ASSETS?.LOGO?.WIDE} alt={config.IDENTITY?.NAME || 'Studio'} style={{ width: '85px', height: 'auto', opacity: 0.9, filter: 'brightness(0) invert(1) drop-shadow(0 0 15px rgba(255, 255, 255, 0.4))', marginBottom: '25px' }} />
                        <h2 style={{ fontSize: '1.4rem', fontWeight: '800', marginBottom: '10px', color: 'var(--primary-gold)' }}>{t('loginTitle')}</h2>
                        <p style={{ fontSize: '0.95rem', color: 'rgba(255,255,255,0.7)', lineHeight: '1.6', wordBreak: 'keep-all' }}>
                            {t('loginWelcome')}<br />
                            {t('loginSub')}
                        </p>
                    </div>
                    <form onSubmit={handleLogin} style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>

                        {/* Language Selector in Login (Unified Style) */}
                        <div style={{ display: 'flex', justifyContent: 'center', marginBottom: '15px' }}>
                            <div style={{
                                display: 'flex',
                                alignItems: 'center',
                                padding: '4px 8px'
                            }}>
                                <span key={langLabelIndex} style={{
                                    fontSize: '0.8rem',
                                    color: 'rgba(255,255,255,0.7)',
                                    marginRight: '8px',
                                    marginLeft: '4px',
                                    minWidth: '40px',
                                    textAlign: 'right',
                                    animation: 'fadeIn 0.5s ease-out'
                                }}>
                                    {langLabels[langLabelIndex]}
                                </span>
                                <div style={{ minWidth: '80px' }}>
                                    <LanguageSelector variant="minimal" />
                                </div>
                            </div>
                        </div>

                        <div style={{ textAlign: 'left', marginBottom: '4px' }}>
                            <label style={{ fontSize: '0.8rem', color: 'rgba(255,255,255,0.5)', marginLeft: '12px' }}>{t('nameLabel')}</label>
                            <input style={{ ...authInputStyle, marginTop: '4px' }} placeholder={t('namePlaceholder')} value={loginForm.name} onChange={e => setLoginFormValue('name', e.target.value)} lang="ko" type="text" inputMode="text" autoComplete="name" spellCheck="false" enterKeyHint="next" />
                        </div>
                        <div style={{ textAlign: 'left', marginBottom: '8px' }}>
                            <label style={{ fontSize: '0.8rem', color: 'rgba(255,255,255,0.5)', marginLeft: '12px' }}>{t('phoneLabel')}</label>
                            <input style={{ ...authInputStyle, marginTop: '4px' }} placeholder={t('phonePlaceholder')} value={loginForm.phone} onChange={e => setLoginFormValue('phone', e.target.value)} maxLength={4} type="tel" inputMode="numeric" pattern="[0-9]*" autoComplete="tel-local-suffix" enterKeyHint="go" />
                        </div>
                        {loginForm.error && <p style={{ color: 'var(--accent-error)', fontSize: '0.9rem', marginBottom: '10px' }}>{loginForm.error}</p>}
                        <button type="submit" disabled={loading} style={{ ...authButtonStyle, marginTop: '10px' }}>{t('checkRecordBtn')}</button>
                    </form>
                    <p style={{ marginTop: '30px', fontSize: '0.8rem', color: 'rgba(255,255,255,0.4)' }}>
                        {t('loginFooter')}
                    </p>
                </div>
            </div>
        );
    }



    // [FIX] Filter out denied logs for Statistics & AI (keep 'logs' for History)
    const validLogs = logs.filter(log => log.status !== 'denied');

    const daysRemaining = getDaysRemaining(member.endDate);

    return (
        <div className="member-profile-wrapper" style={{
            minHeight: '100dvh',
            position: 'relative',
            overflowX: 'hidden',
            overflowY: 'auto',
            background: '#000000' // Pure Black Base
        }}>
            {/* 1. Base Background Layer - Always visible for consistency */}
            <div
                className="profile-bg"
                style={{
                    position: 'fixed',
                    top: 0,
                    left: 0,
                    right: 0,
                    bottom: 0,
                    backgroundImage: `linear-gradient(rgba(0,0,0,0.7), rgba(0,0,0,0.8)), url(${memberBg})`,
                    backgroundSize: 'cover',
                    backgroundPosition: 'center',
                    zIndex: 1,
                    opacity: 1
                }}
            />

            {/* 2. Overlays (z-index: 3-4) */}
            <div className="bg-aura" style={{ position: 'fixed', zIndex: 3, pointerEvents: 'none' }} />
            {(() => {
                // [VISUALIZATION] Determine Particle Mode based on user activity (VALID logs only)
                let mode = 'calm';
                if (validLogs && validLogs.length > 0) {
                    const lastLog = validLogs[0];
                    const lastDate = new Date(lastLog.timestamp || lastLog.date);
                    const daysSinceLast = (new Date() - lastDate) / (1000 * 60 * 60 * 24);

                    if (daysSinceLast > 14) {
                        mode = 'stillness'; // Dormant
                    } else {
                        // Check for high activity (Burning)
                        // Simple check: 3+ valid logs in last 7 days OR total valid logs >= 8
                        const oneWeekAgo = new Date();
                        oneWeekAgo.setDate(oneWeekAgo.getDate() - 7);
                        const recentLogs = validLogs.filter(l => new Date(l.timestamp || l.date) > oneWeekAgo);

                        if (recentLogs.length >= 3 || validLogs.length >= 8) {
                            mode = 'burning';
                        }
                    }
                } else if (member && member.regDate) {
                    // New member check
                    const regDate = new Date(member.regDate);
                    const daysSinceReg = (new Date() - regDate) / (1000 * 60 * 60 * 24);
                    if (daysSinceReg > 14) mode = 'stillness';
                }

                return <InteractiveParticles mode={mode} />;
            })()}
            <div className="profile-overlay" style={{ background: 'rgba(0,0,0,0.1)', position: 'fixed', top: 0, left: 0, right: 0, bottom: 0, zIndex: 4 }} />

            {/* 3. Content Container (z-index: 10 - Must be higher than overlays) */}
            <div className="profile-container" style={{ paddingBottom: 'calc(130px + env(safe-area-inset-bottom))', position: 'relative', zIndex: 10 }}>
                {/* Header */}
                <ProfileHeader
                    logo={logo}
                    studioName={config.IDENTITY?.NAME}
                    langLabelIndex={langLabelIndex}
                    langLabels={langLabels}
                    t={t}
                    logout={handleLogout}
                />

                {/* Main Tabs Content */}
                <div className="tabs-content" style={{ padding: '0 10px' }}>

                    {/* HOME TAB */}
                    {activeTab === 'home' && (
                        <div className="fade-in">


                            <div className="glass-panel" style={{ padding: '24px', marginBottom: '20px', background: 'rgba(20, 20, 20, 0.9)', border: '1px solid rgba(255,255,255,0.15)' }}>
                                <MembershipInfo member={member} daysRemaining={daysRemaining} t={t} />

                                {/* [New] Personal Yoga Journey Chart - Valid Logs Only */}
                                <MyStatsChart logs={validLogs} />

                                <AISection
                                    aiExperience={aiExperience}
                                    weatherData={weatherData}
                                    greetingVisible={greetingVisible}
                                    t={t}
                                    getTraditionalYogaMessage={getTraditionalYogaMessage}
                                />

                                <HomeYogaSection language={language} t={t} />

                                <RecentAttendance
                                    logs={validLogs}
                                    language={language}
                                    t={t}
                                    setActiveTab={setActiveTab}
                                />

                                <div className="glass-panel" style={{
                                    padding: '25px 30px',
                                    background: 'linear-gradient(145deg, rgba(25, 25, 25, 0.9), rgba(15, 15, 15, 0.95))',
                                    marginBottom: '20px',
                                    borderRadius: '24px',
                                    border: '1px solid rgba(255, 255, 255, 0.08)',
                                    display: 'flex',
                                    justifyContent: 'space-between',
                                    alignItems: 'center',
                                    boxShadow: '0 8px 32px rgba(0, 0, 0, 0.3)'
                                }}>
                                    <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
                                        <div style={{
                                            width: '44px',
                                            height: '44px',
                                            borderRadius: '50%',
                                            background: pushStatus === 'granted' ? 'rgba(212, 175, 55, 0.15)' : 'rgba(255, 255, 255, 0.05)',
                                            display: 'flex',
                                            alignItems: 'center',
                                            justifyContent: 'center',
                                            border: `1px solid ${pushStatus === 'granted' ? 'rgba(212, 175, 55, 0.3)' : 'rgba(255, 255, 255, 0.1)'}`,
                                            transition: 'all 0.3s ease'
                                        }}>
                                            {pushStatus === 'granted' ? (
                                                <BellRinging size={22} weight="fill" color="var(--primary-gold)" />
                                            ) : (
                                                <BellSlash size={22} color="rgba(255,255,255,0.4)" />
                                            )}
                                        </div>
                                        <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
                                            <span style={{ fontSize: '1rem', fontWeight: 600, color: 'white' }}>
                                                푸시 알림
                                            </span>
                                            <span style={{ fontSize: '0.85rem', color: pushStatus === 'granted' ? 'var(--primary-gold)' : 'rgba(255,255,255,0.4)', transition: 'color 0.3s' }}>
                                                {pushStatus === 'granted' ? '알림이 켜져 있습니다' : '알림이 꺼져 있습니다'}
                                            </span>
                                        </div>
                                    </div>
                                    
                                    <label className="premium-switch" style={{ position: 'relative', display: 'inline-block', width: '56px', height: '30px' }}>
                                        <input
                                            type="checkbox"
                                            checked={pushStatus === 'granted'}
                                            onChange={handleNotificationToggle}
                                            style={{ opacity: 0, width: 0, height: 0 }}
                                        />
                                        <span className="premium-slider-track" style={{
                                            position: 'absolute',
                                            cursor: 'pointer',
                                            top: 0, 
                                            left: 0,
                                            right: 0,
                                            bottom: 0,
                                            backgroundColor: pushStatus === 'granted' ? 'rgba(212, 175, 55, 0.2)' : 'rgba(255, 255, 255, 0.1)',
                                            transition: '0.4s',
                                            borderRadius: '34px',
                                            border: `1px solid ${pushStatus === 'granted' ? 'var(--primary-gold)' : 'rgba(255, 255, 255, 0.2)'}`
                                        }}>
                                            <span style={{
                                                position: 'absolute',
                                                content: '""',
                                                height: '22px',
                                                width: '22px',
                                                left: pushStatus === 'granted' ? '30px' : '4px',
                                                bottom: '3px',
                                                backgroundColor: pushStatus === 'granted' ? 'var(--primary-gold)' : 'rgba(255, 255, 255, 0.4)',
                                                transition: '0.4s cubic-bezier(0.4, 0.0, 0.2, 1)',
                                                borderRadius: '50%',
                                                boxShadow: '0 2px 4px rgba(0,0,0,0.2)'
                                            }}></span>
                                        </span>
                                    </label>
                                </div>

                                {/* [RESTORED] PWA Install Guide */}
                                {!isPwaStandalone && (deferredPrompt || deviceOS === 'ios') && (
                                    <div className="glass-panel" style={{
                                        padding: '20px 25px',
                                        background: deviceOS === 'ios' ? 'rgba(59, 130, 246, 0.1)' : 'rgba(212, 175, 55, 0.1)',
                                        marginBottom: '20px',
                                        borderRadius: '24px',
                                        border: deviceOS === 'ios' ? '1px solid rgba(59, 130, 246, 0.3)' : '1px solid rgba(212, 175, 55, 0.3)',
                                        display: 'flex',
                                        flexDirection: 'column',
                                        gap: '15px',
                                        boxShadow: '0 8px 32px rgba(0, 0, 0, 0.3)',
                                        animation: 'fadeIn 0.5s ease-out'
                                    }}>
                                        <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
                                            <div style={{
                                                width: '44px', height: '44px', borderRadius: '50%',
                                                background: deviceOS === 'ios' ? '#3B82F6' : 'var(--primary-gold)', 
                                                color: deviceOS === 'ios' ? 'white' : 'black',
                                                display: 'flex', alignItems: 'center', justifyContent: 'center'
                                            }}>
                                                {deviceOS === 'ios' ? <Share size={24} weight="bold" /> : <DownloadSimple size={24} weight="bold" />}
                                            </div>
                                            <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
                                                <span style={{ fontSize: '1rem', fontWeight: 600, color: 'white' }}>
                                                    {deviceOS === 'ios' ? '아이폰에 앱 설치하기' : '앱 설치하기'}
                                                </span>
                                                <span style={{ fontSize: '0.8rem', color: 'rgba(255,255,255,0.7)' }}>
                                                    {deviceOS === 'ios' ? '사파리(Safari)에서 홈 화면에 추가하세요' : '홈 화면에 추가하여 더 편리하게 이용하세요'}
                                                </span>
                                            </div>
                                        </div>

                                        {deviceOS === 'ios' ? (
                                            <div style={{ background: 'rgba(59, 130, 246, 0.15)', padding: '15px', borderRadius: '16px' }}>
                                                <div style={{ display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '10px', fontSize: '0.9rem', color: 'rgba(255,255,255,0.9)' }}>
                                                    <span style={{ background: '#3B82F6', color: 'white', width: '22px', height: '22px', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '0.8rem', fontWeight: 'bold' }}>1</span>
                                                    <span>하단 <Share size={18} weight="bold" style={{ verticalAlign: 'middle', margin: '0 2px' }} /> <strong>공유 버튼</strong> 클릭</span>
                                                </div>
                                                <div style={{ display: 'flex', alignItems: 'center', gap: '10px', fontSize: '0.9rem', color: 'rgba(255,255,255,0.9)' }}>
                                                    <span style={{ background: '#3B82F6', color: 'white', width: '22px', height: '22px', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '0.8rem', fontWeight: 'bold' }}>2</span>
                                                    <span><PlusSquare size={18} weight="bold" style={{ verticalAlign: 'middle', margin: '0 2px' }} /> <strong>홈 화면에 추가</strong> 선택</span>
                                                </div>
                                            </div>
                                        ) : (
                                            <button 
                                                onClick={installApp}
                                                style={{
                                                    background: 'var(--primary-gold)', color: 'black',
                                                    border: 'none', padding: '12px 18px', borderRadius: '14px',
                                                    fontWeight: 'bold', fontSize: '0.95rem', cursor: 'pointer',
                                                    width: '100%',
                                                    display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px'
                                                }}
                                            >
                                                <DownloadSimple size={20} weight="bold" /> 설치하기
                                            </button>
                                        )}
                                    </div>
                                )}

                                <SocialLinks t={t} />



                            </div>
                        </div>
                    )}

                    {/* HISTORY TAB - Uses ALL logs (includes denied) */}
                    {activeTab === 'history' && (
                        <div className="fade-in">
                            <AttendanceHistory
                                logs={logs}
                                member={member}
                                language={language}
                                t={t}
                                aiAnalysis={aiAnalysis}
                                logLimit={logLimit}
                                setLogLimit={setLogLimit}
                            />
                        </div>
                    )}

                    {/* SCHEDULE TAB - Uses Valid Logs Only */}
                    {activeTab === 'schedule' && (
                        <ScheduleTab 
                            t={t}
                            scheduleView={scheduleView}
                            setScheduleView={setScheduleView}
                            scheduleBranch={scheduleBranch}
                            setScheduleBranch={setScheduleBranch}
                            validLogs={validLogs}
                            scheduleMonth={scheduleMonth}
                            setScheduleMonth={setScheduleMonth}
                            images={images}
                            timeTable1={timeTable1}
                            timeTable2={timeTable2}
                            setLightboxImage={setLightboxImage}
                        />
                    )}

                    {/* MEDITATION TAB - Full Screen Overlay */}
                    {activeTab === 'meditation' && (
                         <div className="fade-in" style={{ 
                            position: 'fixed', 
                            top: 0, 
                            left: 0, 
                            width: '100%', 
                            height: '100%', 
                            zIndex: 10000, 
                            background: '#18181b' // Default dark bg to prevent transparency issues
                        }}>
                            <Suspense fallback={<div style={{ padding: '50px', color: 'rgba(255,255,255,0.5)', textAlign: 'center' }}>Loading Meditation AI...</div>}>
                                <MeditationPage onClose={() => setActiveTab('home')} />
                            </Suspense>
                        </div>
                    )}

                    {/* PRICES TAB */}
                    {activeTab === 'prices' && (
                        <PriceTab 
                            memberId={member.id}
                            member={member}
                            images={images}
                            priceTable1={priceTable1}
                            priceTable2={priceTable2}
                            setLightboxImage={setLightboxImage}
                        />
                    )}

                    {/* NOTICES TAB */}
                    {activeTab === 'notices' && (
                        <NoticeTab 
                            t={t}
                            notices={notices}
                            selectedNoticeId={selectedNoticeId}
                            setSelectedNoticeId={setSelectedNoticeId}
                            setLightboxImage={setLightboxImage}
                        />
                    )}

                    {/* MESSAGES TAB */}
                    {activeTab === 'messages' && (
                        <MessagesTab 
                            messages={messages} 
                            t={t} 
                            setActiveTab={(tab, noticeId) => {
                                setActiveTab(tab);
                                if (noticeId) setSelectedNoticeId(noticeId);
                            }} 
                        />
                    )}
                </div>
            </div> {/* End of profile-container */}

            {/* Bottom Navigation (Hidden in Meditation Mode) */}
            {activeTab !== 'meditation' && (
                <ProfileTabs activeTab={activeTab} setActiveTab={setActiveTab} t={t} />
            )}

            {/* Confirm/Alert Modal */}
            {modals.confirm.isOpen && (
                <CustomGlassModal
                    message={modals.confirm.message}
                    isConfirm={modals.confirm.isConfirm}
                    onConfirm={modals.confirm.onConfirm}
                    onCancel={closeConfirmModal}
                />
            )}

            {/* 이미지 라이트박스 모달 */}
            {lightboxImage && (
                <ImageLightbox src={lightboxImage} onClose={() => setLightboxImage(null)} />
            )}

            <InstallBanner onManualInstallClick={openInstallGuide} />
            <InstallGuideModal isOpen={modals.installGuide} onClose={closeInstallGuide} />
            
            <div style={{ padding: '40px 20px', textAlign: 'center', opacity: 0.1, fontSize: '0.6rem', color: 'white' }}>
                v1.0.5 | {config.IDENTITY?.NAME?.toLowerCase().replace(/\s/g, '-') || 'studio'}
            </div>
        </div>
    );
};

export default MemberProfile;

import { db, functions, app } from '../firebase';
import { collection, doc, query, where, orderBy, getDocs, getDoc, addDoc, updateDoc, deleteDoc, onSnapshot, limit as firestoreLimit, increment } from 'firebase/firestore';
import { getStorage, ref, deleteObject } from 'firebase/storage';
import { httpsCallable } from 'firebase/functions';
import { memberService } from './memberService';

// [NETWORK] Timeout wrapper for Cloud Function calls
const withTimeout = (promise, timeoutMs = 10000, errorMsg = '서버 응답 시간 초과') => {
  return Promise.race([
    promise,
    new Promise((_, reject) => setTimeout(() => reject(new Error(errorMsg)), timeoutMs))
  ]);
};

// --- Local Cache ---
let cachedAttendance = [];
let notifyCallback = () => {};
let attendanceListenerUnsubscribe = null; // [FIX] Declare missing variable
let deps = {
  getCurrentClass: async () => null,
  logError: async () => {} 
};

export const attendanceService = {
  setNotifyCallback(callback) {
    notifyCallback = callback;
  },

  setDependencies(dependencies) {
    deps = { ...deps, ...dependencies };
  },

  setupAttendanceListener() {
    console.log("[attendanceService] setupAttendanceListener called - optimized to avoid global onSnapshot read spikes.");
    try {
      if (attendanceListenerUnsubscribe) {
        console.log("[attendanceService] Cleaning up existing attendance listener...");
        attendanceListenerUnsubscribe();
      }
      attendanceListenerUnsubscribe = onSnapshot(
        query(collection(db, 'attendance'), orderBy("timestamp", "desc"), firestoreLimit(500)),
        (snapshot) => {
          cachedAttendance = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
          notifyCallback();
        },
        (error) => console.warn(`[attendanceService] Listener error:`, error)
      );
      return attendanceListenerUnsubscribe;
    } catch (e) {
      console.error(`[attendanceService] Failed to subscribe:`, e);
      return null;
    }
  },

  getAttendance() {
    return cachedAttendance;
  },

  async clearAllAttendance() {
    try {
      const { writeBatch } = await import('firebase/firestore');
      const snapshot = await getDocs(collection(db, 'attendance'));
      if (snapshot.empty) return { success: true, count: 0 };

      // [PHASE 3 AUDIT FIX] Bulk delete using batches (limit 500 per batch)
      const docs = snapshot.docs;
      const CHUNK_SIZE = 500;
      let deletedCount = 0;

      for (let i = 0; i < docs.length; i += CHUNK_SIZE) {
        const batch = writeBatch(db);
        const chunk = docs.slice(i, i + CHUNK_SIZE);
        chunk.forEach(d => batch.delete(d.ref));
        await batch.commit();
        deletedCount += chunk.length;
        console.log(`[attendanceService] Batch deleted ${deletedCount}/${docs.length} records...`);
      }

      cachedAttendance = [];
      notifyCallback();
      return { success: true, count: deletedCount };
    } catch (e) {
      console.error("Clear all attendance failed:", e);
      return { success: false, message: e.message };
    }
  },

  getAttendanceByMemberId(memberId) {
    return cachedAttendance
      .filter(log => log.memberId === memberId)
      .sort((a, b) => new Date(b.timestamp) - new Date(a.timestamp));
  },

  async getAttendanceByDate(dateStr, branchId = null) {
    try {
      let q = query(
        collection(db, 'attendance'),
        where("date", "==", dateStr)
      );

      const snapshot = await getDocs(q);
      let records = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));

      // [FIX] Sort in memory instead of Firestore orderBy to avoid missing index errors
      records.sort((a, b) => {
        const timeA = a.timestamp ? new Date(a.timestamp).getTime() : 0;
        const timeB = b.timestamp ? new Date(b.timestamp).getTime() : 0;
        return timeB - timeA;
      });

      if (branchId) {
        records = records.filter(r => r.branchId === branchId);
      }
      return records;
    } catch (e) {
      console.warn("Get attendance by date failed:", e);
      return [];
    }
  },

  subscribeAttendance(dateStr, branchId = null, callback) {
    try {
      let q = query(
        collection(db, 'attendance'),
        where("date", "==", dateStr)
      );

      return onSnapshot(q, (snapshot) => {
        let records = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
        
        // [FIX] Sort in memory
        records.sort((a, b) => {
          const timeA = a.timestamp ? new Date(a.timestamp).getTime() : 0;
          const timeB = b.timestamp ? new Date(b.timestamp).getTime() : 0;
          return timeB - timeA;
        });
        if (branchId) {
          records = records.filter(r => r.branchId === branchId);
        }
        callback(records);
      }, (error) => {
        console.warn('[attendanceService] Attendance listener error:', error);
      });
    } catch (e) {
      console.error('[attendanceService] Failed to subscribe to attendance:', e);
      return () => {};
    }
  },

  async deleteAttendance(logId, restoreCredit = true) {
    try {
      const logRef = doc(db, 'attendance', logId);
      const logSnap = await getDoc(logRef);

      // [FIX] writeBatch로 원자적 처리 — 크레딧 복원과 출석 삭제를 한 번에
      const { writeBatch } = await import('firebase/firestore');
      const batch = writeBatch(db);

      if (logSnap.exists()) {
        const logData = logSnap.data();
        
        const lowerStatus = (logData.status || '').toLowerCase();
        const wasValid = lowerStatus === 'valid' || lowerStatus === 'success' || (!logData.status && !logData.denialReason);
        
        if (restoreCredit && logData.memberId && wasValid && (logData.type === 'checkin' || logData.type === 'manual' || !logData.type || logData.type === 'attendance')) {
          const creditsToRestore = logData.sessionCount || 1;
          const memberRef = doc(db, 'members', logData.memberId);
          // [FIX] batch에 크레딧 복원을 포함 (기존: 별도 await로 원자성 깨짐)
          batch.update(memberRef, {
            credits: increment(creditsToRestore),
            attendanceCount: increment(-creditsToRestore)
          });
        }
      }

      // [FIX] batch에 출석 삭제를 포함 — 크레딧 복원과 동시에 커밋
      batch.delete(logRef);
      await batch.commit();

      // [NEW] 출석 기록이 성공적으로 삭제(commit)된 후, 연관된 사진 파일이 있으면 Storage에서 삭제
      if (logSnap.exists()) {
        const logData = logSnap.data();
        if (logData.photoUrl) {
          try {
            const storage = getStorage(app);
            // URL에서 경로 추출 로직 (Firebase Storage 다운로드 URL 패턴 대응)
            // ex: https://firebasestorage.googleapis.com/v0/b/boksaem-yoga.firebasestorage.app/o/attendance-photos%2F2026-03-06%2Fphoto_1741235332306.webp?alt=media...
            const urlObj = new URL(logData.photoUrl);
            const pathParts = urlObj.pathname.split('/o/');
            if (pathParts.length > 1) {
              const filePath = decodeURIComponent(pathParts[1]);
              const photoRef = ref(storage, filePath);
              await deleteObject(photoRef);
              console.log(`[attendanceService] Deleted associated photo: ${filePath}`);
            }
          } catch (photoErr) {
            console.warn(`[attendanceService] Failed to delete associated photo:`, photoErr);
            // 사진 삭제 실패가 전체 출석 삭제 실패로 이어지지 않도록 예외 무시
          }
        }
      }

      // Rely on onSnapshot listener for UI update (prevents race condition / double-increment)
      const deletedLog = logSnap.exists() ? logSnap.data() : null;
      cachedAttendance = cachedAttendance.filter(l => l.id !== logId);

      notifyCallback();
      return { success: true };
    } catch (e) {
      console.error("Delete attendance failed:", e);
      await deps.logError(e, { context: 'deleteAttendance', logId });
      return { success: false, message: e.message };
    }
  },

  async syncPendingCheckins() {
    if (!navigator.onLine) return { successCount: 0, remainingCount: 0 };

    const queue = JSON.parse(localStorage.getItem('pending_checkins_queue') || '[]');
    if (queue.length === 0) return { successCount: 0, remainingCount: 0 };

    console.log(`[attendanceService] Syncing ${queue.length} pending check-ins...`);
    const pendingRef = collection(db, 'pending_attendance');
    
    const remainingQueue = [];
    let successCount = 0;

    for (const item of queue) {
        try {
            await addDoc(pendingRef, item);
            successCount++;
        } catch (e) {
            console.error("[attendanceService] Failed to sync pending record:", e);
            remainingQueue.push(item);
        }
    }

    if (remainingQueue.length > 0) {
        localStorage.setItem('pending_checkins_queue', JSON.stringify(remainingQueue));
    } else {
        localStorage.removeItem('pending_checkins_queue');
    }
    
    console.log(`[attendanceService] Synced ${successCount} records. Remaining: ${remainingQueue.length}`);
    return { successCount, remainingCount: remainingQueue.length };
  },

  async checkInById(memberId, branchId, force = false, eventId = null, facialMatched = false) {
    try {
      const checkInMember = httpsCallable(functions, 'checkInMemberV2Call');
      const currentClassInfo = await deps.getCurrentClass(branchId);
      const classTitle = currentClassInfo?.title || '자율수련';
      const instructor = currentClassInfo?.instructor || '미지정';
      
      let lastErr = null;
      for (let attempt = 1; attempt <= 2; attempt++) {
        try {
          console.log(`[attendanceService] Check-in attempt ${attempt}/2... (force: ${force})`);
          const safeUUID = () => (typeof crypto !== 'undefined' && crypto.randomUUID) ? crypto.randomUUID() : 'id_' + Date.now().toString(36) + Math.random().toString(36).substr(2, 5);
          const response = await withTimeout(
            checkInMember({ 
                memberId, 
                branchId, 
                classTitle, 
                instructor, 
                classTime: currentClassInfo?.time || null, 
                force,
                eventId: eventId || safeUUID(), // [FIX] Generate UUID safely to prevent crashes on older iPads/tablets
                facialMatched
            }),
            12000,
            'timeout'
          );

          if (response.data.success) {
            // Updated member data will flow via Firebase onSnapshot listener
            const { newCredits, startDate, endDate, attendanceCount, streak, isMultiSession, sessionCount } = response.data;

            return {
              success: true,
              message: isMultiSession ? `[${classTitle}] ${sessionCount}회차 출석되었습니다!` : `[${classTitle}] 출석되었습니다!`,
              attendanceId: response.data.attendanceId,
              attendanceStatus: response.data.attendanceStatus,
              denialReason: response.data.denialReason,
              isDuplicate: response.data.isDuplicate,
              member: {
                id: memberId,
                name: response.data.memberName,
                credits: newCredits,
                attendanceCount,
                streak,
                startDate,
                endDate,
                isMultiSession,
                sessionCount
              }
            };
          } else {
            console.warn(`[attendanceService] Check-in denied by server: ${response.data.message}`);
            return { success: false, message: response.data.message || 'Check-in failed' };
          }
        } catch (error) {
          lastErr = error;
          const errCode = error.code;
          const errMsg = error.message || '';
          const logicErrorCodes = ['invalid-argument', 'failed-precondition', 'out-of-range', 'unauthenticated', 'permission-denied', 'not-found', 'already-exists', 'resource-exhausted', 'aborted', 'cancelled', 'unknown'];

          if (errCode && logicErrorCodes.includes(errCode)) {
            console.warn(`[attendanceService] Logic error returned: ${errCode} - ${errMsg}`);
            return { success: false, message: errMsg };
          }

          if (attempt === 1 && navigator.onLine) {
            console.warn(`[attendanceService] Attempt 1 failed (${errMsg}). Retrying immediately...`);
            continue; 
          }
          break;
        }
      }

      console.warn(`[attendanceService] Offline mode triggered. Reason: ${lastErr?.message || 'Unknown'}`);
      
      const member = memberService.getMemberById(memberId);
      const today = new Date().toLocaleDateString('sv-SE', { timeZone: 'Asia/Seoul' });
      const now = new Date().toISOString();

      // [FIX] Offline Expiry Validation & upcomingMembership fallback
      if (member) {
          let isExpired = false;
          let denialReason = null;
          
          if (member.endDate) {
              const todayDate = new Date(today);
              const endDate = new Date(member.endDate);
              if (todayDate > endDate) {
                  isExpired = true;
                  denialReason = 'expired';
              }
          }
          if (!isExpired && (member.credits || 0) <= 0) {
              isExpired = true;
              denialReason = 'no_credits';
          }

          // [NEW] Offline fallback: Activate upcomingMembership if current is exhausted
          if (isExpired && member.upcomingMembership && member.upcomingMembership.startDate) {
              const isTBD = member.upcomingMembership.startDate === 'TBD';
              let shouldActivate = false;
              let newStartDate = member.upcomingMembership.startDate;
              let newEndDate = member.upcomingMembership.endDate;

              if (isTBD) {
                  shouldActivate = true;
                  newStartDate = today;
                  const durationMonths = member.upcomingMembership.durationMonths || 1;
                  if (durationMonths === 9999) {
                      const end = new Date(today);
                      end.setMonth(end.getMonth() + 1);
                      end.setDate(end.getDate() - 1);
                      newEndDate = end.toLocaleDateString('sv-SE', { timeZone: 'Asia/Seoul' });
                  } else {
                      const end = new Date(today);
                      end.setMonth(end.getMonth() + durationMonths);
                      end.setDate(end.getDate() - 1);
                      newEndDate = end.toLocaleDateString('sv-SE', { timeZone: 'Asia/Seoul' });
                  }
              } else {
                  const upcomingStart = new Date(member.upcomingMembership.startDate);
                  const todayDate = new Date(today);
                  if (todayDate >= upcomingStart) {
                      shouldActivate = true;
                  }
              }

              if (shouldActivate) {
                  console.log(`[attendanceService] Activating upcoming membership for ${memberId} in offline mode`);
                  // Modify the in-memory member object. The actual update will happen in memberService._updateLocalMemberCache later.
                  member.membershipType = member.upcomingMembership.membershipType;
                  member.credits = member.upcomingMembership.credits;
                  member.startDate = newStartDate;
                  member.endDate = newEndDate;
                  
                  // Reset expiration since we just activated a new one
                  isExpired = false;
                  denialReason = null;
              }
          }

          if (isExpired) {
              return {
                 success: true,
                 isOffline: true,
                 attendanceStatus: 'denied',
                 denialReason,
                 message: '기간 혹은 횟수가 만료되었습니다. (오프라인)',
                 member
              };
          }
      }

      const safeUUIDFallback = () => (typeof crypto !== 'undefined' && crypto.randomUUID) ? crypto.randomUUID() : 'id_' + Date.now().toString(36) + Math.random().toString(36).substr(2, 5);
      const pendingRef = collection(db, 'pending_attendance');
      const pendingData = {
          memberId,
          branchId,
          classTitle,
          instructor,
          classTime: currentClassInfo?.time || null,
          date: today,
          timestamp: now,
          status: 'pending-offline',
          eventId: eventId || safeUUIDFallback(),
          facialMatched: facialMatched,
          // [NEW] 만약 오프라인에서 회원권이 활성화되었다면 해당 정보 포함 (서버 동기화 시 필요)
          activatedUpcomingMembership: member && member.startDate === today ? {
              membershipType: member.membershipType,
              startDate: member.startDate,
              endDate: member.endDate,
              credits: member.credits // 차감 전 혹은 후의 크레딧 (서버에서 최종 결정하겠지만 참고용)
          } : null
      };

      try {
          await addDoc(pendingRef, pendingData);
          console.log("[attendanceService] Pending record saved to Firestore (Offline mode)");
      } catch (firestoreErr) {
          console.error("[attendanceService] Firestore write failed. Using LocalStorage fallback:", firestoreErr.message);
          const localQueue = JSON.parse(localStorage.getItem('pending_checkins_queue') || '[]');
          localQueue.push(pendingData);
          localStorage.setItem('pending_checkins_queue', JSON.stringify(localQueue));
      }

      const newCredits = (member?.credits || 0) > 0 ? ((member?.credits || 0) - 1) : 0;
      const newCount = (member?.attendanceCount || 0) + 1;
      
      const updatePayload = {
          credits: newCredits,
          attendanceCount: newCount,
          lastAttendance: now
      };

      // [NEW] If upcomingMembership was activated, include those changes in the local cache update
      if (pendingData.activatedUpcomingMembership) {
          updatePayload.membershipType = member?.membershipType;
          updatePayload.startDate = member?.startDate;
          updatePayload.endDate = member?.endDate;
          updatePayload.upcomingMembership = null; 
      }

      if (member) {
          memberService._updateLocalMemberCache(memberId, updatePayload);
      }

      return {
        success: true,
        isOffline: true,
        message: `[${classTitle}] 출석되었습니다!`,
        member: {
          ...(member || {}),
          name: member?.name || '회원',
          credits: newCredits,
          attendanceCount: newCount,
          membershipType: updatePayload.membershipType || member?.membershipType,
          startDate: updatePayload.startDate || member?.startDate,
          endDate: updatePayload.endDate || member?.endDate
        }
      };
    } catch (error) {
    return { success: false, message: error.message };
  }
  },

  async addManualAttendance(memberId, date, branchId, className = "수동 확인", instructor = "관리자", { skipCreditDeduction = false } = {}) {
    try {
      const memberDoc = await getDoc(doc(db, 'members', memberId));
      const memberData = memberDoc.exists() ? memberDoc.data() : null;
      const memberName = memberData ? memberData.name : '알 수 없음';

      let finalDate = new Date(date);
      if (isNaN(finalDate.getTime())) {
        finalDate = new Date();
      }
      const timestamp = finalDate.toISOString();
      const dateStr = finalDate.toLocaleDateString('sv-SE', { timeZone: 'Asia/Seoul' });

      let finalClassName = className;
      let finalInstructor = instructor;

      const kstH = String(finalDate.getHours()).padStart(2, '0');
      const kstM = String(finalDate.getMinutes()).padStart(2, '0');
      let finalClassTime = `${kstH}:${kstM}`;

      if (className === "수동 확인") {
        try {
          const scheduleDocId = `${branchId}_${dateStr}`;
          const scheduleDoc = await getDoc(doc(db, 'daily_classes', scheduleDocId));

          if (scheduleDoc.exists()) {
            const scheduleData = scheduleDoc.data();
            const dayClasses = scheduleData.classes || [];

            const hour = finalDate.getHours();
            const minute = finalDate.getMinutes();
            const requestTimeMins = hour * 60 + minute;

            // [FIX] Prefer exact hour:minute match first to avoid fuzzy grouping errors (e.g. 14:00 matching to 14:20 class)
            let matchedClass = dayClasses.find(cls => cls.time === finalClassTime && cls.status !== 'cancelled');

            if (!matchedClass) {
              matchedClass = dayClasses.find(cls => {
                if (!cls.time || cls.status === 'cancelled') return false;
                const [classHour, classMinute] = cls.time.split(':').map(Number);
                const classStartMins = classHour * 60 + classMinute;
                const classDuration = cls.duration || 60;
                const classEndMins = classStartMins + classDuration;
                return requestTimeMins >= classStartMins - 30 && requestTimeMins <= classEndMins + 30;
              });
            }

            if (matchedClass) {
              finalClassName = matchedClass.title || matchedClass.name || "수업";
              finalInstructor = matchedClass.instructor || "선생님";
              finalClassTime = matchedClass.time; // Use the matched class's official time
            } else {
              finalClassName = "자율수련";
              finalInstructor = "회원";
            }
          } else {
            finalClassName = "자율수련";
            finalInstructor = "회원";
          }
        } catch (scheduleError) {
          console.warn("Schedule lookup failed, using default:", scheduleError);
          finalClassName = "자율수련";
          finalInstructor = "회원";
        }
      }

      // [FIX] upcomingMembership 활성화 로직 (Cloud Function과 동일)
      // 수동 출석 시에도 선등록 회원권이 활성화되어야 함
      let membershipUpdate = null;
      if (memberData && memberData.upcomingMembership && memberData.upcomingMembership.startDate) {
        const upcoming = memberData.upcomingMembership;
        const isTBD = upcoming.startDate === 'TBD';
        let shouldActivate = false;
        let newStartDate = upcoming.startDate;
        let newEndDate = upcoming.endDate;

        if (isTBD) {
          // TBD: 현재 회원권이 소진/만료 시 활성화
          const currentCredits = memberData.credits || 0;
          const isCurrentExpired = memberData.endDate ? (new Date(dateStr) > new Date(memberData.endDate)) : false;
          const isCurrentExhausted = currentCredits <= 0 || isCurrentExpired;

          if (isCurrentExhausted) {
            shouldActivate = true;
            newStartDate = dateStr;
            const durationMonths = upcoming.durationMonths || 1;
            const end = new Date(dateStr);
            end.setMonth(end.getMonth() + durationMonths);
            end.setDate(end.getDate() - 1);
            newEndDate = end.toLocaleDateString('sv-SE', { timeZone: 'Asia/Seoul' });
          }
        } else {
          // 시작일이 지정된 경우: 출석일 >= 시작일이면 활성화
          const upcomingStart = new Date(upcoming.startDate);
          const attendanceDate = new Date(dateStr);
          if (attendanceDate >= upcomingStart) {
            shouldActivate = true;
          }
        }

        if (shouldActivate) {
          console.log(`[Manual Attendance] Activating upcoming membership for ${memberId}`);
          membershipUpdate = {
            membershipType: upcoming.membershipType,
            credits: upcoming.credits,
            startDate: newStartDate,
            endDate: newEndDate,
            upcomingMembership: null // Firestore에서 삭제
          };
        }
      }

      // [FIX] writeBatch로 출석 생성 + 크레딧 차감을 원자적으로 처리
      const { writeBatch, deleteField } = await import('firebase/firestore');
      const batch = writeBatch(db);

      const newAttRef = doc(collection(db, 'attendance'));
      const attendanceData = {
        memberId,
        memberName,
        timestamp,
        branchId,
        className: finalClassName,
        instructor: finalInstructor,
        classTime: finalClassTime,
        type: 'manual',
        date: dateStr
      };

      batch.set(newAttRef, attendanceData);

      const memberRef = doc(db, 'members', memberId);

      if (membershipUpdate) {
        // 선등록 회원권 활성화 + 크레딧 차감 (새 크레딧에서 -1)
        batch.update(memberRef, {
          membershipType: membershipUpdate.membershipType,
          credits: membershipUpdate.credits - 1,
          startDate: membershipUpdate.startDate,
          endDate: membershipUpdate.endDate,
          upcomingMembership: deleteField(),
          attendanceCount: increment(1),
          lastAttendance: timestamp
        });
      } else if (skipCreditDeduction) {
        // [FIX] 등록 시 includeToday로 이미 크레딧 차감된 경우, 크레딧은 건드리지 않고 출석 기록만 추가
        batch.update(memberRef, {
          attendanceCount: increment(1),
          lastAttendance: timestamp
        });
      } else {
        // 기존 로직: 단순 크레딧 차감
        batch.update(memberRef, {
          credits: increment(-1),
          attendanceCount: increment(1),
          lastAttendance: timestamp
        });
      }

      // [FIX] 원자적 커밋 — 출석 기록과 크레딧 차감이 동시에 성공하거나 동시에 실패
      await batch.commit();

      const newLog = {
        id: newAttRef.id,
        ...attendanceData
      };

      // Member credits and log additions will flow via real-time Firestore listeners

      notifyCallback();

      return { success: true, id: newAttRef.id };
    } catch (e) {
      console.error("Add manual attendance failed:", e);
      return { success: false, message: e.message };
    }
  },

  // [NEW] Update Past Attendance Records when Schedule Changes
  async updatePastAttendanceRecords(branchId, dateStr, oldClasses, newClasses) {
    try {
      console.log(`[attendanceService] Checking retroactive updates for ${dateStr} at ${branchId}`);
      if (!oldClasses || !newClasses) return { success: true, count: 0 };

      // Find changed classes
      const changedClasses = [];
      newClasses.forEach(newCls => {
        if (!newCls.time) return;
        
        // Find matching class in old schedule (by time)
        const oldCls = oldClasses.find(c => c.time === newCls.time);
        
        // If not found, it's totally new (no past attendance to update).
        // If found, check if instructor or title changed.
        if (oldCls) {
           const isTitleChanged = (oldCls.title || oldCls.className) !== (newCls.title || newCls.className);
           const isInstChanged = oldCls.instructor !== newCls.instructor;
           
           if (isTitleChanged || isInstChanged) {
               changedClasses.push({
                   time: newCls.time,
                   duration: newCls.duration || 60,
                   oldTitle: oldCls.title || oldCls.className,
                   oldInst: oldCls.instructor,
                   newTitle: newCls.title || newCls.className,
                   newInst: newCls.instructor
               });
           }
        }
      });

      if (changedClasses.length === 0) {
        console.log('[attendanceService] No relevant class changes found for retroactive update.');
        return { success: true, count: 0 };
      }

      // Fetch attendance for that date
      const q = query(
          collection(db, 'attendance'),
          where("date", "==", dateStr),
          where("branchId", "==", branchId)
      );
      const snapshot = await getDocs(q);
      if (snapshot.empty) return { success: true, count: 0 };

      // Batch update references
      let updateCount = 0;
      const batchRef = window.firebaseWriteBatch || (await import('firebase/firestore')).writeBatch;
      const batch = batchRef(db);

      snapshot.docs.forEach(docSnap => {
          const log = docSnap.data();
          
          Object.values(changedClasses).forEach(changedCls => {
              // Time matching logic: -30 mins ~ End time + 30 mins
              const [classH, classM] = changedCls.time.split(':').map(Number);
              const classStartMins = classH * 60 + classM;
              const classEndMins = classStartMins + changedCls.duration;

              // Extract hour/min from attendance timestamp
              const logDate = new Date(log.timestamp);
              const logMins = logDate.getHours() * 60 + logDate.getMinutes();

               // If the attendance was recorded roughly during the time window of the exchanged class
              if (logMins >= classStartMins - 30 && logMins <= classEndMins + 30) {
                  
                  // Double check: if it still holds the OLD text, update it.
                  if (log.className === changedCls.oldTitle || log.instructor === changedCls.oldInst) {
                      const docRef = doc(db, 'attendance', docSnap.id);
                      batch.update(docRef, {
                          className: changedCls.newTitle,
                          instructor: changedCls.newInst
                      });
                      updateCount++;
                  }
              }
          });
      });

      if (updateCount > 0) {
          await batch.commit();
          console.log(`[attendanceService] Retroactively updated ${updateCount} attendance records.`);
      }

      return { success: true, count: updateCount };
    } catch (e) {
      console.error("[attendanceService] Failed retroactive update:", e);
      return { success: false, message: e.message };
    }
  }
};

import { db, functions } from '../firebase';
import { collection, doc, query, where, getDocs, getDoc, addDoc, updateDoc, setDoc, onSnapshot, limit as firestoreLimit } from 'firebase/firestore';
import { httpsCallable } from 'firebase/functions';

// [NETWORK] Timeout wrapper for Cloud Function calls
const withTimeout = (promise, timeoutMs = 10000, errorMsg = '서버 응답 시간 초과') => {
  return Promise.race([
    promise,
    new Promise((_, reject) => setTimeout(() => reject(new Error(errorMsg)), timeoutMs))
  ]);
};

// --- Local Cache ---
let cachedMembers = [];
let phoneLast4Index = {}; // { "1234": [member1, member2], ... }
let memberListenerUnsubscribe = null;
let notifyCallback = () => {};

export const memberService = {
  // [NEW] Trigger Kiosk Sync
  async triggerKioskSync() {
    try {
      const syncRef = doc(db, 'system_state', 'kiosk_sync');
      await setDoc(syncRef, { lastMemberUpdate: new Date().toISOString() }, { merge: true });
      console.log('[memberService] Kiosk sync triggered');
    } catch (e) {
      console.warn('[memberService] Failed to trigger kiosk sync:', e);
    }
  },

  // --- Initialization & Listener ---
  setNotifyCallback(callback) {
    notifyCallback = callback;
  },

  setupMemberListener() {
    console.log("[memberService] setupMemberListener called - optimized to avoid global onSnapshot read spikes.");
    
    // [NEW] Load from LocalStorage for immediate UI response (Optimistic)
    const stored = localStorage.getItem('kiosk_member_cache');
    if (stored && cachedMembers.length === 0) {
      try {
        cachedMembers = JSON.parse(stored);
        console.log(`[memberService] Booting from local cache: ${cachedMembers.length} members`);
        this._buildPhoneLast4Index();
      } catch (e) {
        console.warn('[memberService] Local cache corrupt');
      }
    }

    try {
      if (memberListenerUnsubscribe) {
        memberListenerUnsubscribe();
      }
      memberListenerUnsubscribe = onSnapshot(collection(db, 'members'), (snapshot) => {
        const members = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
        cachedMembers = members;
        
        try {
            localStorage.setItem('kiosk_member_cache', JSON.stringify(cachedMembers));
        } catch (e) {
            console.warn('[memberService] Cache persistence failed');
        }

        console.log(`[memberService] Members updated via listener: ${members.length}`);
        this._buildPhoneLast4Index();
        notifyCallback();
      }, (error) => {
        console.warn("[memberService] Member listener error:", error);
      });
      return memberListenerUnsubscribe;
    } catch (e) {
      console.error("[memberService] Failed to setup member listener:", e);
      return null;
    }
  },

  getMembers() {
    return cachedMembers;
  },

  async loadAllMembers(force = false) {
    if (!force && cachedMembers.length > 0) return cachedMembers;

    try {
      console.time('[memberService] Force Fetch Members');
      console.log("[memberService] Cache empty or forced, fetching members...");
      const snapshot = await getDocs(collection(db, 'members'));
      const members = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));

      cachedMembers = members;
      
      // [CRITICAL FIX] Save to localStorage so next kiosk boot is instantaneous
      try {
          localStorage.setItem('kiosk_member_cache', JSON.stringify(cachedMembers));
      } catch (e) {
          console.warn('[memberService] Local cache save failed (Storage full?)');
      }
      
      this._buildPhoneLast4Index();
      console.timeEnd('[memberService] Force Fetch Members');
      
      return cachedMembers;
    } catch (e) {
      console.error("Force fetch members failed:", e);
      return [];
    }
  },


  _buildPhoneLast4Index() {
    const newIndex = {};
    cachedMembers.forEach(m => {
      const last4 = m.phoneLast4 || (m.phone && m.phone.slice(-4));
      if (last4) {
        if (!newIndex[last4]) newIndex[last4] = [];
        newIndex[last4].push(m);
      }
    });
    phoneLast4Index = newIndex;
  },

  async findMembersByPhone(last4Digits) {
    let members = [];
    if (phoneLast4Index[last4Digits]?.length > 0) {
      members = phoneLast4Index[last4Digits];
    } else {
      const cachedResults = cachedMembers.filter(m => (m.phoneLast4 || (m.phone && m.phone.slice(-4))) === last4Digits);
      if (cachedResults.length > 0) {
        members = cachedResults;
      } else {
        try {
          const getSecureMember = httpsCallable(functions, 'getSecureMemberV2Call');
          const result = await withTimeout(
            getSecureMember({ phoneLast4: last4Digits }),
            15000,
            '회원 조회 시간 초과'
          );
          members = result.data.members || [];
        } catch (e) {
          console.error('[memberService] Cloud Function member lookup failed:', e);
          // [FIX] Don't fall back to direct Firestore query — anonymous kiosk auth doesn't have permission.
          // Instead, let the empty result propagate so the UI shows "회원 정보를 찾을 수 없습니다"
          members = [];
        }
      }
    }

    // [SECURITY & PERF] Fetch biometrics for members who have the flag but not the descriptor
    const bioTasks = members
      .filter(m => m.hasFaceDescriptor && !m.faceDescriptor)
      .map(async m => {
        try {
          const bioSnap = await getDoc(doc(db, 'face_biometrics', m.id));
          if (bioSnap.exists()) {
             const bioData = bioSnap.data();
             m.faceDescriptor = bioData.descriptor;
          }
        } catch (e) { console.warn(`[memberService] Bio load failed for ${m.id}`); }
      });

    if (bioTasks.length > 0) await Promise.all(bioTasks);
    return members;
  },

  getMemberById(id) {
    if (!id) return null;
    return cachedMembers.find(m => m.id === id) || null;
  },

  async fetchMemberById(id) {
    if (!id) return null;
    const cached = this.getMemberById(id);
    if (cached) return cached;

    try {
      const docRef = doc(db, 'members', id);
      const docSnap = await getDoc(docRef);
      if (docSnap.exists()) {
        const data = { id: docSnap.id, ...docSnap.data() };
        // Insert into cache to prevent subsequent fetches
        if (!cachedMembers.some(m => m.id === id)) {
           cachedMembers.push(data);
           this._buildPhoneLast4Index();
        }
        return data;
      }
      return null;
    } catch (e) {
      console.error('Fetch member failed:', e);
      return null;
    }
  },

  async updateMember(memberId, data) {
    try {
      const memberRef = doc(db, 'members', memberId);
      await updateDoc(memberRef, { ...data, updatedAt: new Date().toISOString() });
      this.triggerKioskSync();
      return { success: true };
    } catch (e) {
      console.error('Update member failed:', e);
      return { success: false, error: e.message };
    }
  },

  async updateFaceDescriptor(memberId, descriptor) {
    try {
      if (!descriptor) return { success: false };
      // [SECURITY] Save to isolated biometrics collection
      const bioRef = doc(db, 'face_biometrics', memberId);
      const descriptorArray = Array.from(descriptor);
      
      await setDoc(bioRef, { 
        memberId,
        descriptor: descriptorArray,
        updatedAt: new Date().toISOString()
      });

      // Synchronize with membership record metadata to trigger UI badges
      const memberRef = doc(db, 'members', memberId);
      await updateDoc(memberRef, { 
        hasFaceDescriptor: true,
        faceUpdatedAt: new Date().toISOString()
      });

      console.log(`[memberService] Face biometrics secured for ${memberId}`);
      this._updateLocalMemberCache(memberId, { faceDescriptor: descriptorArray, hasFaceDescriptor: true });
      return { success: true };
    } catch (e) {
      console.error('[memberService] Bio hardening failed:', e);
      return { success: false, error: e.message };
    }
  },

  _updateLocalMemberCache(memberId, updates) {
    const idx = cachedMembers.findIndex(m => m.id === memberId);
    if (idx !== -1) {
      const newMembers = [...cachedMembers];
      newMembers[idx] = { ...newMembers[idx], ...updates };
      cachedMembers = newMembers;
      
      // [NEW] Persist for offline durability
      try {
        localStorage.setItem('kiosk_member_cache', JSON.stringify(cachedMembers));
      } catch (e) {
        console.warn('[memberService] Cache persistence failed (Storage full?)');
      }

      notifyCallback();
      this._buildPhoneLast4Index();
    }
  },

  async addMember(data) {
    try {
      const phoneQuery = query(collection(db, 'members'), where('phone', '==', data.phone));
      const phoneSnap = await getDocs(phoneQuery);
      if (!phoneSnap.empty) {
        throw new Error('이미 등록된 전화번호입니다.');
      }

      const docRef = await addDoc(collection(db, 'members'), {
        ...data,
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString(),
        phoneLast4: data.phone.slice(-4)
      });
      console.log(`[memberService] Member added to Firestore: ${docRef.id}`);
      this.triggerKioskSync();
      return { success: true, id: docRef.id };
    } catch (e) {
      console.error('Add member failed:', e);
      throw e;
    }
  },

  getMemberStreak(memberId, attendance) {
    try {
      if (!attendance || attendance.length === 0) return 0;

      const dates = attendance.map(a => a.date).filter(Boolean).sort().reverse();
      const uniqueDates = [...new Set(dates)];

      const today = new Date().toLocaleDateString('sv-SE', { timeZone: 'Asia/Seoul' });
      const yesterdayDate = new Date();
      yesterdayDate.setDate(yesterdayDate.getDate() - 1);
      const yesterday = yesterdayDate.toLocaleDateString('sv-SE', { timeZone: 'Asia/Seoul' });

      if (uniqueDates[0] !== today && uniqueDates[0] !== yesterday) return 0;

      let streak = 1;
      let lastDate = new Date(uniqueDates[0]);

      for (let i = 1; i < uniqueDates.length; i++) {
        const currentDate = new Date(uniqueDates[i]);
        const diff = Math.round((lastDate - currentDate) / (1000 * 60 * 60 * 24));
        if (diff === 1) {
          streak++;
          lastDate = currentDate;
        } else {
          break;
        }
      }
      return streak;
    } catch (e) {
      console.warn('Streak calc failed:', e);
      return 0;
    }
  },

  async getMemberDiligence(memberId) {
    try {
      const docSnap = await getDoc(doc(db, 'member_diligence', memberId));
      return docSnap.exists() ? docSnap.data() : null;
    } catch (e) {
      console.warn("Diligence fetch failed:", e);
      return null;
    }
  },

  // Greeting Cache (Local Storage)
  _safeGetItem(key) { try { return localStorage.getItem(key); } catch { return null; } },
  _safeSetItem(key, value) { try { localStorage.setItem(key, value); } catch { /* ignore */ } },

  getGreetingCache(memberId) {
    const cached = this._safeGetItem(`greeting_${memberId}`);
    return cached ? JSON.parse(cached) : null;
  },

  setGreetingCache(memberId, data) {
    this._safeSetItem(`greeting_${memberId}`, JSON.stringify(data));
  }
};

