        }

        // 3. Merge and sort
        const combined = [...individualMessages, ...notices].sort((a, b) => {
            const dateA = new Date(a.timestamp || a.date || 0);
            const dateB = new Date(b.timestamp || b.date || 0);
            return dateB - dateA;
        });

        return combined;
    } catch (e) {
        console.warn("Get messages by member failed:", e);
        return [];
    }
};

